/* 令和8年委員会データ（自動生成・分割ファイル） */
window.SHINAGAWA_DB.years.r08.committeeSessions.push(...[{"id":"r08-20260119-6","meetingId":"r08-m01","date":"2026年1月19日","dateIso":"2026-01-19","committee":"区民委員会","time":"午後 １時００分～午後 １時５１分","status":"正式会議録","sourceType":"formal","overview":"区民委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を14件整理しています。","topics":[{"id":"topic-01","title":"しながわシティラン２０２６の開催に向けた進捗","agenda":"しながわシティラン２０２６の開催に向けた進捗","exchanges":[{"speaker":"おぎの委員","kind":"質問","question":"まず状況をもう少しお聞きしたいと思うのですが、エントリーで１０ｋｍのほうで、どういった内訳となっていますでしょうか。車いすチャレンジが１２人しか今エントリー確定者がいませんが、追加の募集はないのか、その３点をお願いいたします。","respondent":"守屋スポーツ推進課長","answer":"車いすチャレンジの定員が３０人のところエントリー確定者が１２人というところで、こちらは一旦、参加者が増えていけばと思っているところです。まず今年は１２人でやらせていただいて、その状況によっては、定員のところはまた考えていく必要があるかと思っているところです。","id":"exchange-001"},{"speaker":"おぎの委員","kind":"質問","question":"ウェーブスタートというのは、グループを区切って、やはりタイムの早い方からスタートされるのでしょうか。規制の辺りで、もし万が一この時間を超過してしまったら足切りとかも想定されているのか、その辺を教えてほしいと求めました。","respondent":"守屋スポーツ推進課長","answer":"１点目のウェーブスタートの関係なのですけれども、一応１,０００人と１,５００人の２グループに分けてスタートする予定です。一般的に１ｋｍ６分以上で走ったとしましても、昨年度の状況を踏まえながら、収容関門の時間については設定しています。","id":"exchange-002"},{"speaker":"こしば委員","kind":"質問","question":"どうしても所用があって伺えなかったのですけれども、話をする中で、一つ懸念点がありました。前回のレースの反省といいますか、気づきを踏まえて、どのようにトイレの対策をされているのか説明を求めました。","respondent":"守屋スポーツ推進課長","answer":"そちらのほうに施設のトイレですとか、大井競馬場のほうには仮設トイレも設置しまして、対応します。そういったご意見があれば、来年度以降、考えてまいりたいと考えています。","id":"exchange-003"},{"speaker":"こしば委員","kind":"質問・要望","question":"広げていって、参加者の方があまり苦に思わず、安心してレースに臨めるような環境をつくってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-004"},{"speaker":"高橋（伸）委員","kind":"意見","question":"４の大会当日のイベント内容のところで、（２）の大井ホッケー場での吹奏楽と和太鼓の演奏があるということなのですが、私はこの吹奏楽は、公立の中学校の吹奏楽部の方々が演奏していただけるのかなと思っているのですが、もし決定しているようだったら、説明を求めました。","respondent":"守屋スポーツ推進課長","answer":"今、詳細は詰めているところなのですけれども、現状の予定といたしましては、八潮太鼓之会という八潮地区を中心に活動されている太鼓の会と、東海中学校の吹奏楽部のほうに出演をという形で調整を進めているところです。","id":"exchange-005"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"来てもらわないと駄目ではないですか。そこの詳細を教えてほしいと求めました。","respondent":"守屋スポーツ推進課長","answer":"どういう考えかというところですが、協賛ブース等を実施しておりますし、考え方としています。コースとして走っていただくのですけれども、見てもらいつつも、ランナーを応援するというところを大井ホッケー場のほうは主体にしています。","id":"exchange-006"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"分かりました。ぜひそこら辺の集客含めて、これから周知してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-007"},{"speaker":"せらく委員","kind":"質問・要望","question":"私もイベントのところから質問させてほしいと求めました。昨年１０ｋｍを走りまして、達成感と一緒に盛り上がれるようなイベントスケジュール管理にしていただきたいと思うのですけれども、いかがか尋ねました。","respondent":"守屋スポーツ推進課長","answer":"ステージイベントというのは時間帯が決まっているところの中で進めていくのですけれども、進めさせていただいて、周知等を含めて徹底して楽しんでもらえるようにしたいと思います。","id":"exchange-008"}]},{"id":"topic-02","title":"所管事務調査","agenda":"所管事務調査","exchanges":[{"speaker":"こしば委員","kind":"質問・要望","question":"考えてみたらどうなのかという話も一つの町会ではなく、３つ、４つぐらいの町会からも上がってきているのが事実です。なぜ現役世代の方々が地域のコミュニティに入ってこないのかというのが、実際、どのように受け止めているのか教えてほしいと求めました。","respondent":"平原地域活動課長","answer":"例えば私ども２年に一度行っております、町会・自治会、やはり自分の役に立つ活動がされているかどうかというようなところが筆頭でございました。そういったところがなかなか世論調査上の回答にはつながっていないといったところでは…","id":"exchange-009"},{"speaker":"こしば委員","kind":"質問","question":"少し細かな話を１点お聞きしたいのですけれども、３年たつと突然、町会費を支払ってもらうという義務づけというのが消えてしまっている。実際、地域連絡調整員の役割は一体どこにあるのかと、すごく最近は感じている次第なので、その辺り、分からないので、教えてほしいと求めました。","respondent":"平原地域活動課長","answer":"制度のご紹介、新年度予算を踏まえましてご説明できればと考えていますので、そのような地域間格差がないようにしてまいりたいと考えています。引き続き、そういったところでは、私どもも汗をかいていきたいとは考えているところです。","id":"exchange-010","title":"町会・自治会支援"},{"speaker":"こしば委員","kind":"質問・要望","question":"１０年先というところの中で、また町会長というのにぜひなっていただきたいなと、私も当事者としてすごく感じる次第です。令和７年度に関係構築支援があったということなのですけれども、具体的にどういう内容だったのか教えてもらっていいか尋ねました。","respondent":"平原地域活動課長","answer":"当委員会で年度当初にご説明申し上げまして、そういったところを一緒になってやっていくというようなことをやっているところです。お話をきちんと進めたいのだと、図らずもという形で、そのつながりをつくっていくのが今回の関係構築支援のまさに主眼といったところです。","id":"exchange-011","title":"町会・自治会支援"},{"speaker":"こしば委員","kind":"意見","question":"そういった事例を、お作りになっていると思いますけれども、そこはまた私も当事者としても広めていきたいと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-012","title":"町会・自治会支援"},{"speaker":"おぎの委員","kind":"質問","question":"１階の掲示板には、実際、今マンションでは回覧板は回っていないところが多いと思うのです。人間関係を構築できるマンションの在り方みたいなものを提言したり、話し合っていただけるといいと思うのですが、その辺に関してはいかがか尋ねました。","respondent":"平原地域活動課長","answer":"そういったところから、入りやすいイベントに変えていくというのも、一つの考え方かと思います。大災害のときにそれが果たして継続性としてはいつまでなのか、今回の伴走型支援のところでは、そういう中から。","id":"exchange-013"},{"speaker":"おぎの委員","kind":"意見","question":"防災というのが前面に出てきていますが、私はそれでもいいと思います。人のつながりだと思いますので、この辺からどんどんいろいろな関係性を構築していったらいいと考えていますので、ぜひとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-014"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/612978?Template=document&Id=7297#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=6&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":18345,"voices":45}},{"id":"r08-20260119-7","meetingId":"r08-m01","date":"2026年1月19日","dateIso":"2026-01-19","committee":"厚生委員会","time":"午後 １時００分～午後 ４時１６分","status":"正式会議録","sourceType":"formal","overview":"厚生委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を53件整理しています。","topics":[{"id":"topic-01","title":"令和７年陳情第５７号、誰一人とりこぼさない品川区のために、真のニーズ分析から、優先的に対応すべき事業を踏まえた障害福祉計画を策定するよう、区に求める陳情","agenda":"令和７年陳情第５７号、誰一人とりこぼさない品川区のために、真のニーズ分析から、優先的に対応すべき事業を踏まえた障害福祉計画を策定するよう、区に求める陳情","exchanges":[{"speaker":"鈴木委員","kind":"質問・要望","question":"要望というのが違うのだということで書かれているのですけれども、ここら辺の区の受け止めというのはどうなのか、伺いたいと思います。それから、求められている要望の性質、ここら辺のところは区としてどのようにニーズの分析をされているのかということについて伺いたいと思います。","respondent":"佐藤障害者施策推進課長","answer":"さらなる支援が必要なもの、個別の相談支援等も踏まえて、支援を充足する必要があると考えているところです。国の方針等を踏まえながら、そういった施策の進め方に沿う形で、これから委員会等で検討を進めていくです。","id":"exchange-001"},{"speaker":"鈴木委員","kind":"質問・要望","question":"それに沿ったとしても、品川区の実態がどのような状況になっていて、品川区としてどういう計画をつくっていくのかというのが求められると思うのです。区としてどう評価をして、計画に反映させていくのかというのが求められるのではないかと思うのですが、その点はいかがか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"国の方針に基づいてというところでは、例えば、国の方針で入所から地域生活への移行というところが出されていて。策定委員会等の検討の際も含めて、そこの表し方について、次回の部分については検討させていただければと考えます。","id":"exchange-002"},{"speaker":"鈴木委員","kind":"質問・要望","question":"その点を伺いたいのと、これこれこういう理由で、やはりこれだけのことが必要だと。そこら辺はどう考えられているかということと、そういうのも併せて立てられていくということになっていくのか、その点についても伺いたいと思います。","respondent":"佐藤障害者施策推進課長","answer":"表し方等につきましては、初めての形になりますので、お示しの仕方についても検討が必要になってきます。整備の計画、方針をどこまで具体的にできるかというのは、現在の時点ではそこにつきましても検討させていただきたいです。","id":"exchange-003"},{"speaker":"鈴木委員","kind":"質問・要望","question":"それを併せてやっていくとなると、しっかりと分析をして、計画をつくっていっていただきたいということでお願いをしておきたいと思います。２ページの、実際は区としてはどう認識されているのか、その点についても伺いたいと思います。","respondent":"佐藤障害者施策推進課長","answer":"都度、きちんと対応しておりますので、そういったところについてはきちんと対応していると認識しております。陳情に書いてあるとおりになりますが、全体的な施設の老朽化等も踏まえまして、直ちに安全が確保されていないというところでは認識はしておりません。","id":"exchange-004"},{"speaker":"鈴木委員","kind":"確認","question":"それでも、区としては安全対策はきちんと取っているということでの認識だということで確認させていただいていいでしょうか。品川区はやっていないということでここに書かれているのですが、そういう状況なのか、そこら辺のところも分かったら説明を求めました。","respondent":"佐藤障害者施策推進課長","answer":"初めのお話ですけれども、安全につきましてはきちんと対応しているという認識です。別の形で改築や改修等に入ったときに対応しているものもあると認識しておりますので、区内の施設につきましては対応しているという状況です。","id":"exchange-005"},{"speaker":"あくつ委員","kind":"質問・要望","question":"ＡＩ云々と書いてありますけれども、全区民アンケートの調査結果というのがダイレクトに反映をされるものなのか伺いたいというのが１つ。手帳の所持者、どれぐらいの数をこれはアンケートを出して、回収率がどれぐらいなのかということをお伺いしたいと思います。","respondent":"佐藤障害者施策推進課長","answer":"こちらは全てのサービスを利用されている方を抽出しまして実施しているというところで、合計で約６,０００名を対象に調査を実施している状況です。こちらのほうが回収率が全体で４０％台ですので、一応、そのような状況で実施させていただいたところです。","id":"exchange-006"},{"speaker":"あくつ委員","kind":"確認","question":"当事者の方、利用者の方と手帳の所持者の方で大体６,０００名、前回も同規模ということで確認させていただきました。先ほどお伺いすればよかったのですけれども、こちらの今回陳情を出されているところも行われたのかどうか、確認をさせてください。","respondent":"佐藤障害者施策推進課長","answer":"こちらにつきましては、予定していた団体については、昨年中、１０月までに終了している状況です。こちらの陳情の方の団体もというご質問だったかと思いますけれども、こちらについても実施したところです。","id":"exchange-007"},{"speaker":"あくつ委員","kind":"意見","question":"６,０００名のうち、前回は４０％というお話がありましたが、聞くべきところには聞いているという感触は私も受けました。陳情の趣旨とは異なりますけれども、分析をここはしっかりしていただいて、真のニーズに基づいた計画を立ててほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-008"},{"speaker":"吉田委員","kind":"質問・要望","question":"ほかにも７団体に入っていないところは幾つかというか、それについて全部聞き取りができたのかということをまず確認させてほしいと求めました。きちんと施設に入って、いろいろな支援を受けながら自立していくというものを求めていて、それをもって実績１になるのではないか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"そういったところについては、状況も踏まえて検討して実施していますので、そういった対応があります。学識経験者等入っておりますので、そういったところでの客観的な評価、今後の施策の方針等についてはきちんと検討してまいります。","id":"exchange-009"},{"speaker":"吉田委員","kind":"質問・要望","question":"そちらに力を入れるべきということだと思うので、新しい計画を策定していく時期なので、その点について改めてもう一回ご意見を伺いたいと思います。だから、そこは争いになっては困りますけれども、そのような要望をきちんと上げていくべきではないかと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-010"},{"speaker":"吉田委員","kind":"意見","question":"戸開走行するよりも、そこはご意見がいろいろあって当然だと思いますが、そういう趣旨のことが書かれているのだという。既存不適格はここにも関係しているので、それを意見として申し上げておりますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-011"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"様々な質疑がありましたので、私のほうでは１つだけ。品川区は２３区最低の障害福祉のまちだと書かれておりますけれども、意気込みがありましたら、お話を聞かせていただきたい。","respondent":"佐藤障害者施策推進課長","answer":"２３区最低の障害福祉というところ、いずれにしても、もちろん品川区をよりよいところに進めていくというところでは所管も考えているところです。基本方針で、その部分については当然進めてまいりますし…","id":"exchange-012"},{"speaker":"やなぎさわ委員","kind":"確認","question":"今ご答弁があったように、さらなる充実をしっかりと図っていくというようなところで確認できました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-013"},{"speaker":"えのした副委員長","kind":"意見","question":"障害者団体のヒアリングなど基礎調査をしているということで、様々対応も行っていて、施設の整備をしております。そういったニーズを反映して策定するというご答弁もありましたし、区民の方に寄り添った障害福祉計画の策定をお願いいたしますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-014"},{"speaker":"あくつ委員","kind":"確認","question":"サービスの利用者、当事者の方からの意見は一定程度というか、ほぼ聞いていらっしゃるということは確認ができました。この方のおっしゃることも一面では本当にそのとおりだと思うのですけれども、今回の陳情の趣旨としては不採択とさせてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-015"},{"speaker":"鈴木委員","kind":"質問・要望","question":"本日採決をするということで、趣旨採択でお願いしたいと思います。ニーズを分析した上で、ニーズを反映させた必要量という形でぜひやってほしいと求めましたので、よろしくお願いしたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-016"},{"speaker":"吉田委員","kind":"意見","question":"もう少しきちんと必要量を把握してほしいというご意見も出てきていますし、まだやり方としてはもう少しこうあってほしいというご意見もあります。これについては、いろいろな障害者団体の中でも、ぜひそのように進めてほしいという賛同を得られるのではないかと考えていますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-017"},{"speaker":"やなぎさわ委員","kind":"意見","question":"区の取組というのは評価できる部分はたくさんあると思うのですけれども、そういった中で、やはり必要量を出すと。品川区の障害者福祉、前へ進めていけるのではないかと思いまして、私は趣旨採択ということでお願いできればと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-018"},{"speaker":"田中委員長","kind":"質問・要望","question":"これまでの質疑を伺っていまして、私は、本陳情につきましては不採択とすべきものと裁決をいたします。優先的に対応すべき事業を踏まえた障害福祉計画を策定するよう、区に求める陳情につきましては、不採択すべきものと決定いたします。","respondent":"佐藤障害者施策推進課長","answer":"区内の指定障害児通所支援事業所に対して実施した監査におきまして、運営法人に対し、不正に受給した給付費の返還を命じることを報告するものです。児童相談所設置区としての行政処分は、今回、こちらが初めてとなりますが、慎重に処分内容を検討しまして…","id":"exchange-019"}]},{"id":"topic-02","title":"指定障害児通所支援事業者の行政処分","agenda":"指定障害児通所支援事業者の行政処分","exchanges":[{"speaker":"鈴木委員","kind":"質問・要望","question":"そこら辺のところも具体的に教えていただきたいのと、行為を確認ということで書いてあるのですけれども、誰が行ったのかということを教えてください。具体的には、守ってくださいと言うことだけが再発防止策ということなのか、その点についても伺います。","respondent":"佐藤障害者施策推進課長","answer":"おおむね３年に１回、各事業所を回るようにというところで東京都からもございまして、それに対応できるような形で順次見回っていたところです。事例をきちんと伝えて、法の遵守、制度をきちんと確認して対応していただくように指導していくです。","id":"exchange-020"},{"speaker":"鈴木委員","kind":"質問","question":"そこら辺のところの職員の確保の努力の状況というのはどうだったのかということを伺えたらと思います。トータルすると１３名みたいな、そういう中での職員確保の状況というのは区としてはどう捉えているのか、伺えたらと思います。","respondent":"寺嶋福祉部長、佐藤障害者施策推進課長","answer":"３年に１回きちんと定期的にチェックをして、当然、それがないと分からないということではないというところをまずご理解いただきたいということです。医療的ケアと処分については、担当課長よりご答弁申し上げます。 こちらの事業所の登録者数等々に関しては、持ち合わせてございません。定員としては５名ということで、ほかの放課後等デイサービスと同様に実施されているところかと認識しております。","id":"exchange-021"},{"speaker":"鈴木委員","kind":"質問・要望","question":"さらに要望に応えられるようにということで努力をしていただいているところだと思うのですけれども、実態をしっかりと把握をしていただいて、よりよいサービスにつながっていくようによろしくお願いをしておきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-022"},{"speaker":"吉田委員","kind":"質問","question":"本当に放課後等デイサービスというのにふさわしい療育というか、個別具体的にあそこがという情報は来なかったのですけれども、そういうのがある。こういう形での３年に１回現場を見に行くとか、そういうことでずっとやってきたという理解でよろしいのでしょうかというのをまず伺いたいと思います。","respondent":"佐藤障害者施策推進課長","answer":"支援の内容、それから、事業者へ改善を申し入れてほしいといったようなお声をいただくこともあります。事実であれば改善等も含めて、適宜、指導等については随時行っているところです。","id":"exchange-023"},{"speaker":"吉田委員","kind":"質問・要望","question":"定期的な検査とはほかに、実際にきちんと見に行くとか、指導をしているという理解でいいでしょうか。療育を求めて放課後等デイサービスに通わせるわけだから、区として何かきちんと確認する手だてが、その点についてはいかがか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"匿名等での部分についても対応しておりますし、そういった不利益が及ばないような形できちんと対応はしてまいりますので、そこについては。そういったところがきちんとされているかというところは確認をして、指導等も行っている状況ですので…","id":"exchange-024"},{"speaker":"吉田委員","kind":"質問・要望","question":"預かってほしい、少しでもよい療育をしてほしいというニーズで預けるのだと思いますけれども、増えてしまうのもやむを得ないかと。これは要望です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-025"},{"speaker":"あくつ委員","kind":"確認","question":"この３か月間、これから３か月後には新規も受入れをやるという中で、その改善はしっかりなされる。そういう人的リソースについても、この事業者がしっかりそこは手当てできるのかというところについて確認をさせてください。","respondent":"佐藤障害者施策推進課長","answer":"ほか２つに関しましても、事業の実施に対して、そもそも足りなければ事業の運営自体ができなかったところをやっていたという形ではございません。支援内容ですとか、こちらの処分が妥当というところで、こちらのほうで決定したところです。","id":"exchange-026"},{"speaker":"あくつ委員","kind":"確認","question":"過去の一部の期間というところの今回の処分と。事業所のところが、そういったところについては大丈夫だということで品川区で確認をしたということでいいのか、最後に聞かせてください。","respondent":"佐藤障害者施策推進課長","answer":"委員おっしゃるとおり、事業運営に関しましても、基準となる職員体制は確保されております。加算等につきましては、適正に対応されるというところで確認をしています。","id":"exchange-027"},{"speaker":"やなぎさわ委員","kind":"確認","question":"確認なのですけれども、主に３年に１回程度行う、そういった位置づけでよろしいのか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"請求が間違いであったとか、そういったところについては、そこを改善するところで実地検査としては終了するところです。そこの内容が不正であったりというようなところで、処分を含めて、さらに確認等が必要というところで、監査を実施したというようなところがあります。","id":"exchange-028"},{"speaker":"やなぎさわ委員","kind":"確認","question":"「どうですか、３年に１回の実地検査のときに、お互い出してというような感じでやっていくことになっているのが現状だと思います。２０１９年、令和７年５月に内部のリークがあって実地検査を行ったのですけれども、これは通算でいえば何回目の実地検査になるのか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"ミントへの指導等に関しては、こちら、回数の履歴に関してまでは手元にございませんが、前回、令和４年６月に運営指導については実施しております。そのときについては、書類の不備等の軽微な部分については、その場での改善というところで対応したというところで確認しています。","id":"exchange-029"},{"speaker":"やなぎさわ委員","kind":"確認","question":"開設して１回目の検査が令和４年にあって、２回目が令和７年ということで確認できました。答えは明白かもしれないですけれども、そういったことについては何か事業者側からの回答というか、弁明はあったのか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"委員おっしゃっていただいたようなところについては、弁明書についてはございません。実態のない書類上の体制等でもって受給したというところで、その辺りは給付費を多く取るというところでの意図的に行われたものと認識しています。","id":"exchange-030"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"不正利得分１７８万４,０００円と、普通の事業所だと、なかなかこれぐらいの返金をするというので運営にかなり影響が出ると思うのです。ほかにも何か事業所があるみたいな記載もありますけれども、どれぐらいの規模の会社なのかというのがもし分かれば教えていただきたいです。","respondent":"佐藤障害者施策推進課長","answer":"こちらの運営法人としては、放課後等デイサービスはこちらの区内のミント１か所のみを実施しています。所管のほうから対応しますけれども、状況を確認しつつ、対応していくです。","id":"exchange-031"},{"speaker":"やなぎさわ委員","kind":"確認","question":"どういう形式で、支払いというのは特にまだ決まっていないのかどうかということの確認と、非常にこの会社の存続含めて心配になる。しっかり立て直しというか、状況をつぶさに見ていく必要が私はあると思うのですけれども、その点いかがか尋ねました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-032"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"ぜひ余裕を持ってお伺いできるような、そういったマンパワーの増強も含めて、要望だけしておきます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-033"}]},{"id":"topic-03","title":"介護保険事業計画改定に伴う日常生活圏域ニーズ調査","agenda":"介護保険事業計画改定に伴う日常生活圏域ニーズ調査","exchanges":[{"speaker":"鈴木委員","kind":"質問・要望","question":"自分だったらどうかという思いでやってみたのですけれども、９項目から入れられるということであれば、その点１点伺いたいと思います。要望だったりとか、そういうところが出してもらえるようなものにせめてできないかと思うのですけれども、いかがか尋ねました。","respondent":"菅野高齢者福祉課長","answer":"今年度から新しく新設されました介護人材確保定着支援担当のほうでも、事業者向けにアンケートなどを実施していますので、そういった機会を捉えて。最後に、在宅サービス利用者へ毎年モニタリングアンケートということを実施していますが…","id":"exchange-034"},{"speaker":"鈴木委員","kind":"質問・要望","question":"ご報告いただいて、厚生委員会としても検討できるようにというところはぜひしていただきたいと思うのですけれども、その点を伺いたいと思います。要支援でサービスを使っている方も含まれるわけですから、要望だったりとか実態というのが見える形にぜひとも、その点について伺いたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-035"},{"speaker":"やなぎさわ委員","kind":"質問","question":"まさに地域活動にアクセスするための交通についてもあったほうがよかったかなと思ったりするのですけれども、その点、いかがか尋ねました。","respondent":"菅野高齢者福祉課長","answer":"高齢者の方が例えば病院に通うときとか買物に行かれるとき、どういった交通を使われているのかというのはすごく大事な視点だとは捉えております。在宅介護支援センター等のケアマネジャー等も通じながら、どういった実態なのかというところは常時把握していきたいと思います。","id":"exchange-036"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"ここにも一応、３ページ目のところに赤いはんこで「案」と書いてあるので、さらにブラッシュアップして調査を実施していただければいいと思いました。要望です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-037"}]},{"id":"topic-04","title":"生活扶助基準改定に関する最高裁判決への対応","agenda":"生活扶助基準改定に関する最高裁判決への対応","exchanges":[{"speaker":"あくつ委員","kind":"質問","question":"これも２月の計算ツールのリリースの前にその作業というのはできるのですかというところが、まずそこを伺いたいと思います。リリースがないと、データの加工というのはできないのか、まずはそこをお伺いしたいと思います。","respondent":"豊嶋生活福祉課長","answer":"それは今やれることとすると、人が全ての記録を全て読み起こして、データを加工しなければいけません。人海で全てやるよりは、恐らくそちらのほうが早いだろうということから、今は何ができるかというのを知恵を出し合っている状態です。","id":"exchange-038"},{"speaker":"あくつ委員","kind":"質問","question":"その辺り、原告の方が２倍ぐらい多いみたいなことになっているのですけれども、どうしてそういう形になっているのか。原告というのは、品川区で抽出するのでしょうかというところ、その辺りが理解できないので、そこだけ説明を求めました。","respondent":"豊嶋生活福祉課長","answer":"国から実は明確な説明があまりなかったもので、結局は最終的に計算ツールに当てはめて、歯切れが悪い答弁で申し訳ありません。今私が持ち合わせている情報は以上です。","id":"exchange-039"},{"speaker":"鈴木委員","kind":"質問・要望","question":"そういうことになっていくと考えて、大体そのようになるということで考えられているのかということも伺いたいと思います。ぜひ声を上げていっていただきたいと思うのですけれども、その点についても伺いたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-040"},{"speaker":"鈴木委員","kind":"質問・要望","question":"それと、言ってみれば違法な引下げによって本当に大変な状況を強いられてきたわけですから、本来であれば守るべきところが守られない。１人５万３,７００円ですけれども、意見、声を上げていただきたいということで要望させてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-041"}]},{"id":"topic-05","title":"所管事務調査","agenda":"所管事務調査","exchanges":[{"speaker":"あくつ委員","kind":"質問・要望","question":"３年間ですかね、令和４年度の３年間で、ざっと計算してマイナス５.４％で減っている。どうしてこういう変化が起きたのかというところをまず教えていただきたいのが１点と、これ、対象者はどのような障害のある方なのか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"先ほども申し上げましたけれども、サービス利用者の方、それから手帳をお持ちの方の抽出というような形で実施したアンケート調査です。１つは、整備を進めてきたという中で、施設入所に関してのニーズの変化があったのかというところを考えているところもあります。","id":"exchange-042"},{"speaker":"あくつ委員","kind":"質問","question":"そういうなかなか難しいニーズだと私も団体の方から視覚障害の方から伺ったりして、裏表も全部分かっている人たちで、このような話もありました。状況さえそろえば入れるのでしょうけれども、場合によっては、視覚障害者専用のグループホームも、自治体によってはあると伺いました。","respondent":"佐藤障害者施策推進課長","answer":"既存のグループホームですとか、新たに造るところの中で、視覚障害の方も十分に対応できるようなところで図っていけるのか。そこに特化したものが造れるのかといったところについては、検討してまいりたいです。","id":"exchange-043"},{"speaker":"あくつ委員","kind":"質問","question":"それとも、そもそも申し込まないのかというところ、そこだけ教えてほしいと求めました。把握していなければ把握していないで結構です。","respondent":"菅野高齢者福祉課長","answer":"要介護３以上の方が対象という形で、その中で視覚障害の方がいらっしゃるかという、その詳細のところまでは把握できていないところはあります。ただ、要介護３以上というところで審査に通った後、施設で調整して…","id":"exchange-044"},{"speaker":"あくつ委員","kind":"質問・要望","question":"やはりそういった方は、恐らくその後の生活の困難さを考えると、そもそも申し込まない方が多いのかと。というところもある中で、その後余生をどうやって過ごすのかというところで、そういった方にもしっかり目を向けてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-045"},{"speaker":"吉田委員","kind":"質問","question":"すみません。伺ってもお答えは難しいと思いつつ、少し伺ってみたくなってしまうのですけれども、その辺についてはいかがか尋ねました。","respondent":"松山障害者支援課長","answer":"種別が、なかなか１か所ずつ定員に対してどうかというのが難しいところではありますが、これからも伸びていくだろうというのが推測されます。ただ、出石つばさの家につきましてはまだ空いておりますので、今ご利用を勧めているような状況にあります。","id":"exchange-046"},{"speaker":"吉田委員","kind":"確認","question":"報告をいただいたことに対してまた質問になってしまうので、そういうことであれば、随時空いていますという広報はされているということでしょうか。少し確認だけさせてください。","respondent":"松山障害者支援課長","answer":"ご利用を促すために、相談支援事業所経由で、ぜひご利用くださいという形でご案内をしております。","id":"exchange-047"},{"speaker":"吉田委員","kind":"質問・要望","question":"ということは、定期的に相談支援事業所に行きますよね。そういうときに要望とかを聞いて、しかるべき方には、こういうのが空いていますというような感じの情報提供ということでいいのか尋ねました。","respondent":"松山障害者支援課長","answer":"ご本人の生活状況ですとかニーズは既に相談支援専門員はつかんでおり、この先の将来、どうしたいかというご希望もいただいておりますので、そういった方に合わせて、ぜひご利用くださいというご案内は随時しております。","id":"exchange-048"},{"speaker":"鈴木委員","kind":"質問・要望","question":"地域移行の分科会というのですか、支援区分というのがどういう状況なのかということも教えていただけるようでしたら、お願いしたいと思います。かがやき園とかもめ園の２か所あると思うのですけれども、その中にもこういう担当者の方はいらっしゃって、その仕組みについても伺えたらと思います。","respondent":"松山障害者支援課長","answer":"３点目、国が定めておりまして、全ての入所施設で選任された職員を置くということが令和８年度から義務づけられるということです。かがやき園と、かもめ園につきましても、来年度から選任される予定です。","id":"exchange-049"},{"speaker":"鈴木委員","kind":"質問・要望","question":"品川区の定数としては１３０人の定数ということなのですけれども、トータルで何人いるかというのが分かったら、教えてほしいと求めました。そこら辺の、交渉するというのが区のほうとしてあったと思うのですけれども、現状を教えていただけたらと思います。","respondent":"佐藤障害者施策推進課長、松山障害者支援課長","answer":"実績のほうについて、私のほうでお答えいたしますが、施設入所支援、資料の右上、（２）実績のところです。こちらが、区内にかかわらず施設入所支援サービスを利用されている方になりますので、実績… 福祉型というのは、総合支援法の福祉サービスを使われた場合のものですので、区独自の医療ショートステイとはこちらは違うものになっております。区独自の医療ショートステイにつきましては、現在交渉を続けております。","id":"exchange-050"},{"speaker":"吉田委員","kind":"質問・要望","question":"障害者のグループホームを求めている方にとっても、あそこがどうなるのだろうかというのは気になるところで、いずれそこが検討されるのかと。現在、今お答えになれる範囲でお答えいただけるとありがたいのですけれども、いかがか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"東京都の児童相談所のところについては、恐らく北品川つばさの家と、それから就労支援の施設が、現状はかもめ工房が入っているかと思います。ここが空いて区が使えるとなったときに、適切な対応ができるというところはあるかもしれませんが…","id":"exchange-051"},{"speaker":"吉田委員","kind":"質問・要望","question":"自分たちが選んで、こういうところなら入りたいという施設が増えてほしいというのは、当然のご要望だと思うのです。そういうのは一番必要とされている方たちと共有しながら、ぜひ適切な情報提供を今後していただけるように、要望させてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-052"}]},{"id":"topic-06","title":"行政視察報告書","agenda":"行政視察報告書","exchanges":[{"speaker":"鈴木委員","kind":"質問・要望","question":"ホームページに公開するというところで、ぜひ意見も言っていただきたいと思いまして、そういう意見が出たということを言っていただけたらと思います。意見です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-053"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/784410?Template=document&Id=7295#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=7&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":53964,"voices":145}},{"id":"r08-20260119-8","meetingId":"r08-m01","date":"2026年1月19日","dateIso":"2026-01-19","committee":"建設委員会","time":"午後 １時００分～午後 ６時１７分","status":"正式会議録","sourceType":"formal","overview":"建設委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を105件整理しています。","topics":[{"id":"topic-01","title":"請願・陳情審査および報告事項","agenda":"請願・陳情審査および報告事項","exchanges":[{"speaker":"安藤委員","kind":"提案","question":"ですから、この建設委員会から提案して、私は必要なのではないかと思うのです。この言葉を使われるのは初めてでよろしかったかの確認と、つまり、何を求めたのかを改めて伺いたいと思いますとの意見を述べました。","respondent":"高梨都市計画課長","answer":"この間、区は、大臣面会等でも海上ルートの実現に向けた方策を信じてまいりたいというような要望は行ってまいりました。国が今いろいろと固定化回避検討会の中で検討を進めているところでありますけれども、これからも、しっかりと求めてまいりたいと考えています。","id":"exchange-001"},{"speaker":"安藤委員","kind":"質問・要望","question":"もう少しこの要請文について伺うのですが、第７回固定化回避検討会を受けて、そういうふうに認識を示しているのです。その上で、「その検討を加速し」と要望しているのですけれども、国のどういう点を区は評価したのか、改めて伺いたいと思います。","respondent":"高梨都市計画課長","answer":"私から先ほど説明させていただいた国が公表した資料７、海上ルートの実現可能性を追求するというようなことが記載されてあります。早く示してもらいたいという意味で、要望文には記載をさせていただいたところです。","id":"exchange-002"},{"speaker":"安藤委員","kind":"質問・要望","question":"国に時期を切った検討を求めるべきなのではないかと思うのですけれども、いかがでしょうかというのが１つ。これ、実現できるのでしょうか、伺いたいと思います。","respondent":"高梨都市計画課長","answer":"いつまでに実現をしてもらいたいということで具体的な実施の時期を申し述べることは可能かと思いますけれども、まだこの段階では。国でしっかりと検討していただくことであって、この滑走路を使ってくださいと、ルートを縛ることは考えてございません。","id":"exchange-003"},{"speaker":"安藤委員","kind":"質問・要望","question":"もともと海から入って海に出ていっていたわけですから、そうしたら、初めてそのルートを使えばいいと思うのです。今の検討の加速化をしてほしいと品川区が要望していますけれども、ぜひ品川区として求めていただきたいのですが、いかがか尋ねました。","respondent":"高梨都市計画課長","answer":"第７回では、検討を国のほうで進められているといったようなことで、国の検討の進捗はしっかりあるのかなと感じているところです。今、国が求めて追求する海上ルートの実現を一刻も早く検討を加速化していただいて、一日も早く海上ルートの実現を求めていくという立場です。","id":"exchange-004"},{"speaker":"安藤委員","kind":"提案","question":"私は、少なくとも、品川区が求めたような海上ルート、市街地を飛ばない海上ルートは、議会としても要望すべきだと思う。今日出されたルート撤回を国と交渉してほしいというような請願もありますので、国の航空政策再検討も含めた要望を行うべきだと思うのですけれどもとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-005"},{"speaker":"中塚委員","kind":"質問・要望","question":"ぜひそれを受け止めていただいて、まずは各委員の意見も表明していただきたいなと私も求めておきたいと思います。区長の要望書の最後のほうにある「市街地上空を通過しない海上ルートの実現に向けた検討を加速」、ここで区長が求める海上ルートとは。","respondent":"高梨都市計画課長","answer":"３番目の質問にも関係してまいりますけれども、そこで言う海上ルートに従来ルートは含んでいないものであるというような認識をしています。品川区の上空を飛ばない、市街地上空を飛ばない海上ルートの実現をしっかりと区としては要望してまいりたいと考えているところです。","id":"exchange-006"},{"speaker":"中塚委員","kind":"質問・要望","question":"いわゆる海上ルートの検討について、森澤区長としては、固定化回避検討会に検討を求めているということでいいのかどうかを伺いたいと思います。森澤区長としては、この固定化回避検討会に検討を求めるものなのか、そこをどう考えているのか併せて伺いたいと思います。","respondent":"高梨都市計画課長","answer":"区としては、国の検討の中では、海上ルートの中に従来ルートは含まれていないと考えているところです。品川区としては、固定化回避検討会の中で今後の方向性を検討すると言われていますので、その検討をしっかりやっていただきたいということを要望する。","id":"exchange-007"},{"speaker":"中塚委員","kind":"質問・要望","question":"市街地上空を通過しない従来ルートに戻すべきだと区から国に要望すべきだと思うのですが、この点、いかがでしょうか。従来ルートで増便が大前提ですから、さっきの質問と同じですけれども、改めていかがか尋ねました。","respondent":"高梨都市計画課長","answer":"国が検討していく内容について、やはりやると言ったのであれば、しっかりやっていただく。区としては、固定化回避検討会での検討結果をしっかりと早く示していただきたいといったところで要望してまいりたいと考えているところです。","id":"exchange-008"},{"speaker":"中塚委員","kind":"質問・要望","question":"６年間の区民の苦しみも国としては正面から受け止めるべきだと、区も引き続き、それを国に伝えていただきたいと要望したいと思います。最後に、各委員の皆さんに、ぜひまずはご意見を伺いたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-009"},{"speaker":"せお副委員長","kind":"質問・要望","question":"私が議員になる前の平成３１年ですか、同じ、そういった思いがあるところをまず前提としていただきたいというところです。最近ですと、先ほどご説明がありましたけれども、区からも何回か要望書を出している。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-010"},{"speaker":"松永委員","kind":"質問・要望","question":"我が会派としては、継続でお願いいたします。区民負担の軽減のルートを求めて要望書を出されている段階であり、今回のこちらの陳情に対しては、継続でお願いしたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-011"},{"speaker":"ゆきた委員","kind":"意見","question":"第７回の検討会についても開催され、一定の進捗が示されたこともあります。あくまで固定化を回避する前提の検討会という認識でありますし、また、引き続き検討状況を見ていきたいというところもあるので、継続でお願いしますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-012"},{"speaker":"安藤委員","kind":"質問・要望","question":"なおかつ、品川区も発言を強めているという中ですから、私は、新たな決議が必要だと思います。即刻中止を求める陳情とありますけれども、私は、住民の苦境を取り除くためには、このルートは即刻中止をすべきだと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-013"},{"speaker":"中塚委員","kind":"質問・要望","question":"区議会としても新たに「海上ルート」という言葉をしっかり使った決議なり要望なりをすべきであって、審査を継続とする理由ではないと思います。なので、ここに期待をすることができないと思いますので、改めて採択すべきだと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-014"},{"speaker":"せお副委員長","kind":"意見","question":"ごめんなさい、私の言葉が足らずで、検討途中ですので、それを見守っていくという意味で継続とします。理由は、先ほどと同じですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-015"},{"speaker":"安藤委員","kind":"質問・要望","question":"本日結論を出すで、採択なのですが、陳情にありますように、従来の海上ルートに戻すこと、首都圏一極集中を避けるべきと国に求めるべきだと思いますので、賛成です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-016"},{"speaker":"中塚委員","kind":"質問・要望","question":"森澤区長であっても、検討途中の固定化回避検討会に対して、アンケートの結果を背景に区としての要望を出しているわけです。飛んでからのこのフェーズの中で、区議会の態度表明を行うことが、今こそ必要だということも述べておきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-017"},{"speaker":"安藤委員","kind":"意見","question":"今、本陳情の最後にある都心ルート撤回に匹敵するような市街地上空を通過しない海上ルートを要請するに至ったと私たちは考えております。情勢としては陳情の趣旨にそって動いているなと思いますので、採択ということでお願いしますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-018"},{"speaker":"中塚委員","kind":"意見","question":"結論を出すということと、採択でお願いいたします。直近の要請では、どう違うのかは質疑をしてみないと分からない部分もあるので、そこはそこで述べておきたいと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-019"},{"speaker":"安藤委員","kind":"質問・要望","question":"これは説明してほしいという内容なので、なぜ継続にするのかということが分からない。説明することすら議会としては求めないのかということになってくると思うのです。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-020"},{"speaker":"中塚委員","kind":"質問・要望","question":"今、説明がありましたけれども、この陳情は、検討会での検討内容を教室型説明会を開いて説明してほしいという内容です。各会派はこうした区民の声にしっかり向き合っていただきたいなと述べておきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-021"},{"speaker":"中塚委員","kind":"質問・要望","question":"なぜ説明会の開催を求める請願に対して継続とするのか、その理由が示されていないと思います。ただ、理由を示して議論を深めるということが議会の役割だと私は思いますので、ぜひ委員の方のお考え、ご意見を伺いたいと求めておきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-022"},{"speaker":"中塚委員","kind":"質問・要望","question":"先ほど、理由が示されていないと継続を主張した方に述べましたが、今回も、住民説明会の開催を求める請願を継続とする理由が示されておりません。区民がそれを求めるのは当然だし、議会もそれを採択してこそ、議会の役割が発揮されると私は思いますと述べておきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-023"},{"speaker":"安藤委員","kind":"質問・要望","question":"本日結論を出すで、採択なのですけれども、区議会として、やはり僅かばかりの増便のために区民生活を多大に犠牲にするような航空政策は国に再検討を求めるべきだと思いますし、それが新ルートに現在でも苦しむ区民を救うことにつながると思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-024"},{"speaker":"中塚委員","kind":"意見","question":"品川区議会として計画撤回を国と交渉してほしいという請願です。いずれにしても、結論を出すべきだと思うし、採択すべきだと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-025"}]},{"id":"topic-02","title":"令和７年陳情第５８号（品川浦南地区再開発）","agenda":"令和７年陳情第５８号（品川浦南地区再開発）","exchanges":[{"speaker":"安藤委員","kind":"質問・要望","question":"陳情に国交省通達という言葉が出てくるのですけれども、それについて、内容について改めて教えてほしいと求めました。区分所有者数、もしくはマンション棟数など、こちらを伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"借地権者数が６名、権利者数といたしましては５８名、区分所有のマンションといたしましては６棟あります。借地権者数が１名、権利者数としては合計１８名、区分所有のマンションといたしましては３棟あると確認しています。","id":"exchange-026"},{"speaker":"安藤委員","kind":"質問","question":"かつて私たちも質問したように、１３の開発関連企業がここに集結しているということで、すさまじいところなのです。国の制度変更を受けて、この再開発計画を一度白紙に戻すべきだと思うのですけれども、いかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"地域住民の方が主体的に検討してございまして、範囲といたしましても、地域住民の話合いの中で決められているものと認識しています。区といたしましては、引き続き、しっかりと耳を傾けながら受け止めていきたいと考えているところです。","id":"exchange-027"},{"speaker":"安藤委員","kind":"確認","question":"それを住民に押しつけるのが区のまちづくりなのですかと言われても仕方ないと思うのですけれども、いかがでしょうかと、まずお伺いしたいと思います。これはそういうことで間違いがないかということを確認したいのと、また、その立て替えた資金はどうなるのか伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"１点目の総合実施計画に記載していますスケジュールにつきましては。こちらは、仮に事業が未実施となった場合、その負担について権利者が負うものではないと区としては認識しています。","id":"exchange-028"},{"speaker":"安藤委員","kind":"質問","question":"私がこれを伺ったのは、これが区のまちづくりではないのですかと言われたらどうするのですかというか、そこら辺についてどう説明するのか。２点目の資金については、未実施の場合は住民が負担を負うものではないとありますけれども、では、誰が負担するのかということもお伺いします。","respondent":"大石まちづくり立体化担当課長","answer":"総合実施計画につきましても、地域主体で構成されております準備組合からのヒアリング内容を踏まえまして、区として位置づけているものです。２点目の未実施の場合の立替金の負担ですけれども…","id":"exchange-029"},{"speaker":"安藤委員","kind":"質問","question":"品川浦周辺の再開発を推進するまちづくりビジョンは白紙にすべきなのではないですかと、まずは地域住民と意見交換を行っていくと答弁がありました。その答弁との関係はどういうふうになっているのか伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"昨年１２月中旬に開催させていただきました意見交換会の実施目的です。ただ一方で、個別で問合せがあった際はしっかりと対応していく、そういった考えでこれからも進めていきたいと考えているところです。","id":"exchange-030"},{"speaker":"安藤委員","kind":"質問","question":"これ、なぜ隠したのでしょうか、伺いたいと思います。再開発を前提にして、それを推進するというようなことはやるべきではないと思いますけれども、いかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"冒頭、確かに今回の意見交換会につきましては、準備組合での検討内容とは切り離してお話をさせていただきました。地域の皆様がどうお考えになるのか、あくまで準備組合での検討内容については、こちらからお話しすることはいたしませんでした。","id":"exchange-031"},{"speaker":"安藤委員","kind":"質問","question":"その結果、現状計画は当然白紙にすべきだと思いますけれども、どれだけ地域住民のまちづくりの声を把握できているのですか。把握するためには、もっと踏み込んだ、この陳情にあるような、アンケート調査などもすべきなのではないかと思うのですけれども、いかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"区といたしましても、先ほども申しましたとおり、昨年１２月の意見交換会をもって全ての意見を把握できたとは考えていないところです。アンケートも含めて、手法について検討してまいりたいと、このように考えているところです。","id":"exchange-032"},{"speaker":"安藤委員","kind":"質問・要望","question":"ここにも書いていますように、再開発の要望は非常に難しいことが多いです。そこら辺、ぜひ汲み取っていただきたいと最後に意見を述べさせてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-033"},{"speaker":"中塚委員","kind":"質問・要望","question":"その理由を２つ目に伺いたいと思います。なぜ準備組合のヒアリングだけなのか、なぜ参加していない、この２点を伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"２点目の総合実施計画に反対している人のヒアリングをしなかったのかですけれども、総合実施計画に記載しているものにつきましては。区といたしましても、しっかりと耳を傾けてまいりたいと、このように考えているところです。","id":"exchange-034"},{"speaker":"中塚委員","kind":"質問","question":"改めて、反対の声を受け止めると言いながら、なぜ白紙に戻さないのか、なぜ進める立場になるのか伺いたいと思います。なぜそうしたタワーマンションやオフィスや、品川区の住宅施策は一体何を目指しているのかと思うのですけれども、その点も伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"今回の総合実施計画をつくるに当たり、残りの３割の方にもしっかりとお示しすることが必要と考えまして、今回。区といたしましては、今後、検討が深まってくると思いますので、そちらについてしっかりとチェック機能を果たしていきたいと考えているところです。","id":"exchange-035"},{"speaker":"中塚委員","kind":"質問・要望","question":"都営住宅を壊して、１億円もの高級マンションを造るのが品川区の住宅施策なのですか。住宅施策の何を考えているのか伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"繰り返しになりますけれども、今、地域では７割程度の方が準備組合に加入してまちづくりの検討をしっかりとやっていただいているという認識です。そういったところを上位計画としながら…","id":"exchange-036"},{"speaker":"中塚委員","kind":"質問","question":"億ションを造ることが品川区の住宅施策として目指しているところなのですか。なぜ億ションを造ることをまちづくりとして進めていくのか、とっとと変えるべきだと思いますけれども、いかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"そういったところも含めて、あくまでまだ検討中ですので、こちらで発言は差し控えさせていただければと思います。区として、そういったものにつきましては複数の事業としっかりと連携をとりながら、総合的に取り組んでいくことが重要と考えているところです。","id":"exchange-037"},{"speaker":"ゆきた委員","kind":"確認","question":"１点だけ確認させてほしいと求めました。陳情項目の２番で、この総合実施計画上の計画検討支援に予算を計上されているのかどうかお聞きできればと思います。","respondent":"大石まちづくり立体化担当課長","answer":"総合実施計画に記載しております「計画検討支援」という、予算計上して何か具体的に準備組合を支援しているというものではございません。あくまで再開発事業は地域住民の皆さんが主体で進めていくものですので、区としては…","id":"exchange-038"},{"speaker":"せお副委員長","kind":"質問・要望","question":"私が区に１点要望したいのは、どちらの意見も、いろいろな意見がある。本当にどんどん進めていただきたいという方も私の周りにもいますけれども、白紙に戻してほしいという方と、その間の意見もあると思うのです。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-039"},{"speaker":"松永委員","kind":"質問・要望","question":"皆さんのご意見についても、先ほど、アンケートも含めてという言葉もありました。そうしたことも踏まえて、この度につきましては不採択にさせてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-040"},{"speaker":"ゆきた委員","kind":"確認","question":"陳情項目１番については、２番についても、計画検討支援については直接的な予算は計上されていないことも確認できました。３番についても、アンケートも１つの手法として含めて検討していくという姿勢を確認できましたので、不採択でお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-041"},{"speaker":"安藤委員","kind":"質問・要望","question":"これは中止をすべきだと思います。少なくとも区は、住民の意向を余すことなく把握する努力をしてほしいと求めましたので、こちらは採択すべきかと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-042"},{"speaker":"中塚委員","kind":"質問・要望","question":"先ほど、億ション、タワーマンションを造ること、が品川区の住宅政策なのかと、これが品川区の住宅施策なのかと伺いました。こうした今までどおりの再開発推進の姿勢は改めるべきだと重ねて求めておきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-043"}]},{"id":"topic-03","title":"東京における都市計画道路の整備方針（案）","agenda":"東京における都市計画道路の整備方針（案）","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"特定整備路線、補助２９号線や放射２号線については、やはり検証した上で廃止をすべき路線だと思います。実際の来場者は何人ぐらいいたのかを伺いたいと思いますし、もしご意見などを出されたのであれば、どのような意見が出されたのか伺いたいと思います。","respondent":"高梨都市計画課長","answer":"都市計画課にご用があってお立ち寄りになられた方から、パネルの内容についてご質問があって、担当職員が対応させていただいたといったところです。特段、計画内容の説明をさせていただいて、お客様のほうから計画内容についてのご意見はなかったと聞いているところです。","id":"exchange-044"},{"speaker":"安藤委員","kind":"質問・要望","question":"それと、続けてなのですが、品川区内でいうと、今回の検討の対象になった路線は何本あるのか伺いたいと思います。今回の検証に当たって、区として、これは廃止候補路線として上げるべきなのではというふうに考えた路線は幾つぐらいあったのか伺いたいと思います。","respondent":"高梨都市計画課長","answer":"検討対象の路線数ですが、都施行路線、区施行路線ありますが、全路線で１５路線となっています。先ほど説明させていただいた補助１６１号線、結果としては、１路線が継続になったところになります。","id":"exchange-045"},{"speaker":"安藤委員","kind":"質問・要望","question":"２本を協議対象として挙げて、１本が廃止路線になったということでした。ぜひ今後の検討に向けて、様々そういった住民の声も聞きながら、時代に合わせて廃止をしていくということも進めていっていただきたいなと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-046"},{"speaker":"中塚委員","kind":"質問・要望","question":"それと、都に要望したものですけれども、これは文章なのですか。そこを知りたいのと、公文書であれば、ぜひ見せてほしいと思うのですけれども、いかがか尋ねました。","respondent":"高梨都市計画課長","answer":"今回、概要版の７ページを見ていただきますと、優先整備路線の計画としては第５次事業化計画とお示しをさせていただいているところです。ウェブ等の会議で、品川区からこの路線はこうしてほしいというような個別の路線の打合せをして…","id":"exchange-047"},{"speaker":"中塚委員","kind":"質問・要望","question":"引き続きという要望になるのか、こうしてほしいと伝えた理由、狙いを伺います。補助２０５号線ですけれども、何がどう変わるのか、ご説明ほしいと求めました。","respondent":"高梨都市計画課長","answer":"今後１５年間で整備が見込めるといったところで、こちらについても、そういった見込みがあることから。ただ、これまでいろいろと道路課を中心に検討をしてまいりましたけれども、先ほど説明の中でも申し述べたとおり。","id":"exchange-048"},{"speaker":"中塚委員","kind":"質問・要望","question":"現庁舎の跡地活用に、なぜ補助１６３号線の認可が必要になるのか伺います。いよいよ広大な再開発のエリアを西大井にまで広げていくということでやめるべきだと前回批判いたしましたが、違うでしょうか、ご説明ください。","respondent":"高梨都市計画課長","answer":"いわゆる今、逆に言いますと、検討されている地域内の路線は優先整備路線等の位置づけにはしていないといったような状況でもありますので。冒頭の説明で申し上げさせていただいたとおり、今回…","id":"exchange-049"},{"speaker":"中塚委員","kind":"質問・要望","question":"補助１６３号線は、区独自の現庁舎の跡地ですから、区の判断１つで可能となってくる。最後に伺いますが、都市計画道路の推進ですけれども、再開発に向けた整備は、この計画にどのように位置づいているのか。","respondent":"高梨都市計画課長","answer":"そこの再開発でできる、一緒に道路をつくっていくといったところは、まちづくりについては一般的に非常に重要な視点であるといえると考えています。他事業との連携を図っていくような地区については、そういうまちづくりの動きとの連動は…","id":"exchange-050"},{"speaker":"中塚委員","kind":"質問・要望","question":"そして補助２０５号線、原踏切では、西大井駅周辺の再開発等、将来的な動きを見通して進むものだと思います。これ以上の住民を追い出す再開発の中止を改めて求めて質疑を終わりたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-051"},{"speaker":"ゆきた委員","kind":"質問","question":"１３１ページと、先ほど説明がありました１７ページのところに記載されていますが、ここについてお聞きしたいと思います。期間を決めて社会実験を行うことと、区民からはどのような声や反応があったのか、お聞きできればと思います。","respondent":"中道都市開発課長","answer":"社会実験を約３週間行いました。そうした結果につきましては、まちづくり・公共交通推進特別委員会のほうで、４月に報告予定となっています。","id":"exchange-052"},{"speaker":"ゆきた委員","kind":"質問","question":"令和７年度末には整備方針が策定され公表されることになれば、さらに区として関与の在り方が大きな意味を持つものになると認識しています。そこで、方針決定後を見据えて、区としてどのように検討やスケジュールを想定しているかお聞きしたいと思います。","respondent":"高梨都市計画課長","answer":"本整備方針が、正式な整備方針として公表された際には、令和２２年度までに工事着手を目標とする路線というふうに位置づけられます。この計画の中、計画期間内にどういった動きができるかといったところを計画策定の中でしっかりと考えてまいりたいと考えています。","id":"exchange-053"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"私も直接、大井町駅周辺のまちづくりについての要望は受けているところですが、区民の声の収集といったところでは、８月の委員会のときにも触れさせていただきましたが、より一層多くの意見、声を集約して、さらに進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-054"},{"speaker":"安藤委員","kind":"質問・要望","question":"補助２９号線に接続する未着手の補助３１号線、こちらについては、本当にこれは廃止すべきだと思っています。この計画が１５年の年間になったと、補助３１号線も廃止をということで、東京都に対して協議をしていただきたいと要望します。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-055"},{"speaker":"せお副委員長","kind":"質問・要望","question":"すみません、１点だけお伺いしたいです。学校の周辺に一切道路がない、車が通れないようにした町もあるみたいなお話を伺って、すごいなと思ったのです。","respondent":"高梨都市計画課長","answer":"委員がおっしゃられたとおり、道路に対しては、安全性の確保は最優先に取り組むべき課題であると認識しています。ふだんの区道の維持管理等も含めて、道路の安全確保については、しっかりと取り組んでいきたいと区としては考えてあります。","id":"exchange-056"},{"speaker":"せお副委員長","kind":"質問・要望","question":"ゾーン３０とか、本当に東京の道路は狭いなと思っているで、ぜひそこも一歩踏み込んでほしいと求めました。一歩踏み込んだ子どもたちのための道路空間の形成は、これからも引き続き取り組んでいただきたいと要望して終わります。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-057"}]},{"id":"topic-04","title":"令和８年２月都営住宅入居者募集","agenda":"令和８年２月都営住宅入居者募集","exchanges":[{"speaker":"中塚委員","kind":"質問・要望","question":"今まで民間に住んでいる方が都営住宅に申し込んでいるわけですから、都営住宅の増設こそ必要だと思いますけれども、改めていかがでしょうか。こうした住宅施策は、いよいよ転換すべきだと思いますけれども、いかがか尋ねました。","respondent":"川原住宅課長","answer":"計画等に基づいて実施されるべきもの、都が考えていくべきものではありますが、住宅政策は今後検討していく必要があると考えています。もう１つ、都のマスタープラン、あとは区の全体のそういった住宅施策に係る計画に基づいて検討していきたいと考えています。","id":"exchange-058"},{"speaker":"中塚委員","kind":"質問","question":"これは率直に申込みが高いことを認めているのだから、都営住宅のニーズが高いということを認めることが、そんなに難しいことなのですか。改めて、都営住宅のニーズが高いことを認めるのか、なぜ認めないのか伺いたいと思います。","respondent":"川原住宅課長","answer":"この記載のとおりでございまして、区としては申込みの状況でしかご説明ができない立場ではあるのですけれども、引き続きこういった倍率を見ながら。特に、居住サポート住宅の家賃低廉化もしっかりと実施をして…","id":"exchange-059"},{"speaker":"中塚委員","kind":"質問","question":"都営住宅のニーズが高いことをなぜ認めないのかと質問しましたが、ニーズが高いと認めることはありませんでした。こうした森澤区長の住宅施策は根本から転換すべきだと述べて終わりたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-060"},{"speaker":"安藤委員","kind":"質問","question":"１点だけお伺いしたいのですが、区営住宅については、どのような位置づけになっているのかだけ教えてほしいと求めました。","respondent":"川原住宅課長","answer":"管理も含めてです。そういった適切な更新を図って、修繕等もしっかりと行って、住みよい住環境を提供してまいりたいというふうな思いです。","id":"exchange-061"},{"speaker":"安藤委員","kind":"質問・要望","question":"それはやはり今の維持管理というだけの政策は、私も見直しが必要だと思いますので、そちらを改めて求めたいと思います。区営住宅は増設が必要だと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-062"}]},{"id":"topic-05","title":"東海旅客鉄道（株）が公表した道路隆起の発生原因と対策","agenda":"東海旅客鉄道（株）が公表した道路隆起の発生原因と対策","exchanges":[{"speaker":"安藤委員","kind":"質問・要望","question":"区には、このことについて、ぜひ時間延長をＪＲ東海に求めていただきたいのです。それはいかがか、伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"今回の一斉説明型の説明会ですが、開催時間が１時間となっています。質疑の時間も設ける予定であるということ、一斉説明型終了後も、並行して行っておりますオープンハウス型の説明会も開催していますので。","id":"exchange-063"},{"speaker":"安藤委員","kind":"質問・要望","question":"その上で、少しこれ、時間が足りないのではないかということで、区の意思として求めていただきたいということはいかがかと。要請する上で、前提として、これ、短過ぎるという認識はないのか、そこを伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"１時間の開催が短いか長いか、時間の長さというとなかなか難しいところであるかと思うのです。一斉説明型の説明会だけでなく、受け切れなかった質問はそちらで対応するというところで聞いておりますし、ＪＲ東海が時間については。","id":"exchange-064"},{"speaker":"安藤委員","kind":"質問・要望","question":"１１月２０日に行った道路掘削工事があるのですが、結局何を目的にした掘削工事で、何が分かったとＪＲ東海から伺っているのか伺いたいと思います。このような結果でしたということを聞いているのか、何か見せてもらっているのか、そこら辺を伺います。","respondent":"大石まちづくり立体化担当課長","answer":"これまでもご説明してきたとおり、地盤の状況であったり、既に埋められております埋設物の状況を確認するために行ったと聞いているところです。空気の排出を適切な頻度で行い…","id":"exchange-065"},{"speaker":"安藤委員","kind":"質問・要望","question":"穴があったかどうか確認したぐらいで、いきなり結論がボーンと出ていて、これでなぜこういう結論に達したのかがさっぱり分からないと思うのです。区が原因と対策の丁寧な説明の実施を求めているわけですけれども、そういうふうになっていると考えていらっしゃるのか伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"掘削調査を行ったのは、そこの直下にあります埋設物の状況だとか、地盤面の状況を確認するという目的で実施されたと認識しています。はその状況を見て、しっかりと対応してまいりたいと考えているところです。","id":"exchange-066"},{"speaker":"安藤委員","kind":"質問・要望","question":"対策については、一定、ヒューマンエラーを起こさないような措置を要望したと。これでどの程度抑制できるのかは、分からないところなのですけれども、今回の対策についての区の評価をもう一度伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"トンネル部会の委員については、ＪＲ東海から学識経験者や地盤の専門家など、あくまで第三者の立場でご意見をいただいていると聞いているところです。対策が施工管理の強化ですので…","id":"exchange-067"},{"speaker":"安藤委員","kind":"質問・要望","question":"品川区内に入っているわけですから、国に開催を求めるということをやっていただきたいと思うのですけれども、いかがでしょうか。そこだけ確認させてください。","respondent":"大石まちづくり立体化担当課長","answer":"区といたしましては、ＪＲ東海の責任において、しっかりと説明と確実な履行を実施することが何よりも重要と考えているところです。２点目の説明会後に再開するのかですが、説明会実施後に、再開の準備を進めていくとは聞いているところです。","id":"exchange-068"},{"speaker":"安藤委員","kind":"質問・要望","question":"国に対してぜひ公聴会の開催を求めていただきたいと思うのです。いかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"国に開催を求めるというところもありますが、あくまで現時点ではＪＲ東海が、この件につきましては、国から認可を受けて実施している民間事業ですので、あくまでＪＲ東海の責任の下でしっかりと対応を行っていくことが重要と考えているところです。","id":"exchange-069"},{"speaker":"中塚委員","kind":"質問・要望","question":"これは区長名か何かで要望したのか、どういうものなのか、もう少し詳しく説明してほしいということが１つ目です。１時間が短いとも言えないというのは、本当に駄目だと思うのですけれども、いかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"あくまで東海がこちらの説明の時間と、並行して行うオープンハウス型説明会、あわせてしっかりと対応していくという報告を受けております。説明会以降も、事務所でしっかりと個別で対応するということで、丁寧に説明していくと聞いているところです。","id":"exchange-070"},{"speaker":"中塚委員","kind":"質問・要望","question":"生活の安全、それでも安全が担保されないと判断して担当者レベルで要望しているわけですから、要は足りないと思ったところを伺いたいと思います。それがなぜ人がミスっても二重、施工管理の強化だけでは駄目だと思った品川区なわけですから、そこをもう少しご説明ほしいと求めました。","respondent":"大石まちづくり立体化担当課長","answer":"ただ一方で、今回このような事象が起きている状況がありまして、このまま進めていっても、また同様な事象が起きる可能性は十分考えられます。それに対して、何かしらで分かるような予防保全型の管理ができれば一番いいのかなというところでこういったお話をさせていただいたとこ…","id":"exchange-071"},{"speaker":"中塚委員","kind":"質問・要望","question":"いずれにしても、区はそれ以上の説明を受けたり要望したりすることは当然やるべきだと思います。基準の中だったけれどもバランスが崩れたという言い方ですから、そこはＪＲ東海は品川区に何と説明しているのか、そこを伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"こちらの基準値につきましては、詳細な資料が今ないのでお答えできないのですけれども、ＪＲ東海からは聞いているところです。実際に作業されている方にも通知されて適切に施工管理が行えるよう、システム上でも担保していくと東海からは聞いているところです。","id":"exchange-072"},{"speaker":"中塚委員","kind":"質問・要望","question":"この点、ＪＲ東海が明らかにすべきだと思いますが、いかがでしょうか。合理的な判断でＪＲ東海に要望もできるし、言わば今回の事故を繰り返さないための最後の砦となるシステムなわけですから、いかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"空気を減らすために気泡材の調整をするといった対応は実施していたところですが、対応が完全ではなく。で、先ほど言ったとおり、そちらの傾向があらわれたら発報されるようなシステムになるものと考えているところです。","id":"exchange-073"},{"speaker":"中塚委員","kind":"質問・要望","question":"なので、追加の資料や追加の説明も含めて、新たな原因と対策のＪＲ東海の公表を区はＪＲ東海に求めるべきだと思いますが、いかがでしょうか。いかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"区といたしましては、ＪＲ東海により今回示された対策が、まずもって責任を持ってしっかりと実施されることが重要と考えております。引き続き、ＪＲ東海に対しましては、安全管理の徹底を求めてまいりたいと考えているところです。","id":"exchange-074"},{"speaker":"中塚委員","kind":"質問・要望","question":"このような事態が起きているわけですから、要望すべきだと思いますが、いかがでしょうか。なぜないのかという話はさておき、国が設置した調査委員会を改めて区は求めるべきだと思いますが、最後にいかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"２点目の事故調査委員会のほうですが、こちらはＪＲ東海は第三者によりますトンネル施工検討委員会のシールドトンネル部会を設置しています。２月上旬に行われます説明会につきましても、区民に対してしっかりと説明して…","id":"exchange-075"}]},{"id":"topic-06","title":"「中小企業向け『ＡＩ電気相談所』設立による再エネ導入・脱炭素経営促進プロジェクト」実証実験","agenda":"「中小企業向け『ＡＩ電気相談所』設立による再エネ導入・脱炭素経営促進プロジェクト」実証実験","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"今度、事業者による説明会をやるという話も最後にありましたけれども、このツールの存在をどういうふうに知らせていくのでしょうか。このツールについて、利用料などは発生するのかも伺います。","respondent":"中西環境課長","answer":"説明会に関しましては、ＳＯＭＰＯホールディングス株式会社のほうからも周知をしてもらっているような状況です。省エネコンサル等に関しては有料の部分があると聞いているところです。","id":"exchange-076"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"中小企業センターと、あと、品川産業支援交流施設ＳＨＩＰに端末を設置する。診断結果について事業所がより詳しい説明とかアドバイス、助言を求めたい場合は、どこの所管に問い合わせることになるのかをお聞きしたいと思います。","respondent":"中西環境課長","answer":"設置に当たりましては、地域産業振興課とも連携をしながら進めているところです。そこは直接連携しているというよりは、事業者のほうで行っていただくような形になろうかというふうに考えてあります。","id":"exchange-077"},{"speaker":"ゆきた委員","kind":"質問","question":"連携しながら、地域産業振興課のほうで対応ということですね。このことに付け加えて、先ほど、対面での診断もお話があったと思うのですけれども、これは伴走型支援ということで認識してもよろしいのか尋ねました。","respondent":"中西環境課長","answer":"この株式会社タンソーマンＧＸがやっております省エネの診断、それからご相談が、３０分単位で予約ができるものになってあります。ホームページ等を見ますと「伴走支援」というような表現をうたってありますので、並走しながら、伴走しながら支援をしてもらえると認識しています。","id":"exchange-078"},{"speaker":"ゆきた委員","kind":"確認","question":"確認できました。ＡＩの無料相談ができることも私も確認しましたが、今後の実証実験を踏まえながら、検討の方向性についてお考えがあればお聞きできればと思います。","respondent":"中西環境課長","answer":"実際、この事業者とも、家庭向けにそういった診断のツールが使えないかと話はしています。そういった形で広げていくといったところを今進めているところですので、家庭向けにできないかといったような相談をしてまいりたいと考えています。","id":"exchange-079"}]},{"id":"topic-07","title":"マイガーデン豊町","agenda":"マイガーデン豊町","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"いいことだなと思うのですけれども、これ、土地を取得したのがいつぐらいで、工事はいつからやっていたのかということと、それと、品川区としては、マイガーデンというのを、今後増やしていく考えを持っているのか伺いたいと思います。","respondent":"大友公園課長","answer":"続いて、工事につきましては、令和７年１１月２１日から実施しています。土地の確保等と適地等々があれば、引き続き、拡大を考えているところです。","id":"exchange-080"},{"speaker":"安藤委員","kind":"提案","question":"補助２９号線など住民も反対する特定整備路線を廃止をして、福祉施設や公園などを整備する緑と福祉のまちづくりを提案させていただいています。早く都に意見を出して廃止して、そして、区民のためになるような使い方をしていっていただきたいなと改めて意見を述べさせてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-081"},{"speaker":"ゆきた委員","kind":"確認","question":"南大井と西五反田の周辺で選ばれた区画では、過去に途中で利用されなくなるような放置される区画が発生したことがあったのか、確認でお聞きできればと思います。","respondent":"大友公園課長","answer":"マイガーデン南大井・西五反田につきましては、好評で、基本的には１年丸々使っていただいているところではありますけれども、途中で荒れ地となるではないですけれども、利用を取りやめるような方は、いらっしゃったことはあります。","id":"exchange-082"},{"speaker":"ゆきた委員","kind":"確認","question":"仮に途中で利用されない区画が生じた場合には、どのように考えていくのか、こちらについても確認でお聞きほしいと求めました。","respondent":"大友公園課長","answer":"利用状況の確認をとりまして、まだ今後継続利用するのかどうなのかというところ、また、積極的に利用してもらいたいという声かけをして利用を促進しています。","id":"exchange-083"},{"speaker":"せお副委員長","kind":"質問・要望","question":"スケジュールは同じということなのですけれども、利用者募集の対象者が、この豊町と一緒なのかというところを確認させてほしいと求めました。だから、屋上と地上につくるものでどう違ってくるのかなということについて、何か違いがあれば教えていただきたいなと思います。","respondent":"大友公園課長","answer":"議会で施設関係のほうでお答えさせていただいたところでありまして、屋上は大体機器が載っているところがあり、なかなか整備が難しいです。こちらについては幅広く適用については検討してまいりたいと考えているところです。","id":"exchange-084"},{"speaker":"せお副委員長","kind":"質問・要望","question":"この福祉または教育を目的として活動するという、こういうものもいいなと思っているので、ぜひお勧めしていただきたいなと思います。様々区全体の、例えば、公有地活用とか、そういったところを考えながら進めていってほしいなと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-085"}]},{"id":"topic-08","title":"橋梁長寿命化修繕計画の改定","agenda":"橋梁長寿命化修繕計画の改定","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"予防は大事だなと思います。この対象橋梁はどのように選定していくのかを伺いたいのと、あと、なぜ年間一から二橋程度になるのかを理由なども説明を求めました。","respondent":"森道路課長","answer":"５年間といったような短期で、二橋ずつ進めていけば、ある程度の補修は可能であると判断したところです。まだ５年後に法定点検がありますので、早期にまた計画を立て直して、実際に補修工事を行っていくというようなサイクルで進めていくところです。","id":"exchange-086"},{"speaker":"安藤委員","kind":"質問","question":"では、実際に点検をしながら、この５年間の計画の中で、１年目はここ、２年目はここ、３年目はここ、４年目はここ、５年目はここというふうに具体的にもう決めているというような理解でよろしいのか伺いたいと思います。","respondent":"森道路課長","answer":"大まかな目安として、この橋梁、この橋梁ということは決めております。もう少し、２か年にしようとかというような検討が出てくるかと思いますので、臨機応変に対応しながらやっていければなと思います。","id":"exchange-087"},{"speaker":"ゆきた委員","kind":"確認","question":"夏季の熱中症対策、気象条件の影響とかで、実際の作業が可能な時間は年々短くなっている状況だと思われます。ここについて、１点、確認できればと思います。","respondent":"森道路課長","answer":"４月に協定を始めて３月まで実施するというようなものではなくて、年間の作業スケジュールを平準化していくというようなご提案があったところです。あまりに年間の工事が多くなったり、３月末に終わらせないといけない工事が多くなれば、できるだけフレキシブルに対応していく。","id":"exchange-088"},{"speaker":"ゆきた委員","kind":"質問","question":"今後さらにこういった課題は、かなり拡大していくと考えられます。こうした状況を踏まえて、債務負担行為を含めて、今後どの程度そういった対応が必要なものがあるか、想定しているのか、お聞きできればと思います。","respondent":"森道路課長","answer":"１月、２月、３月の稼働率が非常に高くなってしまうと。年間２０本あれば、今少し進めているところもありますので、そういった視点はしっかりと大切にしながらやっていければなと思います。","id":"exchange-089"}]},{"id":"topic-09","title":"立会川幹線雨水放流管事業（東京都下水道局施工）","agenda":"立会川幹線雨水放流管事業（東京都下水道局施工）","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"１つは、この貯留管の倍増措置で、どの程度、１時間当たり何ミリ程度の雨量に備えられることになるのかということを改めて伺いたい。これはなかなか難しそうなのですけれども、区としては、どのような対策をとる考えなのか伺いたいと思います。","respondent":"関根河川下水道課長","answer":"９月１１日の豪雨等と同等の雨が降った際にも、ためられる雨水の量が倍になるということですので、かなり能力は上がるのかなと認識しています。に、２月に実施される東京都主催の説明会においても。","id":"exchange-090"},{"speaker":"安藤委員","kind":"質問","question":"ぜひよろしくお願いします。そうしたら、この暫定貯留管は貯留しなくなるということになるのか、そこだけお伺いします。","respondent":"関根河川下水道課長","answer":"流下ということで、一時的にためるだけではなく、流せる下水道管となる予定です。具体的には、資料の図の右上の勝島ポンプ所まで流していきまして、ここでポンプで汲み上げて運河のほうへ雨水を吐き出すという計画になってあります。","id":"exchange-091"}]},{"id":"topic-10","title":"令和７年度地区総合防災訓練等の実施結果","agenda":"令和７年度地区総合防災訓練等の実施結果","exchanges":[{"speaker":"中塚委員","kind":"質問・要望","question":"区内一斉防災訓練、４６避難所、合計１万４６１名のうち、障害がある方は何人か伺いたいと思います。参加しにくいハードルをぜひ取り除いてほしいと求めましたが、いかがか尋ねました。","respondent":"星災害対策担当課長","answer":"今後どうやってとるかというところを考えていきたいとは思っているところです。関係７団体のお集まりのところで、私が行って参加の説明とお願いをしているところなのですけれども、鋭意考えていきたいというところはあります。","id":"exchange-092"},{"speaker":"中塚委員","kind":"質問・要望","question":"障壁ですから、下げることを目指すと同時に、取り除く方向に方針をとってほしいと求めましたが、いかがでしょうか。ご要望も変わってくるでしょうから、きめ細かい要望が把握できるように、いかがか尋ねました。","respondent":"星災害対策担当課長","answer":"３つ質問をいただいたかと思いますので、１つずつお答えをさせていただきたいと思います。避難訓練も継続しているというところもありますので、町会の方たちともお話をして、障害者の数字をとっていければと考えているところです。","id":"exchange-093"}]},{"id":"topic-11","title":"「しながわ防災区民憲章（素案）」に係るパブリックコメントの実施","agenda":"「しながわ防災区民憲章（素案）」に係るパブリックコメントの実施","exchanges":[{"speaker":"中塚委員","kind":"質問・要望","question":"今回、改めてこれが示されましたので、３点まとめて伺いたいと思います。２番目ですけれども、共助を求めるという立場なのか、ご説明ください。","respondent":"羽鳥防災課長","answer":"そういった意味合いで、やはり自助、共助が重要であるという認識を持っていただきたい。区長も東日本大震災の被災地である宮古に訪れ、その重要性をまた再認識したというような状況です。","id":"exchange-094"},{"speaker":"中塚委員","kind":"質問・要望","question":"つまり、対象者を限定していないということは、みんなという意味で、高齢者、障害者、低所得者が含まれるという認識でよいのか伺います。それにならって、こうした自助、共助の強調という素案はやめるべきだと、改めるべきだと思いますが、いかがか尋ねました。","respondent":"羽鳥防災課長","answer":"事前防災についても、区といたしまして、しっかり取り組んでまいりたいと考えています。行政として支援ができるところ、それが「品川区災害対策基本条例」の理念、ご理解いただければと思います。","id":"exchange-095"},{"speaker":"中塚委員","kind":"質問","question":"手話を日常会話として、言語として利用する障害者に、備える、あいさつする、伝える、行動する、自分たちでやれと言うのですか。生きづらいから条例までつくって、手話言語条例をつくって、自治体が社会の理解を広げていく柱を立てたのではないか尋ねました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-096"},{"speaker":"ゆきた委員","kind":"確認","question":"広報しながわで、防災区民憲章に向けての有識者の話合いが行われたことを確認しました。その辺の経緯、有識者のアドバイスが素案に具体的にどう反映されたのか、生かされたのかをお聞きしたいと思います。","respondent":"羽鳥防災課長","answer":"そういったところの考え方も取り入れているところです。幅広い方から、なるべく多くの意見を集めようとしたところが、有識者の方のご意見を参考にさせていただいた部分です。","id":"exchange-097"},{"speaker":"ゆきた委員","kind":"確認","question":"有識者の意見の中で、私も広報しながわで見せてもらった中では、中身よりもつくり方が重要だと思っているということを確認しました。経緯や過程について、どう価値をつけていくかというところで、どのようにお考えかお聞きできればと思います。","respondent":"羽鳥防災課長","answer":"１,０００件まではいかなかったですけれど、なるべく多くの方、それもいろいろな、多様な方からご意見をいただいたところです。今後、パブリックコメントでもご意見をいただいて、区民の方がつくる防災区民憲章になるように取り組んでまいりたいと思います。","id":"exchange-098"},{"speaker":"ゆきた委員","kind":"質問","question":"３月の品川区防災会議までに、言葉から行動変容に変えていく力強さの意見を聞くということも持っていいのではないかと思います。この辺についても、最後に何かお聞きできればと思います。","respondent":"羽鳥防災課長","answer":"より多くの方のご意見をです。機会を捉えて、そのほか、ご意見を伺えるように取り組んでまいりたいと思います。","id":"exchange-099"},{"speaker":"安藤委員","kind":"質問・要望","question":"今言ったような意見について、何か区としてご意見があれば、反論する点などがあれば伺いたいです。なぜ憲章になると、これ、そこら辺についての整合性について説明をほしいと求めました。","respondent":"羽鳥防災課長","answer":"重要である、一方で、実際に備蓄しているかという質問への回答は６５％という状況が示されております。最後の部分で、様々な主体が協力して災害に立ち向かうというところは表現したいと考えていたところです。","id":"exchange-100"},{"speaker":"安藤委員","kind":"質問・要望","question":"初めて意見が出るものですから、そういった意味で大事だな、私たちもやってほしいと言ってきたわけです。伺いたいのですが、このパブリックコメント説明会の目的については、これは今回どこに置いているのか伺いたいと思います。","respondent":"羽鳥防災課長","answer":"２月６日に予定しているワークショップ形式でのパブリックコメントの説明会ですけれど、委員おっしゃるとおり。パブリックコメントの説明も含めてですけれど、今後のしながわ防災区民憲章の活用についても、様々ご意見を頂戴できればとは考えてあります。","id":"exchange-101"},{"speaker":"中塚委員","kind":"質問","question":"まとめて質問したいと思います。今のやり取りを聞いていても、私は腹立たしく思うのです。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-102"},{"speaker":"中塚委員","kind":"意見","question":"障害がある方が、情報弱者と言われているわけだから、何がどう必要かを区別に沿って伝えてあげなければ伝わらないわけです。もう時間なので、意見だけ述べておきますけれども、このように腹立たしい憲章はないと、私はそう思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-103"}]},{"id":"topic-12","title":"行政視察報告書","agenda":"行政視察報告書","exchanges":[{"speaker":"安藤委員","kind":"質問・要望","question":"この報告書、大変いい内容だと思いますので、区議会ホームページの公開についても、ぜひ求めていただきたいと要望したいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-104"}]},{"id":"topic-13","title":"その他","agenda":"その他","exchanges":[{"speaker":"中塚委員","kind":"質問","question":"伺っているのですけれども、こういうときは１０時から始めるということも合理的な判断の１つなのかと思いますので、念頭に置いておいていただけたらと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-105"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/680934?Template=document&Id=7293#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=8&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":95686,"voices":294}},{"id":"r08-20260119-9","meetingId":"r08-m01","date":"2026年1月19日","dateIso":"2026-01-19","committee":"文教委員会","time":"午後 １時００分～午後 ４時２６分","status":"正式会議録","sourceType":"formal","overview":"文教委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を51件整理しています。","topics":[{"id":"topic-01","title":"令和７年陳情第５９号、ＰＴＡ役員不足解消のための別居親参画マッチング制度の導入に関する陳情","agenda":"令和７年陳情第５９号、ＰＴＡ役員不足解消のための別居親参画マッチング制度の導入に関する陳情","exchanges":[{"speaker":"のだて委員","kind":"確認","question":"ご説明いただいた中で、別居している親がＰＴＡに入れない障壁はないというお話でした。それを確認するのと、公教育の質の向上に資する施策であると書かれているのですが、区の受け止めを伺います。","respondent":"舩木庶務課長","answer":"２点目です。ご支援いただいていますけれども、お考え、ご判断いただく性質のものとして受け止めております。","id":"exchange-001"},{"speaker":"のだて委員","kind":"意見","question":"今、ご説明を聞いた、ＰＴＡが任意団体であり、区が介入すべきではないというスタンスが貫かれていると感じました。それぞれの自覚に基づいて参加をしていくと、ＰＴＡ活動はそもそもそういうものだと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-002"},{"speaker":"のだて委員","kind":"意見","question":"本日結論を出すということで、不採択です。先ほどの説明でも、ＰＴＡのメンバーについて教育委員会が介入すべきではないと考えますので、不採択ですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-003"},{"speaker":"高橋（し）委員","kind":"意見","question":"もう１つは、教育委員会がどうとか学校がどうとかよりも、不採択であります。この別居親云々ではなくて、ＰＴＡ活動全体にということですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-004"},{"speaker":"横山委員","kind":"質問","question":"先ほどの説明にありましたが、困難であると考えます。引き続き、ＰＴＡや保護者の方々のお声を伺いながら、教育委員会としてＰＴＡ活動への支援を。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-005"}]},{"id":"topic-02","title":"令和８年度新入学学校選択の抽選結果","agenda":"令和８年度新入学学校選択の抽選結果","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"６１７名になっていますけれども、これはどういう動きなのか、区がどう考えているのかを伺います。中学校は、希望者数は減って、４９５名という中で、抽選校は９校から１３校に増えているので、特に、これをどう見ているのか伺います。","respondent":"石井学務課長","answer":"恐らくですけれども、令和８年度から３５人学級が中学校でも開催される影響もありまして、抽選校が増えたと分析をしております。理由の多くは、あと、同じ幼稚園に通っていたとか同じ保育園に通っていたお友達と一緒の学校に通いたいというような理由があることも聞いております。","id":"exchange-006"},{"speaker":"のだて委員","kind":"質問","question":"悪いと思っているのか、今後、影響してくるようなことなどがあるのかどうか伺います。その状況を区としてはどのように認識しているのか伺います。","respondent":"石井学務課長","answer":"あくまでも学校選択制は、その中でさらに各校の学校運営における工夫を促していくものと認識をしております。それは大切なことであると考えていますけれども、一方で、それは１つ学校運営にとっては刺激になると考えています。","id":"exchange-007"},{"speaker":"のだて委員","kind":"質問","question":"そうした面があると思いますけれども、いかがでしょうか。学区変更とかにも影響が出てきているので、やはりこの学校選択制の見直しが必要だと思いますが、いかがか尋ねました。","respondent":"石井学務課長","answer":"もちろん窓口にいらっしゃる方につきましては丁寧にご説明をしますし、そういった部分でのケアも一定程度されているものと考えています。魅力ある学校づくりをしていく、その中の１つの材料に、こういった学校選択の結果があると考えております。","id":"exchange-008"},{"speaker":"のだて委員","kind":"質問","question":"公教育ですから、どこでも同様の、同じような一定水準の教育を受けられることが重要だと思います。そうした競争に結局はなっていくので、学校の格差が生まれることがないようにすべきだと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-009"},{"speaker":"まつざわ委員","kind":"質問","question":"制度がもう限界と質問でも言わせてもらっていますが、では何の選択なのだろうと、常に私も本当に感じています。それを優先するのはどうとかあるのですけれど、初めからこっちにすればその枠の中で入れるわけですから、そこら辺の考え方だけ説明を求めました。","respondent":"石井学務課長","answer":"委員ご指摘の、近年の学校選択において、兄弟枠であっても入れない現状、これについては、我々も１つの課題として認識をしています。そういった課題も含めた上で、今後の学校選択の在り方などについてもいろいろと考えていかなければならないとは思っております。","id":"exchange-010"},{"speaker":"高橋（し）委員","kind":"質問","question":"１つ質問するのですけれど、兄弟が２人待っていて全員待機があと１８ですが、減る要素の４３の戻りはない感じでやっているのですね。１６５で下は全員待機だけれど、もし動かなかったら、この待機の子たちは全く元に戻れない、抽選で、空きはどうすれば出るのか尋ねました。","respondent":"石井学務課長","answer":"浜川小学校につきましては、３ページの表にもありますとおり、いわゆる戻りの考慮はない状況です。ですので、この後、抽選の枠につきましては、例えばその中で、ほかの国立、私立に決まった場合ですとか、辞退が生じた場合に空きの枠が出てくるです。","id":"exchange-011"},{"speaker":"高橋（し）委員","kind":"質問","question":"では、学区内で１６５のお子さんたちが無抽選で、そのお子さんたちの中から今言った国立や私立に行った子が抜けた場合で、兄弟の方が入れるなどという理解でよろしいのか尋ねました。","respondent":"石井学務課長","answer":"委員のご認識で間違いございません。","id":"exchange-012"},{"speaker":"高橋（し）委員","kind":"質問","question":"まつざわ委員のお話があったと思いますけれど、刻々とお子さんの数も変わってきているし、さらに学校改築との関連も出てくると思うのです。今後どうしていくかは、今後そういうことも含めて検討していくべきだと思うのですが、いかがか尋ねました。","respondent":"石井学務課長","answer":"まだしばらく就学人口が一定程度出る中で、これまで一定程度その受入枠に余力があったからできた選択制度という部分もあると思います。そういったことも含めて、課題認識等を持ちながら進めていきたいと考えています。","id":"exchange-013"},{"speaker":"高橋（し）委員","kind":"確認","question":"どこをどう改築するかとか、ぜひその辺、再度確認させてください。いかがか尋ねました。","respondent":"石井学務課長","answer":"こういった制度を考えるときに、先ほど委員ご指摘のとおり、学校改築の状況などといったことを幅広に検討する必要があると思います。ですので、教育委員会事務局全体として、きちんと課題に向き合っていきたいと考えております。","id":"exchange-014"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"ここを改築したいという予算要望をされると思うのですけれど、学習する子たちがいい環境で勉強できるように、ぜひ改築の予算は頑張って要求してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-015"}]},{"id":"topic-03","title":"学校給食における有機農産物等活用推進事業","agenda":"学校給食における有機農産物等活用推進事業","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"ジャガイモとニンジンを１月から指定品目にしたので、その実施した状況も伺えればと思います。できるところからやっていたと思うのですが、ほかの食材、何校かでやっているものがあれば伺います。","respondent":"石井学務課長","answer":"やはりこの試行実施の中で多く出たものは、下処理にかかる時間が増えたです。ニンジンと取り組んできて、１０月とか１１月につきましては、結構旬の時期としてサツマイモなどが特別栽培で主に実施されていました。","id":"exchange-016"},{"speaker":"のだて委員","kind":"質問・要望","question":"どういうことを求めて、黒い部分をなくしていくなどはできるのですか、その辺の具体的なことが分からなかったので伺います。タマネギ、もやしは今後検討していくということで、タマネギは先ほど少しありましたけれども、現状の課題があれば伺いたいと思います。","respondent":"石井学務課長","answer":"残念ながら黒い部分を除けてくれというものはなかなか難しい部分があります。生産者は生産者で一定程度設備投資が必要になってくる部分がありますので、引き続き協議をしながら進めていきたいと考えています。","id":"exchange-017"},{"speaker":"まつざわ委員","kind":"意見","question":"少し似てしまうのですけれど、会派でもいろいろ八百屋であったり、栄養士であったりのお話をヒアリングしたときにいろいろな課題が出ました。やはり、物流が難しいとか、手間がかかる、それはもう、ある程度実験した中で解決したと言っていいのか、そこをまず、聞かせてくださいとの意見を述べました。","respondent":"石井学務課長","answer":"９月の試行実施のときに様々な野菜を試してみた上で、それにおける、発注して欠品がどれだけあったかということを集めました。１月からの本格実施に当たってはジャガイモとニンジン、足元の現実的に調達できるレベルで実施するという解決を図ったと認識しております。","id":"exchange-018"},{"speaker":"まつざわ委員","kind":"質問","question":"それともう１つ、例えばこういうのも、ある程度具体的な基準を設けたほうがいい。そこら辺の困難な基準をある程度明確に示したほうがいいと個人的には思ったのですけれど、どうなのか尋ねました。","respondent":"石井学務課長","answer":"確かに、１つ基準を設けるのは大事だと思いますけれども、現行の最低基準としては、もう明らかに入らない、蓋然性が高い場合と各校には伝えています。は各学校様々事情があると思いますので、そのときについては教育委員会にご相談いただきたいというような運用をしております。","id":"exchange-019"},{"speaker":"横山委員","kind":"確認","question":"もやしの課題はその袋の大きさについてとお聞きしたのですが、あと、タマネギについて個別の課題があれば教えてください。どういったラインだと、もしイメージがあれば共有したいと思うので、確認させてほしいと求めました。","respondent":"石井学務課長","answer":"予算として、実際にかかった費用と、あとは市場価格との差額を各校に配分することによって確実に実施できるような体制で給食費の支給を行っています。これは、急激な事務の変更は逆に負担が増してしまうので…","id":"exchange-020"},{"speaker":"高橋（し）委員","kind":"質問","question":"１つ目は、いわゆる給食の提供時間、給食を昼休みの前に提供できなかった例が何校かあったのでしょうか。理由も含めて始まったと伺っているのですけれど、児童や生徒が給食を食べてどういう反応があったのか、現時点でお感じになっているのかです。","respondent":"石井学務課長","answer":"９月からの実施に当たっては、実際に有機野菜の購入にかかった費用と、あと慣行品の市場価格の差額分を各学校に払う方式を取っております。これまでも、ＳＤＧｓ未来都市宣言に採択された品川区として…","id":"exchange-021"},{"speaker":"高橋（し）委員","kind":"確認","question":"でも今、課長の説明は、差額内で全て収まっているからほかに影響がないというご答弁なのですけれど、そこは確認させてください。いいことをやっている説明を学校から、教育委員会から学校を通じてということになるのでしょうか、その点について伺います。","respondent":"石井学務課長","answer":"はもう１つ、この有機野菜、いろいろ現場の方々、あとは教育委員会事務局の職員も含めて、これまで導入努力をしてきています。それだけの努力をした上で導入している事業ですので、それの予算についても引き続きご理解いただけるように努力していきたいと考えています。","id":"exchange-022"},{"speaker":"高橋（し）委員","kind":"確認","question":"などという声が、ということは、それは間違った認識なわけですね。今、献立に全く影響は出ないように、教育委員会で経費についてはしっかりとやっていただけているということを最後にもう一回確認させてください。","respondent":"石井学務課長","answer":"有機野菜を導入したことによって、１食当たりの価格が上がって、その中でメニューが出なくなったということはないと思っています。で、その中で様々現場が苦労してメニューを考えてくださっている、今回の有機野菜の導入とは関係なく生じていることであると考えております。","id":"exchange-023"}]},{"id":"topic-04","title":"区立学校におけるいじめの重大事態の発生状況","agenda":"区立学校におけるいじめの重大事態の発生状況","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"昨年度が５件、一昨年度が１４件で、重大事態は累計で何件になっているかが今分かれば伺います。この間様々、事案、重大事態が発生しているわけですけれども、今調査中の件数は何件あって、この進捗状況はどうなっているのか伺いたいと思います。","respondent":"丸谷教育総合支援センター長","answer":"総計ですけれども、全部足し合わせますと３３件になります。すみません、今すぐに出てこないのですけれども、それぞれ公にしながら調査を進めている段階です。","id":"exchange-024"},{"speaker":"のだて委員","kind":"質問","question":"今年度１１事案ありますけれども、その調査状況を伺えればと思います。こうした、やはり再発防止をしていくことが必要だと思うのですけれども、それは報告書などをつくってどのように生かされているのかを伺います。","respondent":"丸谷教育総合支援センター長","answer":"いじめ防止に努めるということと、保護者の承諾を得ながら、区立学校で共有して再発防止に努めるための手続を今進めております。複数の学校で同じようなことで起こっているケースもありますので、今後その辺りもしっかりと注力していきたいという考えです。","id":"exchange-025"},{"speaker":"のだて委員","kind":"質問・要望","question":"実際、区としては、この重大事態、この間３３件、区内で起こっている中で、根本原因についてはどのように考えているのか伺います。その取組を行っていくためにも、その点ではどういう対策を行っているのか、または行っていこうと考えているのか伺いたいと思います。","respondent":"丸谷教育総合支援センター長","answer":"昨年度からは、デイケンですとか、いじめＤアンケートですとか、そういったものでＳＯＳを発信できる取組も進めております。引き続き、子どもたちへの学習や指導、それから教員への研修といった充実を図っていきたいと考えております。","id":"exchange-026"},{"speaker":"のだて委員","kind":"質問・要望","question":"学習や研修は進めていただきたいと思うのですけれども、いろいろ取組をやられてきたということで、その効果はどう感じているのか伺います。具体的にはどういう風土を変えていくべきだと考えていらっしゃるのか、問題となっている風土、そこを伺いたいと思います。","respondent":"丸谷教育総合支援センター長","answer":"前向き行動支援や発達指示的生徒指導、そういったところを重点的に今、管理職や生活指導主任を中心に訴え続けてあります。徐々に学校風土も昨年から取り組んでいて改善傾向で、結果は出てきておりますので、継続した取組を続けていきたいと考えております。","id":"exchange-027"},{"speaker":"のだて委員","kind":"質問・要望","question":"先生に相談できるということも、やはり教員の多忙化を解消していくことだと思いますので、そこについてもぜひ取り組んでほしいと求めました。様々ないじめの要因を１つずつなくしていくことが必要だと思いますので、その取組を進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-028"}]},{"id":"topic-05","title":"「品川区社会的養育推進計画（素案）」に係るパブリックコメントの実施","agenda":"「品川区社会的養育推進計画（素案）」に係るパブリックコメントの実施","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"実際に子どもたちや施設の人たちから話を聞いたということで、子どもへのアンケート、あと、里親、児童養護施設職員へのヒアリングを行ったと、あと、児童福祉審議会でもいろいろ議論がされたと思うのですけれども、どんな意見が出たのか伺います。","respondent":"柴田子ども施策連携担当課長","answer":"それから児童養護施設の職員に、子どもにはアンケート、それ以外にはヒアリングという形で実施をしております。里親、家庭的養育優先ということで、区の取組についてもご意見をいただいたようなところです。","id":"exchange-029"},{"speaker":"のだて委員","kind":"質問・要望","question":"子どもの権利ノートを配付していろいろ周知啓発をしているということなのですけれども、このノートがどういうものなのか伺いたいと思います。大体３年とか５年という感じだと思うのですけれど、理由があれば伺いたいと思います。","respondent":"柴田子ども施策連携担当課長","answer":"区主催でボウリング大会を実施して、皆さんの意識、つながりを高めていきたいと考えております。それとほかの自治体が５年間で終わりの年度を合わせるというところで、今回は１年短く４年間としている、それが理由です。","id":"exchange-030"},{"speaker":"のだて委員","kind":"質問・要望","question":"先に、この４年間の計画で、終わりを合わせるとどういうメリットがあるのでしょうか。ぜひやっていただきたいと思うのですが、この里親の登録状況は、他区との例はどうなのか尋ねました。","respondent":"柴田子ども施策連携担当課長","answer":"同じものは難しいと思うのですけれど、権利ということを知っていただく機会は必要と考えています。品川区児童相談所を開設してから、４家庭の新規の里親登録をありがたくいただいておりますので、そういったところを今後も力を入れていく考えです。","id":"exchange-031"},{"speaker":"のだて委員","kind":"質問・要望","question":"実際の声を聞いているので、それもしっかりと反映させながら、取組を充実させて進めてほしいと求めました。子どもの権利ノートは、では一般的なバージョンに修正をして、ほかの子どもたちにもぜひ配布するような形でやってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-032"},{"speaker":"横山委員","kind":"質問・要望","question":"こちらの少し確認ですが、令和６年度の６名の数字の内訳は、区の児童相談所の部分ということでよろしいのですか。本編２１ページの３番と４番、子どもたちにいいようにしてほしいと求めましたので、こちら要望という形にさせてほしいと求めました。","respondent":"柴田子ども施策連携担当課長","answer":"児童相談所も、今回この計画をパブリックコメントに上げる前に見ていただいているのですけれども、共通認識であると受け止めております。それから、計画の２１ページのところでご要望ですけれども、しっかりと私たちも考えて、今後、児童相談所の強化等をサポートしていく考えで…","id":"exchange-033"},{"speaker":"横山委員","kind":"質問・要望","question":"逆に子どもは気持ちを聞いてほしいのに、その話がどういったもので、もし分かれば教えてほしいと求めました。現在の状況が何か分かれば教えていただきたいですし、こういった計画にも反映してほしいと求めましたが、いかがか尋ねました。","respondent":"柴田子ども施策連携担当課長","answer":"子どもにとって、今後、アンケートを実施するに当たってはそういったところをしっかり押さえていけるように対応していきたいと考えております。それから最後に、１２月の児童福祉審議会、２回開催がございまして、里親部会それから本会、それぞれ実施をしております。","id":"exchange-034"},{"speaker":"横山委員","kind":"質問・要望","question":"最後、１２月の児童福祉審議会での意見で、区内の社会資源を最大限活用していただきたいとあります。その辺り、この中には、どういった形で取り組まれているのかを説明を求めました。","respondent":"柴田子ども施策連携担当課長","answer":"それぞれ幅を広げて、社会的養護の子どもたちのサポートをしていただいているところで、こちらは引き続き応援したいと考えています。ファミリーホームや自立援助ホームがありますが、そちらは需要をしっかりと見据えて、対応を今後していきたいという考えです。","id":"exchange-035"}]},{"id":"topic-06","title":"西大井広場公園内における認可保育園の運営期間延長","agenda":"西大井広場公園内における認可保育園の運営期間延長","exchanges":[{"speaker":"のだて委員","kind":"確認","question":"閉園になる場合は、来年度の募集から停止をすることになるのですか。報告されているということでいいのか確認と、増えると見込んでいるという話でしたけれども、見込みの状況を伺います。","respondent":"佐藤保育事業担当課長","answer":"未就学児の人口増の考え方ですが、今年度品川区こども計画を策定いたしまして、その際に最新の人口推計を基に保育の量の見込みを算出しています。その中におきまして、近隣の就学前人口と、近隣の保育園の定員などを鑑みて、人口増、保育園が必要であると判断したものです。","id":"exchange-036"},{"speaker":"まつざわ委員","kind":"意見","question":"トータル的に２０年というと、私の感覚だと、もはやこれは期間限定なのか。周りに何かそういったところを率先して造っていくとかを考えていく必要性があると思うのですけれど、まずそこを説明を求めました。","respondent":"佐藤保育事業担当課長","answer":"区といたしましては、近隣の保育需要を見ながら柔軟に対応していくように、その更新を行いながら実施していきたいと現在は考えてあります。一方で、保育の需要の状況によりますが、委員からお話いただきましたような新規の開設等々も含めて…","id":"exchange-037"},{"speaker":"まつざわ委員","kind":"質問","question":"それと、そもそもが１０年の計画です。１０年だったものが、２０年やると、建物の耐久性などがどうなっているのか説明を求めました。","respondent":"佐藤保育事業担当課長","answer":"建物についてですが、これは当時、法人において建設をされたものでございまして、当時も１０年の期間限定ではありますけれども、建物自体はしっかりとした鉄骨造で建てられてありますので、耐用年数等を鑑みましても特に安全性に問題はないと認識しております。","id":"exchange-038"}]},{"id":"topic-07","title":"所管事務調査","agenda":"所管事務調査","exchanges":[{"speaker":"のだて委員","kind":"確認","question":"４６校、この全校配置した状況ですとか、この現状の課題などがあれば伺いたいと思います。この拠点校３校を豊葉の杜学園と荏原第五中学校、鈴ケ森中学校にした理由があれば伺います。","respondent":"丸谷教育総合支援センター長","answer":"不登校対応の巡回教員の関わり方ですけれども、学校の支援体制について一緒に考えたりですとか、そういった取組を進めている状況です。拠点校を記載の３校にした理由ですけれども、エリア的なものですとか、そういったことを加味して３校に決定したものです。","id":"exchange-039"},{"speaker":"のだて委員","kind":"質問","question":"少し分からなかったのですが、マイスクールに通っているけれども３０日学校を欠席している場合があるのですか。一人一人の子どもとは関わるとかはしていかないのか、その辺この不登校対応巡回教員の方の仕事、役割はどういうことなのかを伺えればと思います。","respondent":"丸谷教育総合支援センター長","answer":"どうしても週に１回の支援になっていますので、学校が不登校対応をどのように進めているかの助言であったり、他校の取組の共有であったり。学校の相談に応じて、全然学校に来られない生徒への支援も、そういった学校の要望に応じて直接的な支援を行うこともありますけれども。","id":"exchange-040"},{"speaker":"のだて委員","kind":"質問・要望","question":"先ほどいじめのところでも伺ったのですけれども、今、不登校が増えている根本原因は、区としてどのように考えていらっしゃるのか伺います。上位３項目が書かれておりますけれども、この上位３項目が全部小・中学校ともに同じで、それぞれ理由が何なのか伺えればと思います。","respondent":"丸谷教育総合支援センター長","answer":"家庭内の理解であったり、必要に応じて関係機関と連携を取ったりですとか、そういった家庭支援も併せて進めていくべきと捉えております。そういった意味では、スクールソーシャルワーカーですとかの職種もおりますので、広く不登校児童生徒への支援を関わって進めてあります。","id":"exchange-041"},{"speaker":"のだて委員","kind":"質問・要望","question":"あるいは、そこを強めていただきたいと思うのですが、区のお考えを伺います。学年別に見ると、３年生、４年生、９年生が、一昨年度から昨年度が増えている状況になっていますけれども、区の認識を伺います。","respondent":"丸谷教育総合支援センター長","answer":"早期の支援も大切だと考えておりますので、我々教育総合支援センター内でも検討を進めております。特別支援教育の観点からもしっかりと連携しながら、また、学校に通えるような支援というのも検討していきたいと考えております。","id":"exchange-042"},{"speaker":"のだて委員","kind":"質問・要望","question":"それは何かもし分析があれば伺いたいと思います。子どもたちは勉強に行っているわけですから、ストレス、そうした負担を軽減していくこともやってほしいと求めました。","respondent":"丸谷教育総合支援センター長","answer":"障害あるなしに関わらず、我々はマイスクールが主催しているファミリークラブ品川という取組を年に一、二回実施しております。少しでもその不安の解消につながればという思いで行っておりますけれども、今後も引き続き継続していきたいと考えております。","id":"exchange-043"},{"speaker":"のだて委員","kind":"質問・要望","question":"最後に、いろいろやはり課題はありますけれども、一つ一つクリアをしていただいて、子どもたちが元気に成長していけるようにしてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-044"},{"speaker":"高橋（し）委員","kind":"質問","question":"会計年度職員なのでしょうか、１日４時間で週５日も来られないとすると２人で分けているとか、そういうやり方なのかということが１つ。どういった形で、ここまでやってきたので課題とか今後どうするか、校内別室指導支援員の方のスキルアップがあると思っています。","respondent":"丸谷教育総合支援センター長","answer":"フリースクールとの連携については、どのような支援を行っていくのか、協議会のようなものを年に数回でも設けられればと考えております。なかなか、１００％満足のいくような設備までは至っていないと思いますけれども、少しずつ環境整備も進めてあります。","id":"exchange-045"},{"speaker":"高橋（し）委員","kind":"確認","question":"少し確認は、お二人で時間を分けている学校とかもやはりあるのですか、そういう形で埋めている方があるのでしょうかというのが１つ。そこだけお願いします。","respondent":"丸谷教育総合支援センター長","answer":"学校が与えられた予算の枠の中でその校内別室指導支援員を配置しておりますので、場合によっては２人配置する曜日を設けたりですとか、そういった取組を行っております。","id":"exchange-046"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"例えば八潮以外のほかの３か所、こういったことに昼食支援はどんどん拡大してほしいので、教えてほしいと思います。不安とかうつが心理的に不安定な子どもの要因という中で、例えばこういうところに、本当に高度なスキルが求められている。","respondent":"丸谷教育総合支援センター長","answer":"運営をしていく中で、１日フルで行うような曜日ができる際には、こういった昼食の提供も検討していきたいと考えております。個別の支援をと、現時点ではそのように考えておりまして、必要なお子さんにはそうした専門家につなぐことも行ってあります。","id":"exchange-047"},{"speaker":"まつざわ委員","kind":"質問","question":"よく小１の壁、中１のギャップがありながらも、このグラフを見ると、令和６年度は令和５年度に比べて、不登校数がそこだけ減っています。それをいろいろ分析していくと、これからのカリキュラムがつくれると思っているのですけれど、そこら辺をどう思っているのか説明を求めました。","respondent":"丸谷教育総合支援センター長","answer":"まさに生活リズム不調については、学校だけではなかなか改善が難しいので家庭の理解や協力が不可欠であると考えております。家庭への直接的な支援は、福祉的なものもありますので、関係機関との連携を図って進めてあります。","id":"exchange-048"},{"speaker":"横山委員","kind":"質問","question":"東京都のバーチャルラーニングプラットフォーム事業への参加の１１０アカウントで、そのうち５８人の利用の実績があるという意味でいいでしょうか。品川オンラインスクールと国際交流事業の利用実績は、ここの５８人とは関連があるのかないのか、その辺り、もう一度教えていただけたらと思います。","respondent":"丸谷教育総合支援センター長","answer":"そのうち、現在５８アカウントの申込みがあって、品川区の児童生徒に区から付与している数になってあります。国際交流事業にも参加できる仕組みになっているのですけれども、日々のログイン数は五、六人がずっと続いている状況です。","id":"exchange-049"},{"speaker":"横山委員","kind":"確認","question":"こちらも確認ですけれども、利用実績５１件は、５１回ということではなくて５１名という理解でよろしいのでしょうか。今年は７月と１１月ですか、どういった形で、そういうブースがあったりプログラムがあったりするのかどうか確認させてください。","respondent":"丸谷教育総合支援センター長","answer":"２回目は、様々区で行っている不登校支援の取組について事務局から説明させていただいて、案内としては事業説明という形をしています。どこかに委託をするなどといったことまでは検討していませんけれども、今後の検討、参考にはしていきたいと考えております。","id":"exchange-050"},{"speaker":"横山委員","kind":"質問・要望","question":"様々な手法があり、様々ほかの自治体も取組があると思うのですけれども、品川区の不登校の状態になっているお子さんや保護者の方のニーズ、お声を聞いていただいて、今後の展開については、ぜひ反映させていただいて進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-051"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/631298?Template=document&Id=7291#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=9&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":52983,"voices":151}},{"id":"r08-20260119-5","meetingId":"r08-m01","date":"2026年1月19日","dateIso":"2026-01-19","committee":"総務委員会","time":"午後 １時００分～午後 ３時２９分","status":"正式会議録","sourceType":"formal","overview":"総務委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を40件整理しています。","topics":[{"id":"topic-01","title":"定額減税しきれないと見込まれる方への給付金（不足額給付）の事業実績","agenda":"定額減税しきれないと見込まれる方への給付金（不足額給付）の事業実績","exchanges":[{"speaker":"澤田委員","kind":"質問・要望","question":"未支給者の方が７.２％まだいらっしゃって、かなり僅かなのかなとは思うのですが、何か把握されていることがあれば教えてください。コールセンターには例えばどのような相談があったのかなどということも教えていただきたいということと、そこに向けて、それについては要望というか。","respondent":"宮澤税務課長","answer":"申請率につきましては先ほどご説明したとおりで、最終的に令和７年度は９２.８％までいったという状況です。支援が必要な方への対応ですけれども、そういった方々には職員のほうで説明の上、申請のほうにという形はさせていただいたところです。","id":"exchange-001"},{"speaker":"西本委員","kind":"質問","question":"事務経費についてですが、これは全額が国から来るという認識でよろしいでしょうか。それの補償というものが、国からどのような補償が来ていて、どのような負担になったのかということを説明を求めました。","respondent":"宮澤税務課長","answer":"給付金に係る給付金額、また事務経費の部分ですけれども、令和６年度の事務経費につきましては、およそ１億円強の事務経費がかかっております。令和７年度についてもほぼ１億円強の事務経費がかかっておりますので、国から全額入る、負担いただけるというものです。","id":"exchange-002"},{"speaker":"西本委員","kind":"質問","question":"かなり煩雑で、非常に分かりにくい制度だと思うのです。その負担という、負担感というものを踏まえて、それがどのような状況だったのか説明を求めました。","respondent":"宮澤税務課長","answer":"事務委託ということで８回線を設置し、それで令和７年度についてはトータルで２,１２４件のお問合せがあって、委託の範囲内で直接に対応ができると。令和７年度については、逆に品川区に対して問合せを来るものに対応していくという事務が非常に…","id":"exchange-003"},{"speaker":"西本委員","kind":"質問","question":"あまりにも煩雑な、それで今のような手間がかかっているということを考えると、どうなのかなというような思いは正直あります。ですから、あまりひどいときには抗議する予定であるのか、いかがか尋ねました。","respondent":"宮澤税務課長","answer":"給付金額や申請者、事務負担の度合いというものは、品川区に限らず全国の自治体が恐らく感じているとは思うところです。適切に事務を進めてきたところですので、特に国への何か報告という、そういったところでの報告の予定はないところです。","id":"exchange-004"},{"speaker":"石田（ち）委員","kind":"質問","question":"これだけの事務負担がかかってどうなっているのだという声も当時も出ていましたので、私はこれは国に言うべきだなと思うのです。きちんと国にこのような負担がないようにしてほしいというようなことは言ったほうがいいのではないかなと思うのですけれども、いかがか尋ねました。","respondent":"宮澤税務課長","answer":"それ以降に８月、９月、１０月と給付事務を進めていったところです。税務課、繁忙期というものが１月から６月という前半部分で、この定額給付金の事務を当たっているというところで対応してきているです。","id":"exchange-005"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"本当にご苦労さまだなと思うところですので、今課長のお話でも、大変なことでしたというようなものがあふれ出ている感じがしました。議会としても要望しながら、自治体の手間というのですか、そこを軽くするような対策というものを求めていきたいなとも思いますし。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-006"},{"speaker":"塚本副委員長","kind":"質問","question":"そのようなところがどうなるのかというところと、まだ先の話ではありますが、ご見解を伺いたいと思います。","respondent":"宮澤税務課長","answer":"ただ、今回実施したような形というよりは、何かそういった１つの税の控除の仕組みという形になるのだろうと考えていますが。申請をもらうことなく、そういったものが進めば、より事務は効率化できていけるのかなと思っているところです。","id":"exchange-007"}]},{"id":"topic-02","title":"広報媒体を活用した情報発信の強化","agenda":"広報媒体を活用した情報発信の強化","exchanges":[{"speaker":"石田（ち）委員","kind":"質問","question":"もう少しこうしたらどうなのだろうということの意見を言って、ホームページのリニューアルについてはあるのかどうか、伺いたいと思います。","respondent":"與那嶺戦略広報課長","answer":"やはりほかの自治体に比べて品川区は少し見づらいよねというところは、エピソードベースにはなってしまうのですけれども、いただいてきたところです。今リニューアルを様々進めていまして、あと…","id":"exchange-008"},{"speaker":"須貝委員","kind":"質問","question":"決算、つくっていってはいけないのではないか、より拡大していくべきだと私は思います。今、スマホの問題と広報しながわの問題について言わせていただいたのですが、区としての見解をちょっと説明を求めました。","respondent":"與那嶺戦略広報課長","answer":"そこからさらに品川区のページに飛んでいくというような使い方をしているものが、一般的なトレンドになっているかなということは認識しています。ご希望いただけた方には自宅への個別配送も実施しており、こちらの周知、ＰＲも続けていこうと考えています。","id":"exchange-009"},{"speaker":"須貝委員","kind":"質問・要望","question":"私はやはり広報紙の発行数ではなくて、できれば配布数を増やしていくということを片一方では進めていくべきだと思うのですが、どうでしょうか。できるだけ多くの事業を見ていただきたいということを考えると、私は逆に発行部数ではなくて、ご見解を説明を求めました。","respondent":"與那嶺戦略広報課長","answer":"やはり費用の部分で見合わないという形でその実施は見送って、新聞折り込みが中心になっているというところになってあります。それを検討していきたいなと思っていますし、あとは予算的なところも含めて、手法については検討していきたいと考えております。","id":"exchange-010"},{"speaker":"須貝委員","kind":"質問・要望","question":"区の情報を多くの区民の方に知らせていくという姿勢はやはりなくしてはいけないと思うので、何とか広報紙の発行部数ではなくて、より配布部数を増やす努力を私は今後も続けてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-011"},{"speaker":"西本委員","kind":"質問","question":"特集記事などの充実にしようというように方向転換した根拠を教えてほしいということと、それから１日号と１５日号の２回になるのですよね。この減らすという意味でいうと、経費削減という目的もあってこのような状況になっているのか、その辺はどうなのか尋ねました。","respondent":"與那嶺戦略広報課長","answer":"広報しながわの役割といいますか、多くの区民の方に見ていただけると、それは我々も十分に認識しておるところです。ただ、我々今回の目的としてはあくまで情報の出し方で、経費を落とそうと思って進めてきた話ではないというところでご理解いただければと思います。","id":"exchange-012"},{"speaker":"西本委員","kind":"質問","question":"結局それもデジタル化になったときそれが反映することになると思うので、そのようなものは改善は期待してよろしいのでしょうか。いかがか尋ねました。","respondent":"與那嶺戦略広報課長","answer":"ここは大変申し訳ないと考えています。そして更新のやり方も変わりますので、その際にきちんとイベントカレンダーも設けますし、ここは我々としても改善していきたいと思います。","id":"exchange-013"},{"speaker":"山本委員","kind":"質問・要望","question":"特に区民目線での情報発信をしてほしいということは昨年の私の一般質問でも要望してきたことですし、課題として区民の皆様にどう情報を届けるか。デジタル、私のご要望なども含めて受け止めていただいたのかなということで、ぜひ進めていってほしいとまず思っております。","respondent":"與那嶺戦略広報課長","answer":"まず庁内の中にそういった意識をつけていくであるとか、ホームページのつくり手側の部分のスキルアップというところも含めて実施していこうかなと。そういったやり方については、これからにはなると思うのですけれども、考えていければと思っています。","id":"exchange-014"},{"speaker":"石田（秀）委員長","kind":"質問","question":"それはよくなるというのならそれでいいけれども、なぜ発行回数を３回から２回にしたのですか。なぜそのようなことをしないのか尋ねました。","respondent":"與那嶺戦略広報課長","answer":"１０万部強というところの規模からすると、まだまだ一部だというところはそのとおりですし、我々は重く受け止めなければいけないと考えています。今日いただいたご指摘も踏まえて、個別配送の事業のＰＲなど、そういったところへも力を入れてまいりたいと思います。","id":"exchange-015"}]},{"id":"topic-03","title":"「ジェンダー平等と性の多様性を尊重し合う社会を実現するための計画」に対するパブリックコメントの結果","agenda":"「ジェンダー平等と性の多様性を尊重し合う社会を実現するための計画」に対するパブリックコメントの結果","exchanges":[{"speaker":"石田（ち）委員","kind":"提案","question":"区としてはこの数というものをどのように見ているのかということを伺いたいということと、要望だったり、提案だったりというものがあるのに対して。出していただきたいなと思うのですけれども、いかがでしょうかということですとの意見を述べました。","respondent":"木村人権・ジェンダー平等推進課長","answer":"５５人という人数から９６件という形で寄せられておりますが、こちらは多かったのではないかと考えています。５月の１日の結果公表時期に合わせてご回答すべく、それをした結果について、見解として述べする予定になっております。","id":"exchange-016"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"ですから本当に大事だな、やはりジェンダー講座というものは、改めてすごく大事なものだなというように感じました。ですから、ここへのさらなる周知というものはこの間も私たち求めているところですけれども、今の時点でぜひ伺いたいと思います。","respondent":"木村人権・ジェンダー平等推進課長","answer":"結構それで条例を初めて見たという方もいらっしゃいますので、引き続きそのような形で実施をさせていただければと考えています。周知の方法につきましては、来年度も引き続き、より見ていただけるような形で周知を行ってまいります。","id":"exchange-017"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"そういったところでも、やはり区の姿勢が、見えつつあるのかなというところもあると思うので、引き続きこうした姿勢で進めていただきたいなと。引き続きジェンダー平等、そして主流化を進める区として頑張っていただきたいなと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-018"},{"speaker":"西本委員","kind":"質問・要望","question":"何というのでしょうか、ジェンダー平等というものが当たり前になってくるという形で、本当はマイナスになっていかなければいけないと思うのです。特に意識の変容というものが求められていることだと思うので、どのように検証がされていくのかなというところを教えてほしいと求めました。","respondent":"木村人権・ジェンダー平等推進課長","answer":"まちで説明をしたときに、お互いに理解し合えるような状況をつくれるようにすることが私たちの仕事だと考えております。２つ目、まずいろいろな方の相談を受けられる状況をつくって、相談について周知をしていくというところが大事になってくると考えています。","id":"exchange-019"},{"speaker":"西本委員","kind":"質問","question":"その辺の進め方と、それから、これから検証したりしていく中で、いろいろな計画が入ってきているではないですか。なぜ唐突的に品川区はやっているのというような形になってしまうので、そこの説明の仕方などはいかがか尋ねました。","respondent":"木村人権・ジェンダー平等推進課長","answer":"全体の動きの中でどのように周知を進めていくかというところなのですけれども、ジェンダー平等を実現しようというような考え方を据えております。これから発行になりますが、そちらのほうをまた周知の際に使っていって…","id":"exchange-020"},{"speaker":"松本委員","kind":"確認","question":"確認なのですけれども、これ意見応募状況で応募者数５５人という方かと思うのですが、区内の方と区内ではない方というものはどのくらいいらっしゃったのかというところをお伺いできればと思います。","respondent":"木村人権・ジェンダー平等推進課長","answer":"こちらにつきましては、その内訳につきましては、特に統計を取っているものではございません。こちらのほうには性別等も書いていないのですけれども、そちらのほうについても伺っておりません。","id":"exchange-021"},{"speaker":"松本委員","kind":"質問・要望","question":"ですから、そこをきちんと想定して、でも品川区としてはこれが正しいと思っているから進めていく。そしてこれがなぜ大事かというと、審議していただきたいと思って、この辺りの考え方について伺えればと思います。","respondent":"木村人権・ジェンダー平等推進課長","answer":"何を考えてそのようなご意見なのかというところは考えながら対応していかなければいけないというように、職員と一緒に考えております。業者の方や先生、委員会の様々な有識者の方々とご相談しながら進めているところですので、対応については注意して進めていきたいと考えていま…","id":"exchange-022"},{"speaker":"松本委員","kind":"意見","question":"あれもやるべきなのか、やらないべきなのか、この部分はしっかりと有識者の方とご検討してほしいと求めました。先進的にやろうとすればやるほど大変な、課長が物すごくご心労大変なところだと思いますけれども、ぜひ頑張ってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-023"},{"speaker":"須貝委員","kind":"質問","question":"国や都に対して、都は実現するための計画はどの程度進んでいるのでしょうか、教えてください。私は何か、ちょっとそこで行き詰まってしまうのではないかと思うのですが、基本的なことで説明を求めました。","respondent":"木村人権・ジェンダー平等推進課長","answer":"第６次男女共同参画の計画について、まだ検討中というか、策定中というところになっております。同じ方向を向いて取組を進めていて、自治体としての区としての取組を私たちのほうでは計画に入れているというような考え方になっていると思います。","id":"exchange-024"},{"speaker":"須貝委員","kind":"質問","question":"その辺がちょっと心配しているのですが、それについては大丈夫なのですか。説明を求めました。","respondent":"木村人権・ジェンダー平等推進課長","answer":"まちの方々へのいろいろなところでの説明をする機会を持たせていただこうと考えていますので、地域の方たちのご意見を伺いながら、こちらとしてはこういった形でやっていきますというところのご説明をさせていただければと考えております。","id":"exchange-025"},{"speaker":"塚本副委員長","kind":"質問","question":"ジェンダー平等と性の多様性を尊重し合う社会を実現するための条例に基づいた計画ということで、ただ、１つ外国人に触れているところありますよね。計画に盛り込まれているというところの、区としての何か思いや意図というものが特にあるのであれば、お伺いしたいかなと思います。","respondent":"木村人権・ジェンダー平等推進課長","answer":"配偶者暴力、女性活躍推進、困難女性支援等の様々な内容も入っております。共に暮らしていく、同じ地域で暮らしていくというところで、共生社会については触れさせていただいているところになっております。","id":"exchange-026"}]},{"id":"topic-04","title":"所管事務調査","agenda":"所管事務調査","exchanges":[{"speaker":"西本委員","kind":"質問","question":"どのようなお話が、今の段階でいいので、予測も含めて変わっていくものなのでしょうか。これだけ収入が上がっているので、それとアリーナをつくるということで、アリーナなどの収益というものは全く関係なくなってしまうのか尋ねました。","respondent":"藤村総務課長","answer":"完全移転なのか、少し残していくのかというところも、恐らく今後の検討という形になるのかなと思います。大井競馬場のほう、そこがどういった動きを取るかということについても、今後また情報が入ればお伝えいたします。","id":"exchange-027"},{"speaker":"西本委員","kind":"質問","question":"大井競馬場のレースはあるよと思っていたらいいのか、それもちょっとあやふやな状況になっているのか。そこはどのように考えたらいいか尋ねました。","respondent":"藤村総務課長、石田（秀）委員長","answer":"当然何かしらレースをやるための場所を確保するということですので、大井競馬場のほうが特になくなるとか、そういった話は聞いておりません。 今これインバウンド対応で、例えば泊まっている方で午後の６時から８時が食事だとして、どこかで娯楽を探している方たくさんいる。… １号交付金につきましては、その売得金額の上昇に見合った対応を取っていただけるようにということで訴えはしていきたいと思います。… ぜひそれは、そのような場所があるということはプラスに考えて…","id":"exchange-028"},{"speaker":"石田（ち）委員","kind":"質問","question":"競艇、様々あるのですけれども、その辺の依存症者の数の把握というものはされているのでしょうか。絞られているかどうかということはあるか、分からないかもしれないのですけれども、その辺もしあれば伺いたいと思います。","respondent":"藤村総務課長","answer":"しっかりお客様に対しての対応というところでも、従業員に対しても研修を実施するということはありますので、そのギャンブル依存というところに対してはしっかり対応を取っているような形になっています。","id":"exchange-029"},{"speaker":"石田（ち）委員","kind":"質問","question":"可能性としては依存症になっていってしまう方が増えるという可能性につながっていってしまうので、その辺はどうなのかなとは私は思うところです。ですから、そのようなものはやっていくべきではないかなと思うのですが、その辺いかがか尋ねました。","respondent":"藤村総務課長","answer":"しっかりそちらのほう区としても把握して、そういったギャンブル依存症の方が増えないようにというところは、特別区競馬組合とも連携してしっかり周知していきたいと思います。","id":"exchange-030"}]},{"id":"topic-05","title":"行政視察報告書","agenda":"行政視察報告書","exchanges":[{"speaker":"須貝委員","kind":"質問","question":"それは品川区に至っては、その予算に対して執行するに当たって、何か影響が出るのですか。それからこの選挙、今日は選挙管理委員会事務局長がいないのですけれども、選挙は大丈夫なのですかということを、分かる範囲で、もし分かる人いたら。","respondent":"加島財政課長","answer":"大体例年のとおり補助金が１０分の１０入ってまいりますので、歳出、支出の内容をまとめているところです。こちらの補正予算案の扱いにつきましては、また後ほど各会派のほうにご説明させていただければと考えております。","id":"exchange-031"},{"speaker":"須貝委員","kind":"質問","question":"日にちがないではないですか。でも何とかできてしまうものなのか尋ねました。","respondent":"堀越副区長","answer":"状況を見ながら、情報を取りながら、一生懸命準備しているところです。決まった段階では速やかに執行できるように、準備を進めているです。","id":"exchange-032"},{"speaker":"西本委員","kind":"質問","question":"ほかの会派の方々は、多分２８日からなのですか。今回、区長のプレス発表はいつなのか尋ねました。","respondent":"藤村総務課長","answer":"今まだ明確に日程のほうは決定がしていないところですけれども、議案説明会の後ということで予定はしております。","id":"exchange-033"},{"speaker":"西本委員","kind":"意見","question":"基本はそうなのだけれども、リークしようが何しようが、ご勝手にどうぞということですねとの意見を述べました。","respondent":"石田（秀）委員長","answer":"会派ごとに説明、重点施策、新規事業を中心に説明、質疑もあります。「情報の取扱いについては、各議員が判断し、責任を持って対応」、これしか書いていない。","id":"exchange-034"},{"speaker":"西本委員","kind":"質問","question":"行為というか、行動というものが、ではマスコミにリークしても構わないのですねという話ではないですか。それこそマスコミの人たちの努力によって情報をつかんだわけだから、それを公開してもいいですよということなのか尋ねました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-035"},{"speaker":"西本委員","kind":"質問","question":"では議会のほうに報告をするまではリークはないという理解でいいのですか。ということか尋ねました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-036"},{"speaker":"西本委員","kind":"意見","question":"でも決まりは決まりだから、区としてどう考えているというわけではなくてとの意見を述べました。","respondent":"藤村総務課長","answer":"リーク云々という話というものはちょっとまた違うかなと思うのですけれども、原則論として、区としては議案説明会を１つの起点として考えているというところ、それ以後に外が情報に出ていくというところが、申し上げているところの全てです。","id":"exchange-037"},{"speaker":"西本委員","kind":"質問","question":"では今山本委員が言ったように、だから仮に、議案説明会が２月５日なわけではないですか。その前に外部に漏れたりなどしていたら、問題だということの認識でいいか尋ねました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-038"},{"speaker":"西本委員","kind":"質問","question":"ただ行政側からは、２月５日前には情報は出ませんよという理解ですか。もちろん情報が出たときに、前に出たら、では議員が何か誰かやったのねという理解でいいか尋ねました。","respondent":"藤村総務課長","answer":"原則、区としては、対外的に情報が流れるということは、議案説明会以後という形です。","id":"exchange-039"},{"speaker":"西本委員","kind":"確認","question":"契約している委託事業などというものを調べるのか、どのような方法で調べるのですか。ほかの区だから関係ないといって調べないのか、どうなるのか尋ねました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-040"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/237549?Template=document&Id=7299#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=5&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":47598,"voices":126}},{"id":"r08-20260120-21","meetingId":"r08-m01","date":"2026年1月20日","dateIso":"2026-01-20","committee":"子ども若者支援・共生社会推進特別委員会","time":"午後 １時００分～午後 ３時１０分","status":"正式会議録","sourceType":"formal","overview":"子ども若者支援・共生社会推進特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を10件整理しています。","topics":[{"id":"topic-01","title":"特定事件調査","agenda":"特定事件調査","exchanges":[{"speaker":"西村委員","kind":"質問","question":"若者ということで、先ほども申し上げたみたいに小学生から３９歳くらいまでの方々が同じ空間にいるというのは一体どういう状況なのかと思ったときに。マイスクールではできないことをすごくしていただいているという印象がありまして、お伺いできればと思います。","respondent":"柴田子ども施策連携担当課長","answer":"曜日で分けるということはしないで、若者の場所、それから小学生の場所、そういった形で区切りをつけているところが多くありました。しかしながら、その辺はまだ区としていろいろな形があるというところで、研究の段階であるかというふうに考えているところです。","id":"exchange-001"},{"speaker":"西村委員","kind":"質問","question":"お話を聞いていて課題だと思ったのは、生活自立訓練の事業所が１箇所しかないですとか、どのように区としてできるのか。二十代が通える精神のデイサービスがないというのもいろいろな自治体での課題なのかと思うのですが、この辺りを伺えたらお願いいたします。","respondent":"柴田子ども施策連携担当課長","answer":"先ほど、視察の説明の冒頭のところで精神科のドクターがいらっしゃったというお話が中塚代表からあったかと思うのですが。児童相談所、子ども家庭支援センター、今後はそのニーズをしっかりと把握して対応していく必要があるというふうに考えております。","id":"exchange-002"},{"speaker":"おぎの委員","kind":"質問","question":"自信を持って、次はそういった子たちがまた別の子たちの話を聞くお兄さんになってあげたりとか、助ける側に回ってあげる。最終的にはそういう場になったらいいと思うのですが、そういうのはいかがか尋ねました。","respondent":"柴田子ども施策連携担当課長","answer":"皆様に何人かスタッフの紹介が中塚代表からあったと思うのですが、実はその中に１人もともと利用者だった方が常勤職員として働いています。それは、そういった利用者から支援者といった流れというのは現状もできておりますので…","id":"exchange-003"},{"speaker":"おぎの委員","kind":"質問・要望","question":"２件目をつくるときにもぜひまた地元の町会の方ともご協力いただきながら進めていってほしいと求めました。これは要望で終わります。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-004"},{"speaker":"鈴木委員","kind":"質問・要望","question":"その辺の連携というのは、どういう状況になっているのかということを伺いたいと思います。それから、このことに対しての区の考え方についても伺いたいと思います。","respondent":"柴田子ども施策連携担当課長","answer":"このそれぞれの団体にはつながっているネットワークがそれぞれにありますので、そこを含めると５０団体は下らないかという認識でおります。それから、そういったところとの整理も必要かというふうに思っておりますので…","id":"exchange-005"},{"speaker":"つる委員","kind":"確認","question":"何年かぶりに状況を確認させていただいて、そのときよりも少しいろいろと充実しているのかということを感じました。鈴木委員のほうからもあって、区が月１の運営委員会とか、どういう形なのかと今伺ったとおりです。","respondent":"柴田子ども施策連携担当課長","answer":"フリースペースを法人に見ていただく機会というのは、定例で設けているということはございません。そういった方々がまずつながっていて、積極的に企業に来てもらって様子を見てつながるということは、現状はできていないというところです。","id":"exchange-006"},{"speaker":"つる委員","kind":"質問・要望","question":"当然そこが区だったりネットワークの法人だったりとか、いろいろあると思うのですけれども、そういう企業の積極的な訪問というのでしょうか。視察という部分と、あとはここに来ているそれ以外の世代のつながり、つなぎというのはどういうような形で今進めているのか説明を求めました。","respondent":"柴田子ども施策連携担当課長","answer":"中塚代表とも話す機会がありますので、その辺を１つのアイデアとしてありがたくいただければと考えております。それから、先ほどの企業に来てもらうというのも併せて、子どもたちの羽ばたく機会というのを数多くつくっていければというふうに考えております。","id":"exchange-007"},{"speaker":"つる委員","kind":"質問","question":"それと、改めてですが、現在の分母というのでしょうか。１０法人がある中でいろいろなところでキャッチいただいていると思うのですが、前後してしまうのですが、説明を求めました。","respondent":"柴田子ども施策連携担当課長","answer":"だけれども、表出できない方というのはずっと家の中にいる。そういったところに何かしらの形で手が届くように、それが学校であったり家族の支援であったり、今後様々進めてまいります。","id":"exchange-008"},{"speaker":"ゆきた副委員長","kind":"質問","question":"その上で、スタッフの人数は２０名とありましたが、どのようにスタッフの求人について周知をしているのか。その辺についてお聞きできればと思います。","respondent":"柴田子ども施策連携担当課長","answer":"パートタイム、アルバイトとして働いてくれていたり、もしくはボランティアの数も含めて２０名という計上になっています。支援団体から「合同で品川区で子どものためにこういう取組をやっています」という説明会をやりたいというお話もいただいているところなので。","id":"exchange-009"},{"speaker":"ゆきた副委員長","kind":"確認","question":"確認できました。人材の確保については、どういうふうにお考えかお聞きできればと思います。","respondent":"柴田子ども施策連携担当課長","answer":"スタッフの登録制をというお話かと思いますが、おっしゃるとおりこの分野を担うことができる人材の数は少ないというふうに認識をしております。今後適地が見つかればニーズに応じて新たなところもということで検討をしているのですけれど…","id":"exchange-010"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/256558?Template=document&Id=7301#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=21&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":10302,"voices":27}},{"id":"r08-20260120-20","meetingId":"r08-m01","date":"2026年1月20日","dateIso":"2026-01-20","committee":"ＳＤＧｓ推進・行財政改革特別委員会","time":"午後 １時００分～午後 ４時４０分","status":"正式会議録","sourceType":"formal","overview":"ＳＤＧｓ推進・行財政改革特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を2件整理しています。","topics":[{"id":"topic-01","title":"特定事件調査","agenda":"特定事件調査","exchanges":[{"speaker":"安藤委員","kind":"質問・要望","question":"７月の質疑でＰＦＩ事業ですけれども、また、改めてＰＦＩ事業による施設建設と運営の方針をやめるよう求めたいと思うのです。指定管理者の場合は議決があるのですけれども、今回のＰＦＩ事業の場合、今後の議決があるのかも含めて伺います。","respondent":"吉岡政策推進担当課長","answer":"今後のスケジュールですけれども、実施方針策定の時期と期間で示しております。令和９年の秋頃、ＳＰＣ、事業者との契約締結を考えておりますので、その段で議決をお願いする予定です。","id":"exchange-001"},{"speaker":"あくつ委員","kind":"確認","question":"ここで核とすると出てきたということは、やはりそこについては、かなり図書館機能を非常に強く考えていらっしゃるという打ち出しでいいのかどうか確認させてください。","respondent":"吉岡政策推進担当課長","answer":"次月に報告をいたしますが、実施方針要求通知書の中で、改めて各機能のポイントをご報告します。詳細につきましては、また次月にご説明させていただければと思います。","id":"exchange-002"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/643711?Template=document&Id=7303#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=20&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":2879,"voices":14}},{"id":"r08-20260121-22","meetingId":"r08-m01","date":"2026年1月21日","dateIso":"2026-01-21","committee":"まちづくり・公共交通推進特別委員会","time":"午後 １時００分～午後 ２時５９分","status":"正式会議録","sourceType":"formal","overview":"まちづくり・公共交通推進特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を37件整理しています。","topics":[{"id":"topic-01","title":"特定事件調査","agenda":"特定事件調査","exchanges":[{"speaker":"石田（ち）委員","kind":"質問","question":"花海道については、東京都が同時期に、同箇所の護岸を整備することを計画しているということですけれども、そうすると、この花海道の修景について、東京都が整備してくれることになるのかというか、そのように区としてもお願いしているのか、どのようになっているのか伺いたいと思います。","respondent":"大友公園課長","answer":"その具体的な手法は、今現在東京都当局のほうで検討しているとお聞きしています。修景工事は別に発注しなくてはならないですしというところで、引き続き内容の調整も進めていく形になるかと思っているところです。","id":"exchange-001"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"ちょっと確認させてほしいと求めました。このライトアップ構想を策定することで、予算がアップされていくという考えでいいのか伺いたいと思います。","respondent":"関根河川下水道課長","answer":"現時点で区の橋梁、１３の橋に対してライトアップを実施をしております。あるいはそれ以外についても周辺の環境を調査の上、どういったライトアップをしていくのが良いのかを検討の中で詰めていければと考えています。","id":"exchange-002"},{"speaker":"石田（ち）委員","kind":"質問","question":"消えてしまっているところもあると聞いてはいるのですけれども、今どれぐらいあるのでしょうか。そこら辺はすごく批判の声もあったので、そういったものとつながっていくものなのか、ちょっとそこを伺いたいと思います。","respondent":"関根河川下水道課長","answer":"それから２点目のご質問、メンテナンスしやすい設備の検討です。これから検討してまいります構想の中では、そういったメンテナンス性というものも考慮して構想を作ってまいりたいと考えております。","id":"exchange-003"},{"speaker":"石田（ち）委員","kind":"意見","question":"そういったところで進めていっていただければなと。そして、やはり地域や住民の皆さん、近隣住民の皆さんの思いや合意等も当然ながら含めて、進めていっていただけたらと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-004"},{"speaker":"田中委員","kind":"確認","question":"これは全てこの勝島地区なのか、目黒川も含めた数なのかということの確認です。船なので、その他の桟橋なり船着場との連携ということへの支援というのをどう考えているのかということを、まとめてお伺いしたいと思います。","respondent":"関根河川下水道課長","answer":"広く利用する方向に向けて検討するものと、進めていくものと区としては認識していますし、そのための支援を区としても行ってまいります。この桟橋間の連携、そうした連携についても、今後どのようなことができるか検討してまいりたいと考えています。","id":"exchange-005"},{"speaker":"田中委員","kind":"意見","question":"それがまちづくりビジョンの全体の構想にもつながりますので、活性化にもつながりますので、お願いしたいと思います。区内にも他に何か所もありますので、イベント支援と同時に災害発災時にも活用できるような視点での取組をぜひお願いをしたいと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-006"},{"speaker":"えのした委員","kind":"提案","question":"以前も目黒川のライトアップについて、様々私のほうもご質問とご提案もさせていただきました。お伺いしましたけれども、何かそういった効果のほうが分かれば、教えていただけますか尋ねました。","respondent":"関根河川下水道課長","answer":"現状、どれぐらいの具体的な効果があるかですとか、どれぐらい取り上げられているかという把握は、現状ではできてございません。あるいはそういったところも含めて検討をしていきたいとは考えておりますので、その中で、そういったことはしてまいりたいと考えています。","id":"exchange-007"},{"speaker":"えのした委員","kind":"質問・要望","question":"やはり、これだけの予算を使うことですから、まちづくり、活性化、観光も含めて重要だとは思いますが、そういった効果の検証が分かるような取組も要望します。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-008"},{"speaker":"石田（秀）副委員長","kind":"質問・要望","question":"それから考えると、立会川の高潮護岸を造るというか今より高くしようという話はないわけではないですか。計画としてはその遊歩道化をしようかということになっているわけですから、すごく良いチャンスのときが来るのだろうなと思っている。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-009"},{"speaker":"石田（ち）委員","kind":"質問","question":"新たな法改正でどう変わるのかなどを知らないとか把握していない人もすごく多くいるのではないかというのを、自転車に乗っていて感じるのです。区としてはどういうことをやってきて、またやっていくのか、伺いたいと思います。","respondent":"山下交通安全担当課長","answer":"先日しながわ中央公園でも行いましたが、あと警察と連携してのキャンペーン、またもろもろの交通安全教室を今後も実施していく予定です。２月１日号の広報しながわにも法改正の趣旨について載せる予定です。","id":"exchange-010"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"１４.４％なので、今、私が申し上げたようなこともきっとあるのだろうなとは思うのですけれども、これの中身をもう少し教えていただきたいのです。区としてはどう考えているのかを伺いたいと思います。","respondent":"櫻木地域交通政策課長","answer":"令和１５年度までに５９.３ｋｍの整備を目指して道路課と連携しながら、なるべく早く進められるように様々取り組んでいければとは思っております。満足度につきましては、その辺りのご意見が見られたという話も聞いておりますので…","id":"exchange-011"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"何とか危険を回避しながらこちらも運転しているのですけれど、そういったところでは、回避できるものなのか伺いたい。車道を走りますけれども、そういったところが都道と国道の関係でスムーズにいくのか、そこを伺いたいと思います。","respondent":"山下交通安全担当課長、櫻木地域交通政策課長","answer":"そういった方もいらっしゃいますので、そこにつきましては警察と連携して、しっかり取締りをしていきたいと考えております。通報等をしていただくといったことをお願いしながら排除に努めておりますので… 区道をネットワーク化していくという形で考えておりますので、あと区もそうですけれども、それぞれ進めているというところになっております。逆に言うと国道・都道もこれから進めていく部分もあろうかと思いますので…","id":"exchange-012"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"何かすごく速く走る自転車みたいなやつ、あれもこの自転車レーンを走る対象のものなのですか。電動キックボードもここを走るものなのかなと感じてはいたのですけれども、そこはルールとして、明確に決まっているのか尋ねました。","respondent":"山下交通安全担当課長","answer":"モペット、基本的には自転車レーンは走行できないことになりまして、車道の左側端を走るということになっております。「令和５年７月１日に法改正がありまして、電動キックボードが、いわゆる青色のレーンを走行可能」と答弁訂正あり〕。","id":"exchange-013"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"商店街の駐輪場の確保もすごく求められているのですけれども、なかなか難しいというところもあると聞いています。これは全区でしょうから、五反田それぞれの地区で何％みたいな、そういう個別の目標というのはあったりするのか伺いたいと思います。","respondent":"山下交通安全担当課長、櫻木地域交通政策課長","answer":"委員会等でもご報告していますが、公園の改修工事の中で駐輪場の整備を行ってまいりまして、早ければ令和９年度からご利用いただける予定です。おおむね５００台ぐらい増える予定ですので、当日利用の方はそちらに移っていただいて… 一応区の方針としてはそういう形で支援を進めていきたいです。２時間までちょっとしたお買物には無料で使えるというような状況はできておりますので、その周知・促進に努めていくのかなと考えています。","id":"exchange-014"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"商店街のところについて、商店側に求めていくというのは、場所を確保するというところではやれるところにも限界があるかと思うのです。こういう計画も出して減らしていこうと言っているわけですから、ぜひ区のほうからのアプローチをもっと強めていってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-015"},{"speaker":"藤原委員","kind":"確認","question":"基本中の基本をお伺いしたいと思います。いろいろな施策が出てくるのですけれども、歩行者はいわゆる交通弱者ですから、歩行者の安全が一番だと考えていてよろしいのですよねという確認です。","respondent":"山下交通安全担当課長","answer":"歩行者が第一かですが、歩道は歩行者のためにあるものです。歩道につきましては歩行者第一ですし、自転車が通行することができる場合であっても、そちらについてもしっかりと啓発をしていきたいと考えています。","id":"exchange-016"},{"speaker":"藤原委員","kind":"質問・要望","question":"こういうのをどうしたら良いかということをご相談しても、歩行者の歩道を自転車が走ってはいけないというわけではないではないですか。その辺についての広報、もう出前講座でも良いので徹底していっていただきたいと思うのですけれども、その辺についてはいかがか尋ねました。","respondent":"山下交通安全担当課長","answer":"年に２回全国交通安全運動等もありますので、そういった集客が見込めるような大きいイベントで啓発をしてまいります。しっかりそういった年代に応じた安全講習ですとかキャンペーン等ができればと考えていますので、今後とも引き続き実施してまいります。","id":"exchange-017"},{"speaker":"藤原委員","kind":"質問・要望","question":"その反則金と私も伺ってお話の中で出てきますけれども、どうどういう形で、切符とか切るのですか。そういう場合は、具体的にその人であるという担保はどのように確認していくのか尋ねました。","respondent":"山下交通安全担当課長","answer":"そういった方への対応について、それと自分の持っている何かしらの顔写真が付いてない証明書と突き合わせたりとかということをしています。いずれにしましても、基本的には免許を持っている人も持っていない人も顔写真付きの証明書で確認をすることが鉄則かと思います。","id":"exchange-018"},{"speaker":"えのした委員","kind":"質問・要望","question":"私も様々要望もさせていただきましたが、ご対応本当にありがとうあります。ほかに何か具体策などがあればここに出てきているとは思うのですが、意気込みと、今後考えられることがあればお答え願えますか尋ねました。","respondent":"山下交通安全担当課長","answer":"武蔵小山駅につきましては、大変申し訳ありません、土地の確保の事情でなかなか区営駐輪場の設置が、難しいところがあります。少しでも空いているところを有効に活用できるように、区としましては啓発を引き続き続けてまいりたいと考えています。","id":"exchange-019"},{"speaker":"えのした委員","kind":"質問・要望","question":"今後も引き続き対策を考えてほしいと求めました。これは要望です。","respondent":"大友公園課長","answer":"それでも変わらないというところがあれば、次の手段として警告札等々を掲示して、その自転車に直接教えるという形を取っているところです。即時撤去はなかなか難しく、このような対応を取って、引き続き違法駐輪をなくしていきたいと考えているところです。","id":"exchange-020"},{"speaker":"塚本委員","kind":"質問・要望","question":"電動キックボードというのは一応、２０ｋｍ／ｈの速度制限がある。そもそもスピード違反というのが、その取締りの対象となっているのかどうかというのを、最初に確認させてほしいと求めました。","respondent":"山下交通安全担当課長","answer":"それで自転車を取り締まることができるのかどうかという、実質的に難しいのかなと私の今の考え方だと思います。ただ、速度を超過すれば、それは違反になりますので、取締対象とはなりますけれども、その取締りをするかどうかというところは微妙なのかなです。","id":"exchange-021"},{"speaker":"塚本委員","kind":"質問","question":"そうすると、なかなか、そういうスピード違反をすると違反になって切符を切られるよというのは、言えない感じになるのですかというのが一つ。そういうところの物理的な制限を行うみたいな、何かできることはあるのかというようなことについて、伺いたいと思います。","respondent":"山下交通安全担当課長","answer":"一般に販売されている、ちょっと管理が難しいといいますか、速度のリミッターを解除している方も中にはいるかもしれません。いつでも私のほうに来てくださいということでお願いをしておりますので、そういったところで啓発していければいいのかなと考えております。","id":"exchange-022"},{"speaker":"松本委員","kind":"意見","question":"在住区民アンケートなのでこの令和４年しかないということかと思うのですが、そちら側の数字を使うということはできないのかというのが一つ。そういうデータがあれば、分かる範囲で結構ですので、お示しほしいと求めました。","respondent":"櫻木地域交通政策課長","answer":"一時期入っていることを確認する書類も同時に求めるという形で、利用促進というか加入促進をしてきたところがあります。引き続き加入促進について、東京都の条例で義務化されているということもありますので、その辺りは周知に努めてまいりたいと考えています。","id":"exchange-023"},{"speaker":"松本委員","kind":"質問・要望","question":"この保険に入るかどうかというとき、軽い気持ちで自転車を運転されている方もいらっしゃるのかなと思います。ひょっとすると私の確認不足で、ぜひそういう周知も引き続き行ってほしいと求めましたが、いかがか尋ねました。","respondent":"山下交通安全担当課長","answer":"そういった機会があれば載せて、本当に怖い、大変なのだというところをアピールしていければいいのかなとは考えております。今後また検討します。","id":"exchange-024"},{"speaker":"松本委員","kind":"質問・要望","question":"最後に、要望です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-025"},{"speaker":"田中委員","kind":"質問・要望","question":"私はきちんと連携を取るべきだと思っているのですけれども、特に区境で指定されている道路はどうなのかというところをぜひご説明いただきたいです。まだまだ多いと思うのですが、例えば旗の台の昭和大の鏑木坂というんか尋ねました。","respondent":"櫻木地域交通政策課長、森道路課長","answer":"付け方の考え方ですが、逆にそれほどニーズが見込まれない、それを定量的に点数化した上でこれが設定されているものです。４点目、隣接区との関係ということで、こちらは非常に大事な視点と認識しております。 品川区道ということで、今回の線をつけしています。ここへつなげるような路線も大変重要だということで、ネットワークに位置づけをさせていただいたです。","id":"exchange-026"},{"speaker":"田中委員","kind":"質問・要望","question":"商店街との関係性で言うと、やはり冒頭の藤原委員のお話にあったように、歩行者最優先でやるべきですので、こここそしっかり周知をぜひお願いしたい。その補助２６号線の関係と、安全性の視点のもう一度確認と、商店街の歩行者周知という視点でもう一度お願いします。","respondent":"櫻木地域交通政策課長","answer":"こちらも次の見直しのタイミングでまた新たな交通状況を踏まえて再検討することになるかと考えています。それは商店街の実情に応じてご対応いただき、交通安全対策の強化につなげる形で今回は指定させていただいているところです。","id":"exchange-027"},{"speaker":"田中委員","kind":"質問・要望","question":"１件だけ。指定する以上はその指定する側が安全対策をしっかり講じるべきだと思いますので、そこは徹底してほしいと求めました。","respondent":"山下交通安全担当課長","answer":"モペットが原動機付自転車扱いとなって走行はできないというところで、すみません、答弁を訂正させていただきたいと思います。大変申し訳ありませんでした。","id":"exchange-028"}]},{"id":"topic-02","title":"京浜急行バス株式会社のバス路線における系統廃止","agenda":"京浜急行バス株式会社のバス路線における系統廃止","exchanges":[{"speaker":"石田（ち）委員","kind":"質問・要望","question":"こうした京浜急行バスにしても、都や民間事業者に要望を出していただきたいとは思いますけれども、区として何かできることはないのでしょうか。そして減便、改善に向けて区としても求めていくというようなことをぜひしていただきたいと思うのですけれども、いかがか尋ねました。","respondent":"櫻木地域交通政策課長","answer":"継続していただくことを強く求めてきたところですし、この件につきましても、情報をいただいた時点から強く求めてまいりました。現時点で減便等の追加的な情報については、区は把握していないという状況です。","id":"exchange-029"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"競合しないわけですから、もう走らせていただきたい。そうやって改善を求めていっていただいた上で、走らせるという、それはできないのか伺いたいと思います。","respondent":"櫻木地域交通政策課長","answer":"今後、交通サービス圏域外が一定解消のめどがついたタイミングで、今後の取組方針を固めていくようなタイミングが来ようかと考えています。今お話がありましたコミュニティバスにつきましては１区間この路線と重複する部分もありますので、そこにつきましては…","id":"exchange-030"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"交渉はぜひ強い姿勢で進めていっていただきたいのですが、それがかなわないときは、やはり区として考えていくべきではないかと思いますので、コミュニティバス等の検討をよろしくお願いしたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-031"},{"speaker":"田中委員","kind":"質問・要望","question":"大森駅からさくら会までの間に、何もバス停がないという状況を解消してほしいという具体的な声があり、何回も伝えております。それとこれは要望ですけれども、そういった方面を踏まえた新路線というものも考えていただきたい。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-032"},{"speaker":"塚本委員","kind":"質問","question":"将来この路線の復活みたいなこととかはあるのかどうかということ。収益が会社全体として厳しいのでどこかをリストラしなくてはいけないという話の中で出てきたこの路線廃止なのかというのを説明を求めました。","respondent":"櫻木地域交通政策課長","answer":"１点目の需要回復の遅れのニュアンスということです。この路線に関しても減少して、回復していないと、話としては聞いております。","id":"exchange-033"},{"speaker":"塚本委員","kind":"質問","question":"いろいろと、経済が回復しているではないですか。どうしてかということがちょっと気になるのですけれども、何か分かっていることがあれば、説明を求めました。","respondent":"櫻木地域交通政策課長","answer":"京浜急行バスに限らずバスの協会は、ピークと比べて８割程度までしか戻ってきていないという言い方をしています。結果として、最初のコロナ前には戻っていないという状況をこのような形で表現されているという認識です。","id":"exchange-034"},{"speaker":"塚本委員","kind":"意見","question":"地域公共交通会議とかで議論されているいわゆる公共交通の空白地帯というものがまたこの辺にできてくるのかなと。そういう流れも今後出てくるのかなというか、そのようにしていくべきでもあろうと思うのですけれども、その辺の今後の見通しをお知らせくださいとの意見を述べました。","respondent":"櫻木地域交通政策課長","answer":"区全体の中で交通サービス圏域外の一定のめどがついた後にどこを強化していくかということを考えてまいりますが、先ほど勝島のお話もありました。様々な地域の様々なご要望の状況を踏まえて、どのような品川区の交通政策をつくっていくかを検討していくものと考えております。","id":"exchange-035"},{"speaker":"塚本委員","kind":"意見","question":"この距離も結構あるので、間に当然幾つか、先ほどバス停をもっと作って欲しいという意見も他の委員からございました。様々環境も変わってくるので、ぜひ前向きな検討というか、みんなの地域の公共交通ということでの検討というのはお願いしたいと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-036"},{"speaker":"石田（秀）副委員長","kind":"質問","question":"この路線はなくなるのですから。けれども、それは一つの既得権益ぐらいをくださいよと、コミュニティバスはそこを強く言ってほしいと思っているけれども、どうか尋ねました。","respondent":"櫻木地域交通政策課長","answer":"副委員長がおっしゃられた状況も含めて、区としてもいすゞ病院や桜新道というところについては様々強い申入れをして、交渉していますので現時点では言うことは難しいのですが、区としても皆様の思いを強く交渉していく所存です。","id":"exchange-037"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/931508?Template=document&Id=7305#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=22&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":35952,"voices":87}},{"id":"r08-20260122-10","meetingId":"r08-m01","date":"2026年1月22日","dateIso":"2026-01-22","committee":"議会運営委員会","time":"午後 １時００分～午後 １時０６分","status":"正式会議録","sourceType":"formal","overview":"議会運営委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を0件整理しています。","topics":[],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/677927?Template=document&Id=7307#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=10&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":2826,"voices":22}},{"id":"r08-20260217-10","meetingId":"r08-1t","date":"2026年2月17日","dateIso":"2026-02-17","committee":"議会運営委員会","time":"午前１０時３０分～午前１０時５７分","status":"正式会議録","sourceType":"formal","overview":"議会運営委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を6件整理しています。","topics":[{"id":"topic-01","title":"令和８年第１回定例会","agenda":"令和８年第１回定例会","exchanges":[{"speaker":"まつざわ委員長","kind":"提案","question":"なお、本件の採決方法については、３月４日水曜日の予算特別委員会後に行う議会運営委員会で確認いたします。追加で提案される予定の議案につきましては、明日午後０時４５分から、ご予定ほしいと求めました。","respondent":"大澤区議会事務局長","answer":"資料No.５にお戻りいただきまして、以上の議事日程で、終了は０時３０分を見込んでおります。次に、予定表(3)陳情の参考送付について、資料No.７になります。","id":"exchange-001"}]},{"id":"topic-02","title":"予算特別委員会","agenda":"予算特別委員会","exchanges":[{"speaker":"安藤委員","kind":"提案","question":"共産党としては、今年も区長の予算編成権を侵さない範囲で、予算修正案を提案したいと考えています。提案の時期なのですが、各会派、議員の皆さんが検討できる時間を取れるようなタイミングで提案させていただきたいと思っていますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-002"}]},{"id":"topic-03","title":"広報会議からの報告事項","agenda":"広報会議からの報告事項","exchanges":[{"speaker":"せお委員","kind":"質問・要望","question":"令和８年１定号から、区議会だよりの紙質を見直すことといたしました。紙質の見直しを求めるご意見がありましたので、フリーペーパーのような、手に取りやすく親しみやすい紙質となるように変更することとなりました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-003"},{"speaker":"あくつ委員","kind":"質問","question":"親しみやすいというお話があったのですけれど、これは、予算的にも抑えられるということなのでしょうか。その辺りを説明を求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-004"},{"speaker":"あくつ委員","kind":"意見","question":"きちんと、紙質も変わって、予算も下がりますという説明がこれからできればなと。承知いたしましたとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-005"}]},{"id":"topic-04","title":"その他","agenda":"その他","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"どのようなものを考えているのかというか、どういうふうにして内容とかを決めていくのかというのは、現時点での考えを伺いたいです。なぜなのかというのと、ほかの係では欠員というか足りていないということはないのか、その辺も併せて伺いたいと思います。","respondent":"大澤区議会事務局長","answer":"内容的に大きく変更する予定はありませんけれども、より、児童・生徒が手に取りたくなるようなパンフレットに変えていこうという方向性です。ほかの係については、いろいろ職員がぎりぎりでやっておりますけれど、今のところはこの人数でいけると見込んでおります。","id":"exchange-006"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/677927?Template=document&Id=7309#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=10&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":9290,"voices":43}},{"id":"r08-20260218-10","meetingId":"r08-1t","date":"2026年2月18日","dateIso":"2026-02-18","committee":"議会運営委員会","time":"午後 ０時４５分～午後 ０時４８分","status":"正式会議録","sourceType":"formal","overview":"議会運営委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を0件整理しています。","topics":[],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/677927?Template=document&Id=7311#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=10&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":1562,"voices":12}},{"id":"r08-20260220-3","meetingId":"r08-yosan","date":"2026年2月20日","dateIso":"2026-02-20","committee":"予算特別委員会","time":"午前１１時５５分～午後 ０時０２分","status":"正式会議録","sourceType":"formal","overview":"予算特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を0件整理しています。","topics":[],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/629350?Template=document&Id=7377#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=3&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":1994,"voices":16}},{"id":"r08-20260224-6","meetingId":"r08-1t","date":"2026年2月24日","dateIso":"2026-02-24","committee":"区民委員会","time":"午前１０時００分～午前１０時５７分","status":"正式会議録","sourceType":"formal","overview":"区民委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を20件整理しています。","topics":[{"id":"topic-01","title":"令和８年陳情第９号、インボイス制度による事業者への影響の実態調査を品川区独自で行う陳情","agenda":"令和８年陳情第９号、インボイス制度による事業者への影響の実態調査を品川区独自で行う陳情","exchanges":[{"speaker":"おぎの委員","kind":"質問","question":"中小企業庁が国として調査を今、やり直しといいますか、前回ひどい調査だったので、今回仕切り直しの調査になっていると思いますが、どちらが今請け負っていらっしゃるのか尋ねました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"今回の調査については、東京商工リサーチが受託したと報道で把握しております。","id":"exchange-001"},{"speaker":"おぎの委員","kind":"質問","question":"そうしますと、東京商工リサーチは区がリーチできない情報をお持ちで、区内事業者でも、区がつながれないところの声は幅広く拾えている感じなのか尋ねました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"国の調査ですので、細かい手法については、区で関知していないところです。免税情報を持ち合わせているので、受託事業者とどのように連携を取っているかというのは、そこについては何とも言えないところです。","id":"exchange-002"},{"speaker":"おぎの委員","kind":"質問","question":"やり直しということですので、前回を踏まえて今回はきちんとやっていただけるのかなという期待はしている部分があります。９月に２割特例が切れますので、９月から２割から３割に変わって、区としては何か今後の方針などというのはあるのか尋ねました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"現状のところでは、区が今やっている施策を、より丁寧にやっていくということを引き続き考えているところです。そちらの利用状況ですとか、それを事業者の方に案内するとか、そういったことは丁寧にやっていきたいと考えています。","id":"exchange-003"},{"speaker":"おぎの委員","kind":"意見","question":"景況調査等も含めて、また負担が増える時期になるので、何らかの対策等もまた考えていただけたらと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-004"},{"speaker":"こしば委員","kind":"質問","question":"昨年の秋に同じような趣旨の請願の審査がありまして、その際に課長の説明で、１２月に創業支援センターで個人事業主等に向けたインボイスの説明会を行うというところを聞いておりまして、その振り返り、参加者の特性だとか、人数だとか、反応など、分かる範囲で教えてほしいと求めました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"こちらは、５名の方が参加されまして、個人事業主でもう創業している方と、これから創業を考えている方が参加されました。こういったことを知れたといったアンケートの回答はあったところですので、より広報、周知を努めてまいりたいと考えております。","id":"exchange-005"},{"speaker":"こしば委員","kind":"質問","question":"その際に、インボイス制度そのものについて、問合せだとか、意見とか、そういったものは出てこなかったという認識でよろしいか尋ねました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"インボイス制度そのものに関するご意見だとかお問合せというのは、なかったと聞いております。","id":"exchange-006"},{"speaker":"こしば委員","kind":"質問・要望","question":"人数が５人程度であったということと、それでも参加された方の中からは、インボイス制度そのものの話というのは実際出てこなかったです。そういったことも踏まえまして、今回の陳情に関しては、願意に沿い難く、不採択とさせてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-007"},{"speaker":"おぎの委員","kind":"質問・要望","question":"ただ、個人的には、今回選挙で区内あちこちを回りましたけれども、インボイスを早くやめてほしいという声は結構あったのです。国も政策として何らかやっていただきたいですし、２割から３割に特例割合が変わってしまうので、何か支援などを考えてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-008"},{"speaker":"こんの委員","kind":"質問・要望","question":"１１月にも同じような請願が出ていたと伺っております。どうしたらいいのかという個別相談会みたいなものも併せてしていくことによって、より一層細かい実態がつかめてくるのではないかと想像します。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-009"},{"speaker":"せらく委員","kind":"質問・要望","question":"区内事業者支援は、既存の産業振興施策や相談体制の充実を通じて、継続的に取り組むべき課題だと考えます。今後も必要に応じて改善は求めていくと思いますが、現時点において改めて独自調査を求める今回の陳情については。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-010"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"私の理解ではやって、ここに記載があるように、全ての人といっても職人はこの中には入らないのかなと私は考えております。なので、やはりこれは今、結果を分析してからいろいろ検討していただきたいということで、不採択でお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-011"}]},{"id":"topic-02","title":"令和７年国勢調査","agenda":"令和７年国勢調査","exchanges":[{"speaker":"こんの委員","kind":"質問","question":"少し様子を伺いたいのですけれども、手渡しあるいは接触をするというところのご苦労のお話がよく出ますが、今回はどんな状況だったでしょうか。この２点を説明を求めました。","respondent":"平原地域活動課長","answer":"前回の令和２年の国勢調査の時点で、その課題が強く認識されまして、最初から投函でよいなどの対応が今回から取られているところです。今回試行的に完全郵送化を４つの自治体で国が取り組んだところでございまして、そういったところの改善につながっていくものと期待しています。","id":"exchange-012"},{"speaker":"こんの委員","kind":"質問・要望","question":"モデル実施なのでしょうか、実証実験されたのでしょうか、今のお話を聞いていて思いました。今回のいろいろな皆さんが気づいた点だとか、ご負担だとかというところを、５年後のことにも活かしていただきながら進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-013"},{"speaker":"こしば委員","kind":"質問","question":"どこも町会・自治会の中で、それぞれの調査区に割り当てる人数の確保に多分ご苦労されているところだと思います。５年後、今回は公募などというのが６２人おりましたが、どのような仕組みなのか教えてもらえますか。","respondent":"平原地域活動課長","answer":"なるべく軽減するような手だてを取りながら、引き続きこういったところはご協力を求めていく形で丁寧にご説明してまいりたいと考えています。そういったところにつきましては、町会推薦あるいは公募等を含めて、様々こちらでも努力してまいりたいと考えています。","id":"exchange-014"},{"speaker":"こしば委員","kind":"質問","question":"実際に歩いて回るわけですから、町会・自治会の一つの活性化につながるかどうか分かりませんけれども、５年後に備えてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-015"},{"speaker":"高橋（伸）委員","kind":"質問","question":"２０１の町会・自治会も本当に皆さんご苦労している中で、本当にいろいろご苦労もあるかと思いますので、これは感謝申し上げたいと思います。資料にマンション管理人、施設管理者と記載がありますが、タワーマンションの方たちの取扱いを改めてお聞きしたいと思います。","respondent":"平原地域活動課長","answer":"まずは管理会社、管理人等々の方にご協力いただくということがベースになりますので、そういった方々にしっかりと説明していくというのが基本です。お住まいの形態には全く関わりなく調査対象です。","id":"exchange-016"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"なので、ぜひ、これは区には求められないことなのだけれども、その調査結果を踏まえて、いろいろ今後も検討してほしいと求めました。これは要望でお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-017"}]},{"id":"topic-03","title":"品川ソーシャルイノベーションアクセラレーター デモデイの開催","agenda":"品川ソーシャルイノベーションアクセラレーター デモデイの開催","exchanges":[{"speaker":"こんの委員","kind":"質問","question":"参考までに伺いたいといったところ、参考までに伺いたいのですが、研修６回とその他パートナー企業との交流会等と書いてある。具体的にはどういった取組をされているのかといったところ、この３点の状況を説明を求めました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"そういったところで、令和２年度にこのプログラムを実施させていただいたところです。どういったマインドセットを行わなくてはいけないのかといったところを実施しておりまして、このプログラムは２１のパートナー企業があります。","id":"exchange-018"},{"speaker":"こんの委員","kind":"質問・要望","question":"いかがでしょうか。その２点を、何か感想なり、現状を教えていただきたいです。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"来年度はそういったＩＴではない業種の方への支援についても、より強化していくことを検討しています。それから、さっき申し上げた３施設の入居も、ご検討くださいという形でご案内しています。","id":"exchange-019"}]},{"id":"topic-04","title":"その他","agenda":"その他","exchanges":[{"speaker":"こんの委員","kind":"確認","question":"確認ですが、事前申込みということは、定員などがあるのでしょうか。その辺りを伺いたいと思います。","respondent":"守屋スポーツ推進課長","answer":"大変細かくて申し訳ないですが、チラシの２ページ目のところに、事前申込み制のところは青く記載されております。ここに定員数を書かせていただいておりまして、教室形式ですので、人数自体は小規模なものから若干多いものまで、千差万別という形になっております。","id":"exchange-020"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/612978?Template=document&Id=7319#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=6&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":17798,"voices":65}},{"id":"r08-20260224-7","meetingId":"r08-1t","date":"2026年2月24日","dateIso":"2026-02-24","committee":"厚生委員会","time":"午前１０時００分～午後 ４時０１分","status":"正式会議録","sourceType":"formal","overview":"厚生委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を104件整理しています。","topics":[{"id":"topic-01","title":"福祉施設関係条例の改正等（4議案）","agenda":"福祉施設関係条例の改正等（4議案）","exchanges":[{"speaker":"鈴木委員","kind":"質問・要望","question":"９月のときに厚生委員会で、それぞれ定員というものは２０名ということでいいのか、その具体的な定員数を教えてほしいと求めました。ここの総事業費と補助金などが分かったら教えていただきたいということと、施設２、もし建設費と補助金が分かったら教えていただけたらと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-001"},{"speaker":"鈴木委員","kind":"質問","question":"高齢者施設の５６億円というものは、全部合わせた、大体施設１と施設２を合わせたものが５６億円ということになるのでしょうか。その辺のところが分かったらお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-002"}]},{"id":"topic-02","title":"障害福祉関係条例の改正等（3議案）","agenda":"障害福祉関係条例の改正等（3議案）","exchanges":[{"speaker":"鈴木委員","kind":"質問・要望","question":"この就労選択支援が創設された背景と、具体的にどう変わるのか、このサービスの対象や支援の中身についてお聞かせほしいと求めました。","respondent":"松山障害者支援課長","answer":"就労継続支援Ｂ型については令和７年の１０月以降から、Ａ型については令和９年の４月以降からと段階的に設定されております。内容についてですが、作業場面を活用したアセスメント、アセスメントシートの作成、多機関連携によるケース会議、事業者調整となっております。","id":"exchange-003"},{"speaker":"鈴木委員","kind":"質問","question":"区内でこの就労選択支援の登録事業者というものがあるのかどうなのかということと、何というのですか、そのようなものがあるのかどうなのかについてもお聞かせいただけたらと思います。","respondent":"松山障害者支援課長","answer":"国の就労選択支援のマニュアルのとおりに進める予定です。今後の方向性については、区内の事業所、ニーズに応じて対応できるところが指定を受けていただければと考えています。","id":"exchange-004"},{"speaker":"吉田委員","kind":"質問","question":"そして事業者も決まったということなのですけれども、それに伴ういろいろな人員のことなどは今後ということなのでしょうか。その辺についての今後の、段々スキルアップなど、そのようなことは併せて考えておくべきだと思うのですけれども、その辺についてはいかがか尋ねました。","respondent":"松山障害者支援課長","answer":"これまでは統一されている手法ではなかったということで、今回国のほうで統一して養成研修を行い、その上で特化したサービスとして切り出したです。今後もニーズに合わせて対応してまいります。","id":"exchange-005"},{"speaker":"吉田委員","kind":"質問","question":"何といいますか、スキルの問題もあるし、やはり人員体制の充実させる必要もあると思うのです。その辺について、そのようなものも必要だと思うのですが、その辺については具体的にはどのように進められるのか教えてほしいと求めました。","respondent":"松山障害者支援課長","answer":"就労選択支援は委託ではなく、民間事業者として指定を取っているものです。したがいまして、区としましては、地域自立支援協議会就労支援部会などの課題検討、協議を含めて、その中で対応してまいりたいと考えています。","id":"exchange-006"},{"speaker":"吉田委員","kind":"質問","question":"それぞれの事業者が取るものということですが、でも私としては、やはりこれ非常に重要な事業かなと思います。やはり現実としてそのようなミスマッチが起きてしまっているということは伺いますし、区としても適切な支援は考えていってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-007"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"非常にこういった制度、いい制度だと思うのですけれども、ちょっと確認なのですが、この就労選択支援を利用される方には自己負担が発生するのか、もし発生するなら費用はどれぐらいなのかということが分かれば教えてほしいと求めました。","respondent":"松山障害者支援課長","answer":"費用負担についてのお尋ねです。就労選択支援サービスは総合支援法のサービスですので、利用者負担は１割となっております。","id":"exchange-008"},{"speaker":"やなぎさわ委員","kind":"確認","question":"確認ですけれども、収入があれば１割ということでよろしいか尋ねました。","respondent":"松山障害者支援課長","answer":"障害者総合支援法は国の全体のサービスですので、収入に応じてということになります。","id":"exchange-009"}]},{"id":"topic-03","title":"第３１号議案、品川区介護保険制度に関する条例の一部を改正する条例","agenda":"第３１号議案、品川区介護保険制度に関する条例の一部を改正する条例","exchanges":[{"speaker":"鈴木委員","kind":"質問","question":"今回の給与所得者の中で、税制改定で影響を受ける人というものがトータルで何％ぐらいいるのかということが分かったら教えていただけたらと思います。年金の人のほうが非課税になる年金の年額の総収入というものが多いわけですから、その辺の考え方についても伺えたらと思います。","respondent":"菅野高齢者福祉課長","answer":"８００人ちょっとかなというように、ご本人だけではなくて、現時点では人数は特定できないような状況となっております。ご理解いただければと思います。","id":"exchange-010"},{"speaker":"鈴木委員","kind":"質問・要望","question":"これを反映させたとしても、品川区の場合は本当にないのではないかと思うのですけれども、その辺のところの介護財政との関係も伺えたらと思います。それともう一つ、そこに対しての今回の税制改正の影響の反映というものはどのようなことになっていくのかについても伺えたらと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-011"},{"speaker":"鈴木委員","kind":"質問","question":"ちょっと聞き逃したのかもしれないのですけれども、年金よりも給与所得の方のほうが非課税の額というものが低いではないですか。そのようなことからすると、１０万円上がって１１０万円になるということのほうが、その点はいかがか尋ねました。","respondent":"菅野高齢者福祉課長","answer":"税の部分では確かに今回１０万円上がることによって、３年間の介護保険料の見込みの中で、そちらはこの令和８年度に関しては連動しないというように理解しております。","id":"exchange-012"},{"speaker":"鈴木委員","kind":"意見","question":"反対です。連動させて、やはりそれに合わせた負担を減らすというようなことにすべきだと思いますので、反対ということでお願いしますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-013"}]},{"id":"topic-04","title":"第３２号議案、品川区立高齢者住宅条例の一部を改正する条例","agenda":"第３２号議案、品川区立高齢者住宅条例の一部を改正する条例","exchanges":[{"speaker":"鈴木委員","kind":"質問・要望","question":"それから現在は、この家賃というものが、生活保護の方は住宅扶助の５万３,７００円という規定になっていると思うのです。最低額の３万円ということで考えていいのか、その最高額は、いるとしたらどれぐらいなのかということもお聞かせいただけたらと思います。","respondent":"樫村高齢者地域支援課長","answer":"まずは区のほうで実施しております家賃市場調査、令和７年９月に実施しておりまして、それから家主と協議をいたしまして。もう一つありました現在の最高額７万２,０００円をお支払いいただいている方がいらっしゃるかというと、現在はおりません。","id":"exchange-014"},{"speaker":"鈴木委員","kind":"質問・要望","question":"高齢者住宅が２００人ちょっと分あると思うのですけれども、最高額の収入の方が幾らかということと、最高額を払っている方というものはいらっしゃるのかということを教えてほしいと求めました。","respondent":"樫村高齢者地域支援課長","answer":"２１９戸ありますけれども、皆さん減額の適用になっておりますので、減額をせずに最高額をお支払いしている方というものは現在いらっしゃいません。先ほど申し上げたとおり、所得に応じて金額決められておりますので、どの方が最高額などというところまでは把握をしておりません。","id":"exchange-015"},{"speaker":"鈴木委員","kind":"確認","question":"何というのですか、その６,０００円というものが、その点を確認させてください。","respondent":"樫村高齢者地域支援課長","answer":"この６,０００円分の値上げにつきましては区が負担をするといったところでございまして、当然この６,０００円分もお支払いいただくことになりますので、影響を受ける方がいらっしゃる可能性があるといったところです。","id":"exchange-016"},{"speaker":"あくつ委員","kind":"質問・要望","question":"特に社会情勢等踏まえて、うちの会派で検討したときに、これは確認をしていただきたいという意見があったので伝えます。そこはしっかり丁寧にやっていただきたいという、私どもの会派の要望があったので、その辺りについてお考えがあれば教えください。","respondent":"樫村高齢者地域支援課長","answer":"確かに今回条例改正を行います、このアツミマンションにつきましては、家主の方がこのアツミマンション内のところに居住をされていると。引き続きそういったところのないように、丁寧に家主の方、それから管理人の方と区が仲介して運営をしてまいりたいと考えています。","id":"exchange-017"}]},{"id":"topic-05","title":"第３３号議案、品川区後期高齢者医療に関する条例の一部を改正する条例","agenda":"第３３号議案、品川区後期高齢者医療に関する条例の一部を改正する条例","exchanges":[{"speaker":"鈴木委員","kind":"質問・要望","question":"納入通知、督促ですか、そのようなものごとに何件ぐらいあるのかということが分かったら教えてほしいと求めました。それはどれぐらいの期間されていたのか、そのことによって対応されたことというものはあるのか、その点についても伺います。","respondent":"山下国保医療年金課長","answer":"例えば納入の通知が通知書ということで掲示をされるものではなくなり、その内容が何らか伝わるような形でお示しをしていくということとなっています。公示をされている期間ですけれども、内容によりましてちょっと異なるところかと思うのですが…","id":"exchange-018"},{"speaker":"鈴木委員","kind":"質問","question":"その辺の効果というものはどう考えているのかということと、何というのですか、名前が公開されるわけです。プライバシーの侵害ということに対してはどう考えるのか、その点についても伺いたいと思います。","respondent":"山下国保医療年金課長","answer":"実際に何週間、今後関係所管等と検討を進めて、実際に運用を開始してまいりたいと考えています。例えば、そういったところは、区として運用していくに当たっても十分に配慮してまいりたいと考えています。","id":"exchange-019"},{"speaker":"鈴木委員","kind":"質問・要望","question":"３０件とか、４０件とかあった中での督促状の割合というものはどれくらいなのかということを伺いたいということと。後期高齢者医療制度の中でも差押えというものはあるのか、ある場合はその件数についても、どれぐらいあるのかということも伺えたらと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-020"},{"speaker":"鈴木委員","kind":"質問・要望","question":"何というのですか、何件でもぜひやめていただきたいというようなことは、ちょっと要望として述べておきたいと思います。何か次に区として進む法的措置などのことも含めて、そのようなことというものがあるのか、その点はいかがか尋ねました。","respondent":"山下国保医療年金課長","answer":"現状も、今回条例提案を申し上げているものは、公示送達後の効果というところで法的な効果は今の運用とも変わらないところです。ご連絡いただければ還付の手続をご案内するということで、法的な効果といいますか、運用上はそのように対応してまいります。","id":"exchange-021"},{"speaker":"鈴木委員","kind":"意見","question":"そのようなものは本人にとってもメリットなので、すごくプラスの部分だと思うのですけれども、督促など、そのようなところで進むことというものは何かあるのか、その点もお聞かせいただけたらと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-022"},{"speaker":"鈴木委員","kind":"質問・要望","question":"それは分かっているのだけれども、だから今までのところでの公示送達の中で、公示送達をすることで督促状を出したことの、その次に何か進むことというものはないのかということだけをちょっと、確認をさせていただきたい。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-023"},{"speaker":"あくつ委員","kind":"確認","question":"もう１回確認なのですけれども、名前があって、そういったものを貼っていた。今回のインターネットでの公示というものは、種類も掲示しないし、住所も掲示しない、名前を掲示する、このような認識でいいのか尋ねました。","respondent":"山下国保医療年金課長","answer":"分かりづらい説明になりまして申し訳ございませんでした。引用できるようなもの、少し婉曲的にはなるのですけれども、こういった内容が出ていますよということをお伝えできるように努めてまいる考えです。","id":"exchange-024"},{"speaker":"吉田委員","kind":"質問","question":"すみません。どうも私には効果があまり、どこかで効果測定などはされると思うのですが、その辺についてはいかがか尋ねました。","respondent":"山下国保医療年金課長","answer":"地方税法の改正ということに基づきまして、税の所管や、私ども国保の所管でいう後期高齢者のほうの条例改正ということで手続をしているところです。広く皆さんにお気づきいただける機会になるものと捉えてありますので、効果としては大きくなりますけれども…","id":"exchange-025"},{"speaker":"吉田委員","kind":"質問・要望","question":"返金いたしますので口座を教えてくださいということがあって、ですから、ちょっとそれがどうなるのということはすごく思うのです。少し難しいのではないかなと思うのですけれども、ちょっと今の実感として、何か見解があれば教えてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-026"},{"speaker":"吉田委員","kind":"質問","question":"答えようがない。やってみなければ分からないということか尋ねました。","respondent":"山下国保医療年金課長","answer":"先ほど来申し上げている、デジタル化することでその一部、少しでも一歩踏み出せるのではないかというようなところが発想としてございました。一定ご利用いただくことで今後効果が生まれていくよう、適切な運営、運用ということに努めてまいりたいと考えています。","id":"exchange-027"},{"speaker":"やなぎさわ委員","kind":"質問","question":"現時点で年間３０件から４０件ぐらい、区役所の掲示板に公示送達出しているということですけれども、実際、何だろう、直接本人から問合せが来るというものは年間どれぐらいの件数なのか尋ねました。","respondent":"山下国保医療年金課長","answer":"実際にその公示送達を見たということでご連絡いただくということは、必ずしもあるわけでございません。お問合せいただく中で手続に進んでまいりますので、何人の方がその状況を把握されたかというところを把握しているものではございません。","id":"exchange-028"},{"speaker":"やなぎさわ委員","kind":"質問","question":"そうなると、先ほど説明のときには一定の効果があると受け止めているというお話だったと思うのですけれども、それこそどうやってその効果をはかるかということは非常に難しいかなと思うのですが、その辺はいかがか尋ねました。","respondent":"山下国保医療年金課長","answer":"先ほど別の委員のご質問にもご答弁申し上げましたとおり、紙で掲示をしていたものがインターネットでも閲覧できる。今までは１つの方法だったものが２つに、方法として、手段として増えますので、そういったところでは１つ前進をしていくものと捉えてあります。","id":"exchange-029"},{"speaker":"鈴木委員","kind":"意見","question":"本当に後期高齢者医療のホームページに掲載しても、高齢者が気づくという人がなかなかいないのではないかなと。効果の面でどうかというようなこともありますし、やはりプライバシーの侵害に当たるのではないかというところで、反対ということですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-030"},{"speaker":"やなぎさわ委員","kind":"意見","question":"氏名が載ってしまうというリスクをてんびんにかけたときに、やはりこの条例は適さないのではないかなと判断しました。反対ですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-031"}]},{"id":"topic-06","title":"第４８号議案、指定管理者の指定","agenda":"第４８号議案、指定管理者の指定","exchanges":[{"speaker":"鈴木委員","kind":"質問","question":"生活介護６２％、就労継続支援Ｂ型が５８％というところで、その点ちょっと伺いたいと思います。令和６年度は四億八千何百万円という感じだったと思うのですけれども、約５億円近い額となっていると思うのですが、伺えたらと思います。","respondent":"松山障害者支援課長","answer":"は報告書の選定予備委員会の中で議論されたところについて説明を申し上げます。今おっしゃられたように約５億円となっておりますが、今後の拡充の状態に合わせて、毎年指定管理者との協議ということになります。","id":"exchange-032"},{"speaker":"鈴木委員","kind":"質問・要望","question":"１のところで、出していただきたいという要望を出しているところなのですが、そのようなことがあればお聞かせいただけたらと思います。それからあと、ここで８ページの２つ目の黒丸のところで、されているのであればどの程度なのかということについても伺えたらと思います。","respondent":"松山障害者支援課長","answer":"障害の重度化に対応するとともに安全性に配慮する、重症心身障害児者や医療的ケアを必要とする身体障害者に対して受入体制の準備を進めていくです。１８人の方がトライしたということですけれども、まだ途中段階でありまして、今努力している最中です。","id":"exchange-033"},{"speaker":"鈴木委員","kind":"確認","question":"何というのですか、そこのところでの送迎ということで確認させていただいていいのか、ちょっとその点お願いします。","respondent":"松山障害者支援課長","answer":"日中一時支援の家族懇談会での施設長の例を出した発言から、不安になられた方がいらっしゃいますけれども、現実的には個別送迎を行っているです。その確認をさせていただいたものです。","id":"exchange-034"},{"speaker":"吉田委員","kind":"質問・要望","question":"生活者ネットワークとして要望を出しているものが、どこかでやってほしいのですが、教えてほしいと求めました。","respondent":"松山障害者支援課長","answer":"指定管理制度の中で、労働環境チェックは３年目に実施しております。","id":"exchange-035"},{"speaker":"吉田委員","kind":"質問・要望","question":"社会保険労務士を入れてのチェックという理解でよろしいでしょうかということが１つと、ご利用者のご要望が多いということは大変承知をしております。その点で伺っているのですけれども、その点についていかがか尋ねました。","respondent":"松山障害者支援課長","answer":"指定管理制度の中で３年目に行う労働環境チェックは、社会保険労務士が行っております。","id":"exchange-036"},{"speaker":"吉田委員","kind":"質問・要望","question":"それで、その結果適正な、だから送迎の要望にも十分堪えられるような労働環境であるということを確認した上での、次の指定管理者として継続するという理解でよろしいか尋ねました。","respondent":"松山障害者支援課長","answer":"特に送迎ということで特化したものではございませんで、適正な労働環境の下で適切かつ安定的な履行が確保されるよう、指定管理者の従業員の労働関係法令の遵守に関わる評価を実施したというものです。","id":"exchange-037"},{"speaker":"吉田委員","kind":"質問・要望","question":"分かりました。やはりできる限り利用者のご要望には応えるべきだと思うのですけれども、その辺については継続して、これは要望にとどめておきます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-038"},{"speaker":"やなぎさわ委員","kind":"提案","question":"３ページのところですけれども、以前の選定の報告書だと大体提案内容と財務評価のようなもので２つに分かれて点数が出ていたと思うのですが、内訳というものはどのようになっていますか尋ねました。","respondent":"松山障害者支援課長","answer":"内訳は福祉部の内訳と一緒ですので、変更はございません。","id":"exchange-039"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"では内訳は一緒であるとして、そのうちの、例えば財務の評価というものはどれぐらい、何点満点中何点などということで、把握しているようであれば教えていただきたいです。","respondent":"松山障害者支援課長","answer":"財務に関しては、公の施設の管理を安定して行う物的能力および人的能力を有しているものであること、そこで評価をしております。福祉部で、総合得点でしか特に評価をしておりませんので、財務が高くほかが低いということではありませんということを申し上げます。","id":"exchange-040"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"最低限の財務の点数の基準のようなものは設けるべきだなというようなことでありまして、健全性というか、が判断できるのかなと考えております。そのような意味で、もし今後改善など検討できるようであれば、ご意見をいただきたいのですけれども。","respondent":"松山障害者支援課長","answer":"ご意見としては承ります。統一して表記については考えてまいります。","id":"exchange-041"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"ぜひ、その点は前向きにご検討していただきたいというふうに強く要望したいと思います。一応１つ確認ですけれども、やはり前任の法人に比べて、確認でお願いします。","respondent":"松山障害者支援課長","answer":"あわせて、地域住民を招いたぐるっぽ祭り等々、町会との良好な関係づくりに取り組んでいることが評価されていた。成果指標としては、施設やサービス全体に関する満足度が８割を超えており、総括では優良との評価を受けているというところが結果となります。","id":"exchange-042"},{"speaker":"あくつ委員","kind":"質問・要望","question":"本当によくお伺いしたり、女性が１人でも入りやすいというか、誇張もないなというところです。いろいろあった中での交代ですから、その辺りについて、区で調整ができるところがあるのであればぜひ調整していただきたいなと。","respondent":"松山障害者支援課長","answer":"委員ご指摘の１２月の笠原シェフのみんな食堂の件ですが、より積極的にぐるっぽのよさをＰＲして、さらに地域に根差した施設運営を目指してまいります。","id":"exchange-043"}]},{"id":"topic-07","title":"第４９号議案、東京都後期高齢者医療広域連合規約の変更","agenda":"第４９号議案、東京都後期高齢者医療広域連合規約の変更","exchanges":[{"speaker":"鈴木委員","kind":"質問","question":"この後期高齢者のところでちょっと伺いたいのですが、この１万６,０４４円というものは、過去最大の値上げなのではないかなと思ったのです。それが更新されるということなのか、ちょっとその辺の値上げの増の部分についての状況をお知らせいただけたらと思います。","respondent":"山下国保医療年金課長","answer":"今ご説明申し上げましたように、令和８・９年度の最終案のほうは１４.４％の増という形で、令和６・７年度と比してそのような数字となっています。先ほどご説明申し上げましたように、特別対策の実施、今回規約で変更をお願いしているものと。","id":"exchange-044"},{"speaker":"鈴木委員","kind":"意見","question":"今までが六・何％のものが１４.４％というと、２倍近いぐらいの割合の負担増なので、本当にこれはちょっとひど過ぎる。でも、今日はそれの賛否がどうのということの場ではないので、ここではそれは申し上げませんがとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-045"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"賛成なのですけれども、やはり制度の抜本的な見直しを、区から国に対して強く求めていただきたいということは申し添えておきます。賛成です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-046"}]},{"id":"topic-08","title":"第５１号議案、品川区国民健康保険条例の一部を改正する条例","agenda":"第５１号議案、品川区国民健康保険条例の一部を改正する条例","exchanges":[{"speaker":"鈴木委員","kind":"質問・要望","question":"令和６年のときが、前年度に比べて１万３,９６１円で、これを１点確認させてほしいと求めました。特別区長会としては、これだけ自分たちが、過去最大の値上げになるということに対してどう考えているのかということについて伺いたいと思います。","respondent":"山下国保医療年金課長","answer":"百分率としては６.９７％ということでしたので、率としては、この中でいうと２番目というところに続いているものです。複数年度にわたって要望を続けているところでございまして、引き続きこういった要望を続けていく必要があると受け止めてあります。","id":"exchange-047"},{"speaker":"鈴木委員","kind":"質問・要望","question":"引き続き要望していきますというように、何というのですか、何というのですか。収入のない子どもに国民健康保険料を取りながら、私は制度の矛盾ではないかなと思うのですけれども、その点はいかがか尋ねました。","respondent":"山下国保医療年金課長","answer":"少しずつではありつつも歩みを進めていく、やはり要望を引き続き行っていくということの大事さが出ているところかなと考えているところです。令和８年度から開始される子ども・子育て支援金制度につきましては、１８歳未満の被保険者に係る、そういったことで認識をしています。","id":"exchange-048"},{"speaker":"鈴木委員","kind":"質問・要望","question":"そのような点では、本来子どもから国民健康保険料は取るべきではないというところで、無償化にしていくというところを求めていただきたい。そうあるべきなのではないかと思うのですけれども、その点はいかがか尋ねました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-049"},{"speaker":"鈴木委員","kind":"質問・要望","question":"そのようなことも含めて答弁していただきたいのです。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-050"},{"speaker":"鈴木委員","kind":"提案","question":"そのようなところもぜひ提案もしていただきたいですし、それを無償化するには１億５,０００万円あればできるというご答弁もありました。品川区のほうから言っていただいて、２３区で統一してやろうということの提案をしていただきたいということと、品川区独自にもとの意見を述べました。","respondent":"山下国保医療年金課長","answer":"収納率の向上、法定外繰入れを常に使っていくということを前向きに捉えるような形で進めていくことは、なかなか難しいところがあります。東京都内というところで進めていく中では…","id":"exchange-051"},{"speaker":"鈴木委員","kind":"質問","question":"だから本当に、そのようなことをさらに助長してきたものですから、本当に本来あるべき姿から逆行するようなやり方を国民健康保険で取ってきたために。これ１０回払いなので、１か月６万４,０００円も払うという、私たちは本当に胸に落として理解をしておくことが必要だなと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-052"},{"speaker":"吉田委員","kind":"質問","question":"国民健康保険、現に保険料が払えなくなるような人たちが続出していて、結果として皆保険にはなっていないのではないかということがあるのです。現在、その辺の数字の把握や品川区の現状など教えてほしいと求めました。","respondent":"山下国保医療年金課長","answer":"生活状況調査ということでご提出いただいたもの等を踏まえて、各月で納付いただける金額や、その後の保険料納付の計画というものを立ててまいります。これまでも努めてきているところですし、今回も、引き続きそのような納付相談については注力してまいりたいと考えています。","id":"exchange-053"},{"speaker":"吉田委員","kind":"確認","question":"そのようなことについて、区としては、全体としての制度から漏れているような人たちも含めての把握というものはされていないのでしょうか。改めて確認させてください。","respondent":"山下国保医療年金課長","answer":"都度都度、基本的なスタンスとしては、国民健康保険に入られていない方は何かしらの被用者保険に入られている方だというような形で認識をしています。保険料というものは、保険制度ですのでお支払いいただく必要があると認識していますけれども、対応に努めているところです。","id":"exchange-054"},{"speaker":"やなぎさわ委員","kind":"確認","question":"確認なのですけれども、子ども・子育て支援金なのですが、段階的に上げていくというような話も聞いておりますけれども、要は、今の金額よりも今後上がるのか、そういった予定についてお伺いしたいです。","respondent":"山下国保医療年金課長","answer":"実態上はこども家庭庁のほうから示されるところの子ども・子育て支援金制度の仕組みにつきましては、令和１０年度は１兆円というように。」と答弁訂正あり〕そちらについては社会保険負担軽減と相殺して、制度として維持をしていきたいというようなところで…","id":"exchange-055"},{"speaker":"やなぎさわ委員","kind":"確認","question":"要は、今はある意味６割で、２年後には１０割にいくということだと思うのですが、確認できました。そもそも子育て支援金、矛盾した状況のような気がするのですが、その辺についてはいかが受け止めていらっしゃいますか尋ねました。","respondent":"山下国保医療年金課長","answer":"子ども・子育て支援納付金の賦課額につきましては、賦課はされるのですが、制度上のその部分の矛盾というものは生じないかなと考えています。７３円ずつ均等割額に加算されるというようなところで、制度…","id":"exchange-056"},{"speaker":"やなぎさわ委員","kind":"確認","question":"確認しました。大丈夫です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-057"},{"speaker":"鈴木委員","kind":"質問・要望","question":"求めているという状況にもかかわらず、私は自治体自らが矛盾に対して対策を取らず、逆行するという状況になっていると思います。子どもの国民健康保険料は２３区統一で無償化すべきだと思いますし、少なくとも区独自に無償化すべきだと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-058"},{"speaker":"吉田委員","kind":"意見","question":"今品川区の場合は、やはり品川区としての公費の投入というものは避けられないのではないか、それが皆保険の仕組みの維持につながると思います。このたびのこの案については、それと矛盾するということで反対をいたしますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-059"},{"speaker":"やなぎさわ委員","kind":"意見","question":"１.５億円でできるというところもありますし、これを１００％にしてもうなくすというのではなくて、むしろやはり維持してほしいと思います。２０２６年から１１０万円に上限がなると思いますけれども、今税収も増えているというところで、ぜひ行ってほしいなと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-060"}]},{"id":"topic-09","title":"令和８年陳情第３号、「労働」ではなく質の高い「訓練」のサービス提供ができる就労継続Ｂ型事業所を誘致・育成するよう、区に求める陳情","agenda":"令和８年陳情第３号、「労働」ではなく質の高い「訓練」のサービス提供ができる就労継続Ｂ型事業所を誘致・育成するよう、区に求める陳情","exchanges":[{"speaker":"吉田委員","kind":"質問・要望","question":"タクシー券は、結構基準厳しいのではないですか。教えてほしいと求めました。","respondent":"松山障害者支援課長","answer":"交通費と工賃のみを比較するものではないということをご説明申し上げました。交通費と工賃のみを比較するものではないと考えております。","id":"exchange-061"},{"speaker":"吉田委員","kind":"質問","question":"自分の能力という言い方はどうなのでしょうか、それからやっている場所とご自宅の間、どうしても行かなければいけないわけです。そのときに、その１つに、やはり往復の送り迎えか、交通費というものはどうしても必要なのではないかと思うのですけれども、いかがか尋ねました。","respondent":"松山障害者支援課長","answer":"就労継続支援Ｂ型のモチベーションアップということについてのご質問かと思われます。交通費については、労働であれば必ず交通費が伴うものと考えておりますけれども、今後ご意見を伺いながら検討してまいりたいと考えております。","id":"exchange-062"},{"speaker":"吉田委員","kind":"質問","question":"交通費の支給が労働意欲のアップにつながるかどうかは、交通費がないということが、そこに通う意欲をそぐことにどうしても私はなると思います。絶対通ってほしいと思っていらっしゃるに違いないと思うのですが、それでも通うべきだとお思いになるのか、その辺について改めて伺いたいと思います。","respondent":"松山障害者支援課長","answer":"先ほど申しました地域自立支援協議会で就労支援部会がありますので、そちらのほうで事業者から意見を吸い上げて、どのようにモチベーションアップを図っていくかというところについては、今後研究してまいりたいと考えております。","id":"exchange-063"},{"speaker":"吉田委員","kind":"質問・要望","question":"本会というのですか、これはいい議論だったということで結構なので、教えてほしいと求めました。","respondent":"松山障害者支援課長","answer":"そうですね。就労支援部会や区に寄せられるご意見としましては、今、利用者のニーズに合ったような事業者を誘致していきたいと考えております。","id":"exchange-064"},{"speaker":"吉田委員","kind":"提案","question":"私、たしか区のほうの障害者雇用の一般質問をしたときに、共同受注の仕組みというものは有効なのではないかというように提案したと思います。たしか２つぐらいは、何ですか、その跡地でやっている事業の中で……との意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-065"},{"speaker":"吉田委員","kind":"質問・要望","question":"Ｋｉｔａｒａですか。なかなか共同受注というものは難しいかと思うのですけれども、どのような受注の仕組みになっているのか教えてほしいと求めました。","respondent":"松山障害者支援課長","answer":"最後のほうに、当該生産活動により一般就労に必要な能力向上が見込まれるか、それにより安定した生産活動収入を得ることができるか等々。１か所の事業所では対応できないために、手挙げしたところに参入していただいて納入したという実績について…","id":"exchange-066"},{"speaker":"吉田委員","kind":"提案","question":"まだまだスタートしたばかりかなと思いますので、今後その受注の仕方がふさわしいかどうかということは検証していってほしいと求めました。それとも自立支援協議会での議論を待つべきなのか、ちょっと私には判断がつかないのですが、その辺についての見解を伺いたいと思いますとの意見を述べました。","respondent":"松山障害者支援課長","answer":"それから次ですけれども、定員は少なくなっておりませんで、就労継続支援Ｂ型としては、増えている状況です。今後、午前中お話ししました就労選択支援のサービス事業所がおりますので、障害者の方ご本人と一緒に考えるような形をしながら支援してまいります。","id":"exchange-067"},{"speaker":"吉田委員","kind":"質問・要望","question":"ちょっと制度が始まったばかりで、どれくらいそのご要望に応えられるかは、ぜひその辺については今後もいい方向に行っていただきたい。その辺についての状況把握や、生活介護での作業というか、そのようなことについての今後の見解があれば伺いたいと思います。","respondent":"松山障害者支援課長","answer":"委員がお尋ねの生活介護での作業についてですけれども、生産活動として取り組んでいるところもありますし、ご本人のご希望がまず第一で、そのご本人のご希望に沿ってどのようなプログラムを提供するかですので、またそれは事業者とともに研究してまいります。","id":"exchange-068"},{"speaker":"吉田委員","kind":"質問・要望","question":"今後もきちんとした生活介護および就労継続支援Ｂ型という事業を進めていってほしいと求めました。これは強く要望しておきます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-069"},{"speaker":"鈴木委員","kind":"質問・要望","question":"前回の１１月５日の陳情審査のときに、２２５人が使われていたのではないか、活用されていたのではないかというような状況なのです。今交通費がかかっている方がどれくらいいるのかということを私も質問したときに、区のほうとしては、その点はいかがか尋ねました。","respondent":"松山障害者支援課長","answer":"交通費の把握についてのご質問です。自立支援協議会の就労支援部会の中でも、また委員のご提案も含めまして、就労支援部会のほうで検討してまいりたいと考えております。","id":"exchange-070"},{"speaker":"鈴木委員","kind":"質問・要望","question":"今の時点で、これがどうなっているのかということは、区としては把握をされていないでしょうかということです。区としては、それをどのような形で増やしていくというようなところがあるのか、その点のお考えがあったら伺いたいと思います。","respondent":"松山障害者支援課長、佐藤障害者施策推進課長","answer":"２３区の状況についてですが、特に交通費に対して課題であるという認識をしていないので、把握しておりません。 就労継続支援Ｂ型の必要量というところのご質問ですが、それから見込み量であったり、事業所の誘致や区の施設の整備というようなところも検討していっているようなところです。","id":"exchange-071"},{"speaker":"鈴木委員","kind":"質問・要望","question":"就労支援部会で同じようなことでやっているということなのですけれども、就労支援部会に参加している事業者というものはどれくらいあるでしょうか。そのような形で就労継続支援Ｂ型もあると、もっと質的にも向上していくのかなという思いがあるのですけれども、その点いかがか尋ねました。","respondent":"松山障害者支援課長","answer":"就労支援部会の中で、就労継続支援を主に検討するグループと就労移行支援、企業向けの就労を検討するグループと分かれて検討をしています。年に３回以上顔を合わせる機会がありますので、そちらのほうでやっていきたいと思います。","id":"exchange-072"},{"speaker":"やなぎさわ委員","kind":"質問","question":"質の高い訓練というところでお伺いしたいのですけれども、生産活動の適切性というところの不適切な事例としてｅスポーツが入っていると思うのです。何ですか、お考えや受け止めがあれば伺いたいのですけれども、いかがか尋ねました。","respondent":"松山障害者支援課長","answer":"先ほどもご説明しましたように、その後が以下の観点、根拠条項等を踏まえて詳細に確認することということです。具体的な生産活動の場面があるか、当該生産活動により一般就労に必要な能力向上が見込まれるか、幾つかの観点から確認することとなっております。","id":"exchange-073"},{"speaker":"やなぎさわ委員","kind":"質問","question":"何ですか、新しいというか、取組をやっている事業所ですということを１つうたい文句にして求人をかけている。実際具体的な生産活動という話もありましたけれども、もし区として何か事例として把握しているものがあればということでお伺いしたです。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-074"},{"speaker":"大倉委員","kind":"質問・要望","question":"すみません。その辺の、あとは就労継続支援Ｂ型の空きがない状況などというものが把握されているのかなということが分かれば教えていただきたいです。","respondent":"松山障害者支援課長","answer":"就労継続支援Ｂ型については、空きがない状況ではありません。ただし、実際のご希望する作業とマッチするかどうかということ、全ての方のご希望にかなえられない状況があることは事実です。","id":"exchange-075"},{"speaker":"大倉委員","kind":"質問・要望","question":"分かりました。どのくらいあるのか教えていただきたいということと、ちなみに空きがあるような作業の内容などは、どのようなものがあったりするのか尋ねました。","respondent":"松山障害者支援課長","answer":"例えばぐるっぽのカフェレストランは、最初定員２０名で設定していましたが、令和６年度末で８人です。やってみたいというメニューが多くなれば、その事業者にまた複数展開をしていただくようなことはお伝えはしております。","id":"exchange-076"},{"speaker":"えのした副委員長","kind":"質問","question":"動画作成や音楽作成ですか、サービスメニューも伝えて、事業者の誘致をされている。何というのですか、ああ、増えているなということを実感しているところであります。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-077"},{"speaker":"大倉委員","kind":"質問・要望","question":"様々選択肢が多いほうがいいということではあると思いますので、そうした選択肢を増やしながら取り組んできているということでありました。就労継続支援Ｂ型の必要量など、この辺ぜひ区としても進めていっていただきたいなと思うものの、不採択でお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-078"},{"speaker":"あくつ委員","kind":"質問・要望","question":"先ほど課長もはっきりと定員は減少していないということのご説明があって、ただマッチングの問題はありますけれどもというところはありました。マスク等の作成ですか、ある意味これから注視をしていっていただきたいなと思いますが、現状では不採択ということでお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-079"},{"speaker":"鈴木委員","kind":"質問・要望","question":"できれば私は就労継続支援Ｂ型全体の事業所も含めた形でのレベルアップというようなところでも取組を進めていただきたいと思っています。そのようなことなので、ぜひこのような趣旨で取組を進めていただきたいということで、採択をお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-080"},{"speaker":"吉田委員","kind":"質問・要望","question":"その辺の言い方はちょっと不適切だったら修正していただきたいと思うのですけれども、直接ご意見を伺うのでも、やはり交通費のことが多いのです。その他、やはりさらに進めるためにも、この陳情は採択としたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-081"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"やはり働く場を提供する福祉サービスということである以上、交通費の助成は行われるべきだと思います。委員会含めて様々議論を深めて、ぜひ実現に向けて動いていただきたいなと、そういった思いで採択をします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-082"}]},{"id":"topic-10","title":"令和８年陳情第４号、２３区最低の障害者福祉から脱却するために、小山７丁目障害者グループホームの公平公正な入居選考を区に求める陳情","agenda":"令和８年陳情第４号、２３区最低の障害者福祉から脱却するために、小山７丁目障害者グループホームの公平公正な入居選考を区に求める陳情","exchanges":[{"speaker":"吉田委員","kind":"質問・要望","question":"一発で解決することだと思うのですけれども、それが一応一番公平な形かなと思うのですが、区からそのようなものは求めないのでしょうか。ぜひ求めてほしいと求めましたし、その選考基準を見れば、その点についてまず伺いたいと思います。","respondent":"佐藤障害者施策推進課長","answer":"先ほどご説明させていただいたとおり、準備、調整を進めているというところで伺っているというような現状です。","id":"exchange-083"},{"speaker":"吉田委員","kind":"質問・要望","question":"そうすれば、本当に公平公正かどうかも一発で判断できるわけです。それを求めることは当然ですし、なぜ選考基準を事業者に公表を求めないのか、その辺について伺いたいと思います。","respondent":"佐藤障害者施策推進課長","answer":"その選考方法について協議、入居の基準自体を最終的に公表するという形については、事業者のほうの判断で行う形かというように認識しております。どのようにされるかということは申入れもしておりますので、そのようになったかどうかという形に関しては確認はしてまいります。","id":"exchange-084"},{"speaker":"吉田委員","kind":"質問・要望","question":"このようなメリット、事業者としての公平性を示すことになりますよということで求めることはなぜできないのか、ぜひそれをやっていただきたい。では拒否の理由もきちんと聞き取って、せめて厚生委員会には説明していただきたいのですけれども、その点についていかがか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"今後も今調整中の部分、準備中の部分もありますので、確定した部分についても確認はきちんと取ってまいります。内容についてはきちんと確認してまいりますし、運営する事業者を選定するところにおいて、そういった部分についてはきちんと確認をしてまいります。","id":"exchange-085"},{"speaker":"吉田委員","kind":"質問・要望","question":"区として使用貸借という形かもしれないけれども、経済的な支援をしていることになるわけだから、それをぜひ求めてほしいと求めました。本当に事業者の言うとおり支援区分５・６の人たちを入居させるということであれば、その点についていかがか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"スプリンクラーの設置というようなところで制度的にあるわけですけれども、スプリンクラーについては設置が必須というような形になってくるようなところで、この部分について支援区分に応じた入居者のところについては配慮しているというようには認識しています。","id":"exchange-086"},{"speaker":"吉田委員","kind":"質問・要望","question":"本当に支援区分の重い人を入れていますよということを明らかにするためにも、選考基準などというものを区として求めることは当然だと思います。これはもう不誠実なやり方としか言いようがないかなと思うのですが、この事実については、どのようにお考えか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"入居選考の選考基準等につきましては、まずは事業者のほうでどのような形で出されるかといったところを確認してまいりたいと考えています。入居の説明会、それから面談等行ってまいりますので、そういったところで適切に対応するよう事業者にも確認をしていきたいと考えておりま…","id":"exchange-087"},{"speaker":"吉田委員","kind":"質問・要望","question":"区の資産といっても結局は区民の資産なわけですから、そこは強く求めていってほしいと求めましたし、何というか。そのようなことについては、やはり事業者に一定の義務というものは求めてしかるべきかなと考えています。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-088"},{"speaker":"鈴木委員","kind":"質問","question":"１つ、ここの施設は区分４以上が８割以上になる、そのような施設ということで考えていいのでしょうか。そして、そうなったときの職員体制というものはどのような状況になるのか、その点についても説明を求めました。","respondent":"佐藤障害者施策推進課長","answer":"応募等受けてまいりますので、基本的には、そこに配慮した形での入居選考等を行っていくというような認識になりますというところになります。常勤５名、非常勤５名程度を目安に、開設に向けて準備を進めているというようなところで聞いております。","id":"exchange-089"},{"speaker":"鈴木委員","kind":"質問","question":"常勤５、非常勤５の内、どのような専門職が何人なのかということも教えていただけたらと思います。そうした場合の職員配置というものもどうなっていくのか、そのような施設の仕様になっているのか、その点についても説明を求めました。","respondent":"佐藤障害者施策推進課長","answer":"施設のほうとしましては、医療的ケアの対応が積極的にできるような状況ではないというところになります。知的障害者対応のグループホームで想定される形の介護福祉師等について、事業者のほうで準備を進めているというように聞いているところです。","id":"exchange-090"},{"speaker":"鈴木委員","kind":"質問・要望","question":"４月に説明会では、その点はどう考えられるのか、もっと早くにできないのかということを伺いたいと思います。何というのですか、支障があるのかどうなのか、その考え方についても伺いたいと思います。","respondent":"佐藤障害者施策推進課長","answer":"こちら順を追いますと、４月に説明会をさせていただいて、もしくは体験等が開始するというようなところで設定しているというようになっております。入居の選考方法等について検討したところで、こちらの整備の案件につきましては、このようにさせていただいたところです。","id":"exchange-091"},{"speaker":"鈴木委員","kind":"質問・要望","question":"土地を無償で貸すわけですから、それは品川区がこうやってくださいというように言うことは、権限は十分あると思うのです。それに応えて、公開はぜひするようにということを区が求めるべき、その辺の考え方についても改めて伺います。","respondent":"佐藤障害者施策推進課長","answer":"申込み等を検討いただいてというところで、４月に説明会、そこに入居の方が随時決まっていくというようなところで予定しています。公平公正だというところが確認できるような形で、外向きにお出しできるように申し入れ、検討はするように努めてまいりたいと思います。","id":"exchange-092"},{"speaker":"鈴木委員","kind":"質問・要望","question":"何というのですか、６月という、そのような設定だと思うのです。そのような説明会というものを、戸越四丁目のところにはこのような形でぜひ進めていただきたいと思うのですけれども、最後いかがか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"おっしゃったように４月説明会というところですが、相談支援事業所などや連絡会等について、周知というようなところは考えているところがあります。今回の状況を踏まえまして、よりよく皆さんに情報が伝わるように、見直しというものは進めていきたいと考えております。","id":"exchange-093"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"それは求めるという前提でお伺いしますが、そういったところをしっかりと確認して、ということはお約束していただけるか伺います。","respondent":"佐藤障害者施策推進課長","answer":"こちら当然都の整備補助というような部分については、制度で決まっているところあります。支援区分の目安としての入居の人数等も聞いているところありますので、入居の状況、報告は続けていきたいと考えております。","id":"exchange-094"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"確認できました。今この１.２という数字がどれぐらいなのかということが、少し分かればお教えていただきたいのですが、いかがか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"こちら調査したのは多分令和６年９月で、実際のこの数字の根拠自体は令和５年の数字ということで調査されたのかなというところで認識しています。申し訳ありません、支援区分６というものはなかなか、ここについては増えていくというようなところで進めているところです。","id":"exchange-095"},{"speaker":"やなぎさわ委員","kind":"質問","question":"恐らく７名や８名ぐらいの入居だったと記憶しておりますので、そう考えると、区のほうでされているということでよろしいでしょうか。グループホームについて。","respondent":"佐藤障害者施策推進課長","answer":"グループホームにつきましても、今回区で整備を予定している案件、これでニーズが満たされたということではないということは感じているところです。日中サービス支援型や新たな類型のところも含めて、民間の誘致も含めまして、検討してまいりたいと考えているところです。","id":"exchange-096"},{"speaker":"やなぎさわ委員","kind":"確認","question":"課題を持っていただけるというところは確認できました。ぜひ積極的に進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-097"},{"speaker":"あくつ委員","kind":"質問・要望","question":"今回の陳情の趣旨である公平公正な入居選考を行うよう求めてくださいというところについては、区のほうで十分に求めているという認識を受けましたが。これいろいろな条件の下でつくってしまったものはどうすればいい、品川区としてはどのような対応を取るのかだけ、最後確認させてください。","respondent":"佐藤障害者施策推進課長","answer":"最大限障害の重い方等には配慮して進めていくですので、対応の是正等も含めて、区のほうとしましては進めていきたいです。","id":"exchange-098"},{"speaker":"えのした副委員長","kind":"質問・要望","question":"とはいえ、区は事業者に対して、公平公正に利用者との面談や、もちろん中重度の方も入れるように求めております。利用者に対しても地域でも、住民説明会をこれからもしていくということですし、支援区分も考慮に入れて選考を求めていくということです。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-099"},{"speaker":"大倉委員","kind":"質問・要望","question":"本日結論を出すということで、不採択でお願いいたします。委員間でしているものを伺った中で、入居者選考基準についてはしっかりと区のほうにも提示を求めるし、不採択ということでお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-100"},{"speaker":"あくつ委員","kind":"確認","question":"内容については先ほど確認させていただきましたが、先ほど私の課長のご答弁では、そのように受け止めさせていただきました。そのような意味では、陳情の趣旨の入居選考基準を作成するというところは沿えないというところで不採択というようにします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-101"},{"speaker":"鈴木委員","kind":"質問・要望","question":"４月ということで決まってしまっているのであれば、４月すぐにやっていただきたいということで、お願いをしておきたいと思います。そして重度の方がしっかりと入れるような、そのようなグループホームにしてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-102"},{"speaker":"吉田委員","kind":"質問・要望","question":"やはり区が選考にも責任を持つということで選考基準は持つべきですし、事業者がということであれば、公表をさせるべきだと思います。支援になるのか分かりませんが、区としてもしっかり見ていっていただきたいということは要望して、採択を主張したいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-103"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"区が関与していただけるということは確認できましたけれども、やはり基準を公表するということが一番シンプルだと私も思います。もちろん区としても様々な条件をつけたり、要望を出したりということはしなければいけないというか、すべきことだと考えております。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-104"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/784410?Template=document&Id=7317#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=7&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":85660,"voices":360}},{"id":"r08-20260224-8","meetingId":"r08-1t","date":"2026年2月24日","dateIso":"2026-02-24","committee":"建設委員会","time":"午前１０時００分～午後 ２時２１分","status":"正式会議録","sourceType":"formal","overview":"建設委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を66件整理しています。","topics":[{"id":"topic-01","title":"第３４号議案 品川区建築物不燃化促進助成条例の一部を改正する条例","agenda":"第３４号議案 品川区建築物不燃化促進助成条例の一部を改正する条例","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"これらの３つの施策について、都市防災不燃化促進事業だけが条例として建設委員会に出てきているのはなぜなのか、伺いたいと思います。","respondent":"小川木密整備推進課長","answer":"こちらは推測にはなるところですが、本事業は建物の不燃化促進の先駆けの事業となってございまして、昭和６２年から事業を開始しています。そのほかの不燃化特区制度、あと耐震化事業のほうに関しましては、要綱で定められているものです。","id":"exchange-001"},{"speaker":"中塚委員","kind":"質問","question":"昭和６２年から始まっているということですけれども、事業対象の目的が、広域避難場所の安全確保と延焼遮断帯の形成ということです。そうではなく、広域避難場所の安全確保や延焼遮断帯の形成に事業を集中している理由は何かということを伺いたいと思います。","respondent":"小川木密整備推進課長","answer":"やはり広域避難場所、戸越公園はやはり火災対策、そして一時的な避難場所といったところで、まずは広域避難場所の安全性を確保する。都市計画道路と補助２９号線等の沿道は、この都市防災不燃化促進事業、そして助成支援を行っていくものです。","id":"exchange-002"},{"speaker":"中塚委員","kind":"質問","question":"この理由を資料で挙げているのであれば、区内全域で防災性・安全性を高めていくという事業にしない理由は何故か、そこを伺いたいと思います。恐らく区内全域に広げていくと、補助金の関係だけの判断なのか、それ以外にも理由があるのであればお伺いしたいと思います。","respondent":"小川木密整備推進課長","answer":"まずは区内全域ではなくて優先度を設定して、まずは危険度の高く、役割がある地区から順番に助成支援を行っていきたいというところで考えてあります。あくまでも補助金等の、そういったところの観点での取組としての考え方ではございません。","id":"exchange-003"},{"speaker":"中塚委員","kind":"質問","question":"広域避難場所に避難しようというのが現状の防災計画ですから、相当な被害の拡大の状況だと思います。こうして品川区は進んでいるわけですから、まずそこを安全にするという考えは持ちながらも、意見を述べておきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-004"},{"speaker":"ゆきた委員","kind":"確認","question":"お話を伺った方がどのように受け止めるかというのはあると思うのですけれども、ご家族などにも周知していくというところが大事なところだと思います。ここへのアプローチの仕方というのはどういうふうに考えているのか、この１点だけご確認させてほしいと求めました。","respondent":"小川木密整備推進課長","answer":"それとはまた別に福祉部署と連携しまして、こういった事業に令和８年度から取り組むという形で、しっかりと案内等させていただきたいと考えています。広く、福祉系のイベント等を活用して、周知を徹底していきたいと考えています。","id":"exchange-005"},{"speaker":"安藤委員","kind":"意見","question":"先ほどもありましたけれども、不燃化特区の区内全域への拡大などが必要ではないかと思います。反対ですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-006"},{"speaker":"中塚委員","kind":"意見","question":"補助２９号線を含めた延焼遮断帯の機能というところでは、結局、これは到底受け入れることはできません。事業として、延焼遮断帯機能の形成というところは受け入れられませんので、全体として反対ということですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-007"}]},{"id":"topic-02","title":"第３５号議案 品川区自転車等の放置防止および自転車等駐車場の整備に関する条例の一部を改正する条例","agenda":"第３５号議案 品川区自転車等の放置防止および自転車等駐車場の整備に関する条例の一部を改正する条例","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"改正に賛成なのですけれども、ストレートに地下機械式駐輪場を当日利用に切り替えるということはできないのかを伺いたいと思います。最新の利用率について伺いたいのですけれども、定期利用があれば、それぞれ伺います。","respondent":"山下交通安全担当課長","answer":"今後、当日利用に変更するとなりますと、あと精算機を、当日利用にできるようなシステムに改修する必要があると。当日利用が駐輪スペースは１６０.８％、続きまして、大森駅前住宅の南側にある歩道の駐輪場が９４.２％となっております。","id":"exchange-008"},{"speaker":"安藤委員","kind":"質問・要望","question":"大森駅前住宅の駐輪場についてですけれども、景観等の関係から撤去してほしいという要望がやはり根強く、届けられているかと思います。利用状況なども見据えながら、大森駅前住宅の駐輪場の閉鎖に向けて動いていただきたいのですけれども、それについてはご答弁はいかがか尋ねました。","respondent":"山下交通安全担当課長","answer":"当日利用をしている方が、一応、見込みですが１００台以上は入るのかなと考えているところです。ただ、現状のままですとなかなか難しいので、将来的に利用率が一定程度下がったときには、またその場で検討できるのかなとは考えてあります。","id":"exchange-009"},{"speaker":"中塚委員","kind":"質問・要望","question":"当初想定していたものより、少ない理由というのでしょうか、そこはどのように分析されているのかということを伺いたいと思います。併せて、定期利用ですけれども、契約は１年なのでしょうか、半年なのでしょうか、１か月なのか尋ねました。","respondent":"山下交通安全担当課長","answer":"約１００名ほどの回答があったのですけれども、その中では、やはり料金が高い、やや高いという方が６４％を超える状況でございました。３か月、６か月、以上となります。","id":"exchange-010"},{"speaker":"中塚委員","kind":"質問","question":"２,３００円ですから、例えば学生に限定してさらに減額していくというふうにするとどうかなと思ったのですけれども、いかがでしょうか。さらに利用が増えていくのではないかなとも思ったりするのですけれども、そういう検討など、どんなふうにお考えなのか伺いたいと思います。","respondent":"山下交通安全担当課長","answer":"区民の皆様に同等に同じように利用していただきたいという理由から、今、学割を検討してございません。申し上げられませんけれども、そういったご意見があるということもひとつ受け止めて、今後の検討課題にさせていただければと思います。","id":"exchange-011"},{"speaker":"中塚委員","kind":"質問・要望","question":"後で支払っていただくという考えも、一方であるべきかなとも思いますので、最後に意見だけ述べておきます。とにかく一旦下げてみて、どういう状況なのかというのを把握した上で、その機会でまたご検討いただけたらと要望したいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-012"},{"speaker":"ゆきた委員","kind":"質問","question":"先ほどのご答弁で、定期利用の契約期間が１か月、３か月、６か月とご説明がありました。既に、事前に複数月分納めている利用者についてはどういう対応となるのか、あと併せて周知方法についてもお聞きできればと思います。","respondent":"山下交通安全担当課長","answer":"１０月３０日までの契約となるのですけれども、１０月分につきましては減額後の料金を反映するようにシステムを変更していく予定です。周知方法についてですが、当日利用者に対して声をかけするほか、ホームページ・広報紙などで周知を図っていきたいと考えています。","id":"exchange-013"},{"speaker":"中塚委員","kind":"質問・要望","question":"対象も１８歳まで、いわゆる高校３年生まで拡大というところです。高校３年生までは、学割制度の導入をご検討いただきたいと、改めて要望したいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-014"}]},{"id":"topic-03","title":"第５０号議案 専決処分の承認を求めること","agenda":"第５０号議案 専決処分の承認を求めること","exchanges":[{"speaker":"安藤委員","kind":"確認","question":"専決処分にしなくてはいけなかった理由というのをお伺いしたいというのが２点目。これは確認なのですけれども、今回のような訴訟を起こす以外の方法というのは何かあるのか、伺いたいと思います。","respondent":"川原住宅課長","answer":"こちらは改めてのご説明になるのですけれども、第１７９条第３項の規定にのっとりまして、その承認を求めるという形になってあります。きちんと話合いができて、分納の納付誓約書を提出していただくといった対応もできたところですが、訴訟を提起したところです。","id":"exchange-015"},{"speaker":"中塚委員","kind":"質問・要望","question":"滞納整理の対応をするのは品川区の職員なのか、それとも指定管理者の方なのか、伺いたいと思うのです。電気がついているとかメーターが回っているとか、そこにいらっしゃるということを確認するのか、どちらが確認するのか。","respondent":"川原住宅課長","answer":"ファミーユ西五反田への訪問については、指定管理者の管理人が同建物内の防災センターに常備２４時間待機しています。ただ、居住の実態があることは確実につかんでいるようなところです。","id":"exchange-016"},{"speaker":"中塚委員","kind":"確認","question":"どういうふうに確認するのか。そこを伺いたいと思います。","respondent":"川原住宅課長","answer":"実際の区としての踏み込んだ確認・支援などの対応というところと、課長としての対応というところのご質問があったかと思います。万が一、連絡を受けた際にはきちんと対応するようにということで、この住宅の担当以外の職員でも共有させていただいたといったところです。","id":"exchange-017"},{"speaker":"中塚委員","kind":"質問・要望","question":"そこを確認させてほしいと求めました。指定管理者の方の業務だということも分かった上で、そこだけ確認させてほしいと求めました。","respondent":"川原住宅課長","answer":"滞納整理の状況を把握するとき、通常は区役所に管理者が来て説明を受けるのですけれども、見回りに同行するといったことはございました。ただ、残念ながら呼出し等には来てくださらなかったといった事例ですので、このような形にしています。","id":"exchange-018"},{"speaker":"中塚委員","kind":"意見","question":"引き続き、丁寧な対応をお願いしたいと思います。以上ですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-019"},{"speaker":"ゆきた委員","kind":"質問","question":"今回の案件のように、保証限度額が約１９２万円に対して訴訟価額が約７２９万円となる事案について、区の財政的負担というのは小さくないと思います。この辺についてお聞きできればと思います。","respondent":"川原住宅課長","answer":"今後の滞納整理の見込みにつきましては、三か月だけでも、本人にも非常に大きな負担になってしまいます。この方以外いらっしゃらないので、引き続き細かな連絡を取っていって、滞らないように対応していきたいと考えています。","id":"exchange-020"},{"speaker":"ゆきた委員","kind":"確認","question":"ほかにも複数名いらっしゃるということを確認させていただきました。明渡訴訟、請求に至る前に、再発防止策というのはこれから必要になるなとは感じますが、ここについて説明を求めました。","respondent":"川原住宅課長","answer":"明渡しを求める前の滞納の再発防止策です。当然、１か月滞納したときの督促状と２か月滞納の催告書には、場合によっては相談を受けるといったところを引き続き実施していきたいと考えています。","id":"exchange-021"},{"speaker":"ゆきた委員","kind":"意見","question":"通知していくというのは承知しているのですけれども、生活再建をしていく上でのアプローチの仕方が必要だとお伝えしているので、こちらについては受け止めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-022"},{"speaker":"せお副委員長","kind":"質問・要望","question":"今、ゆきた委員が最後にちょっと要望されたのですけれども、そこのところを聞きたい。その方の状況がどこまで把握できるか分からないのですけれども、そういったところをこちらから発信していくというのはないのか尋ねました。","respondent":"川原住宅課長","answer":"生活の相談をされて、結果、保護に至った方もやはりいらっしゃるといったところです。一定、そこの部分は寄り添った対応を、福祉部門とも連携して行っていったという事例は実際にあります。","id":"exchange-023"},{"speaker":"せお副委員長","kind":"質問・要望","question":"賛成です。今質問した区からのアプローチを積極的に、やっていらっしゃると思うのですが、より一層丁寧に行っていただきたいと要望して、賛成いたします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-024"},{"speaker":"中塚委員","kind":"提案","question":"福祉的なアプローチのところ、少し議論や様々な提案があって、そのとおりだと思います。品川区も、初動といいますか、滞納額が増える前に、今ご説明もありましたけれども、ぜひ丁寧に引き続き進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-025"}]},{"id":"topic-04","title":"再開発準備組合の運営等に関する陳情","agenda":"再開発準備組合の運営等に関する陳情","exchanges":[{"speaker":"安藤委員","kind":"質問・要望","question":"今後の事業のスケジュールというのですか、どんなふうに流れていくというスケジュールなのか、もう少し伺いたいと思います。処理がなぜ進んでいないかなどについて、区が知り得ている情報があれば伺いたいと思います。","respondent":"中道都市開発課長","answer":"今、事業者から聞いているのは、おおむね２年ほどでその辺は固めていきたいということは聞いてあります。続きまして、小山三丁目第２地区で火災があった原因等についてですけれども、区としては詳細の部分は把握していないです。","id":"exchange-026"},{"speaker":"安藤委員","kind":"質問・要望","question":"どういうことをやってくれるのですかというのを伺いたいと思います。森澤区長とはどのような情報共有を行って、そしてどのような指示を受けているのか、伺いたいと思います。","respondent":"中道都市開発課長","answer":"区といたしましても、できる限り丁寧に対応していただきたいと考え、取り組んでいるです。区長とのやり取りでも、区長からは、そういった丁寧な対応を行うよう努めてほしいということを言われてあります。","id":"exchange-027"},{"speaker":"安藤委員","kind":"質問","question":"もし具体的に相談などがあったら対応してもらいたいと思うのですけれども、これについてはやっていただけるのか、伺いたいと思います。区長もいろいろな事業のトップだから、この武蔵小山の開発事業についてどういう情報共有が行われているのかというのは、もう一回伺いたいと思います。","respondent":"中道都市開発課長","answer":"区としての対応ですけれども、区にご相談があった際には、適切に丁寧に対応していきたいと考えています。もちろんこういった陳情書は区長まで届きますので、その結果等について、まずは区長に報告しているというような状況です。","id":"exchange-028"},{"speaker":"安藤委員","kind":"質問","question":"小山三丁目第１地区の事業費等の予定額なのですけれども、これは何年何月時点のものなのか伺いたいと思います。その前にもう一度、最新の資金計画を説明するというのは当然あるべきなのではないかなと思うのですけれども、その辺についてはいかがか尋ねました。","respondent":"中道都市開発課長","answer":"この資金計画について、その資金計画も、そういった中で合意に結びついているという認識です。回答は申しあげられないのですけれども、近年、大崎駅西口Ｆ南地区については補助金が当初よりも上がっているというところがあります。","id":"exchange-029"},{"speaker":"安藤委員","kind":"質問","question":"加入していても反対という方がまた別にいると思うので、再開発に同意している方と非同意の方が何名でというところを伺えないかなと思います。マンション区分所有者の準備組合加入者・非加入者や同意・不同意の内訳についても教えてほしいと求めましたが、いかがか尋ねました。","respondent":"中道都市開発課長","answer":"個別のマンションは１つの組織といった形の考え方で、いわゆるマンションの一組織としての判断ということになりますので、回答は控えします。〔傍聴席にて騒ぐ者あり〕","id":"exchange-030"},{"speaker":"安藤委員","kind":"質問","question":"そこを伺ったのです。その辺をもう一回お伺いします。","respondent":"中道都市開発課長","answer":"同意者数につきましては、全体で８３.６％が同意されているというところになります。一方で、先ほどの理由のとおり、１つの組織の決定になりますので、区としては回答は控えするです。","id":"exchange-031"},{"speaker":"安藤委員","kind":"質問・要望","question":"そういうことなのか確認させていただきたいのと、あと同意者８３.６％というのは、そのうちの８３.６を掛ければ人数が出てくるのでは。そこだけお伺いします。","respondent":"中道都市開発課長","answer":"総地権者数が６１.２２名、ここで同意しているのが５１.１６名というところで、８３.６％というところになります。そこの権利を持っている方に同意書を提出していただいて、マンションごとに、何％同意しているかというところを把握しているです。","id":"exchange-032"},{"speaker":"安藤委員","kind":"質問","question":"組合員総数でいうと、実人数でいうと１６８人に遠く及ばないのではないかと思うのですけれども、なぜ総会が成立とされたのか、伺いたいと思います。８ページにも関わるのですが、総会定足数の答弁を差し控えると言ったのはなぜなのか、伺いたいと思います。","respondent":"中道都市開発課長","answer":"今回の準備組合の出席の考え方でいきますと、都市再開発法にのっとって、マンションの権利者は１というところでカウントしております。前回の答弁で回答を控えするというところ、委員会の場では回答を控えさせてもらいたいということを聞きましたので…","id":"exchange-033"},{"speaker":"安藤委員","kind":"質問","question":"法の解釈でいうとマンション１棟１人かもしれないのですけれども、もうずっと暮らしてきた１人の人間がもう何百人と住んでいるわけではないですか。改めて区として受け止める考えはあるのか、ないのか、伺いたいと思います。","respondent":"中道都市開発課長、新妻委員長","answer":"こういったマンション住民の一人一人にどう対応しているかです。マンションは１と考えるところですけれども、やはりマンションの全体で、していないのかというところの把握には努めてあります。 私語はできません。委員長の命令に従わないときは、品川区議会委員会傍聴規則第７条に基づき退場を命じますので、念のため申し上げておきます。","id":"exchange-034"},{"speaker":"安藤委員","kind":"質問・要望","question":"補償はどうするのかということでありますが、地権者への補償価格が２倍になるというような場合、どう補償するのか伺いたいと書いております。それも伺いたいと思います。","respondent":"中道都市開発課長","answer":"もちろん、回答に対して陳情者の方が全部が全部理解する、またはお互いに共通認識であったことを確認できたといったところもございました。「一つ一つ丁寧に回答していただいてありがとう」といった言葉も頂いたという認識ですので、様々な機会がありますけれども、ひとつ。","id":"exchange-035"},{"speaker":"安藤委員","kind":"質問","question":"最後に伺ったのは、補助金自体が相当上がってしまうというときに、行政というか、区民の側というのは何も判断できない。そして、そういうふうに上がっていくものなのかというのを伺ったので、お答えください。","respondent":"中道都市開発課長","answer":"補助金の使い方です。再開発事業の補助金要綱であったり手引であったりといったものがありますので、そうしたものにのっとって対応していくものです。","id":"exchange-036"},{"speaker":"安藤委員","kind":"質問・要望","question":"要綱や手引にのっとって、どんどん上がっていくというのは、ちょっとおかしな仕組みだと思います。冒頭の説明ではかなり簡素な感じでしたので、きちんと住民の方の疑問には答えていっていただきたいと、改めて申し上げたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-037"},{"speaker":"中塚委員","kind":"質問・要望","question":"今の質疑ではこのご説明がなかったので、小数点になるのはなぜなのか、理由を伺いたいと思います。マンション１棟が１人になってしまうというのは、成立していると区が考えている根拠を説明してほしいと求めました。","respondent":"中道都市開発課長","answer":"マンションは１棟ですけれども、４名の方が出席すると０.８人という形になりますので、小数点というのは通常発生しているものという認識です。こういった総会等があった際には、準備組合の規約に、こういったところにも照らし合わせて区としても判断していきたいと考えています。","id":"exchange-038"},{"speaker":"中塚委員","kind":"確認","question":"それと、３つ目の質問の、総会の成立についてですけれども、弁護士も含めて、合っているかどうか確認しているというところでした。時間も時間なので、そこは改めて伺いたいと思います。","respondent":"中道都市開発課長","answer":"はその民間の組織の中でのルールというものがきちんと守られて、民間の中できちんと運営されているというところが重要かなと考えています。その中で、弁護士等の専門家にも確認して、適正に運営を行っているという報告を受けているです。","id":"exchange-039"},{"speaker":"中塚委員","kind":"質問","question":"初めて私もこの答弁を伺いますけれども、何で判断しないのでしょうか。規約や法令の違反があるかどうかは、ちょっと違うなと思うのですけれども、いかがか尋ねました。","respondent":"中道都市開発課長","answer":"判断するには、区がそこで出席者の定足数を、その場できちんと「適正ですので運営を開始していいです」と判断する立場ではないのかなと思っています。総会に出て、そういったときには事後に状況を確認して、どういうふうに運営されているかというのは把握に努めているです。","id":"exchange-040"},{"speaker":"中塚委員","kind":"質問","question":"こうやって疑問の声が上がっているわけですから、３月２４日の総会が成立していると区が判断している、その根拠は何か。最後にもう一度伺いたいと思います。","respondent":"中道都市開発課長","answer":"こういったマンションの権利者はやはり１名というカウントの中で、定足数を設定されてございまして、その過半数が出席すればその総会は成立する。過半数以上が出席しているというところも踏まえて、区としては適正に運営されているという判断をしております。","id":"exchange-041"},{"speaker":"松永委員","kind":"質問","question":"その中で、先ほどご答弁の中で、規約違反や定足数を満たしていないという事実については、ないのであろうと判断させていただきました。事業の手続については適正に進められていると判断し、今回の陳情は不採択といたします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-042"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"生活再建に不安を抱える権利者への配慮として、区が組合に対して相談所の設置を要請して具体的に支援策を講じている姿勢も確認できました。ですので、引き続き権利者に寄り添い、必要な助言を継続していくことを求めて、この陳情については不採択でお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-043"},{"speaker":"安藤委員","kind":"質問・要望","question":"採択を主張しますけれども、やはり再開発は地権者の皆さんにとっては本当に、命と暮らし、財産がかかった問題であります。新たな定数等の答弁もありましたけれども、住民・地権者の疑問には真摯に答えてほしいと求めましたので、採択ということで主張したいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-044"},{"speaker":"中塚委員","kind":"質問","question":"そもそも法律でマンション１棟の議決権を１人分とするというところがあまりにも乱暴な見方だなと思います。ここの規定で住民から声が上がっているわけですから、そのほうにはぜひ向き合って、丁寧な説明をしていくべきだと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-045"}]},{"id":"topic-05","title":"専決処分の報告","agenda":"専決処分の報告","exchanges":[{"speaker":"安藤委員","kind":"質問・要望","question":"結局、本人との接触といいますか、がどのようにあって、どのようなやり取りがあったのか、もう少し説明していただきたい。今回の場合、いろいろ事情を抱えている可能性がありますので、他部署との連携等、そういったことは何かあったのか伺いたいと思います。","respondent":"川原住宅課長","answer":"この状況を説明したところ、本人もそれには応じるというか、納得するといった話があったところです。この方の個人情報に関連してしまうところがあるので、細かい部署名までは言えないのですけれども、現在３課と連携させていただいています。","id":"exchange-046"},{"speaker":"安藤委員","kind":"確認","question":"確認なのですが、先ほどのやり取りの中で、最終催告書を送った後に一度接触があったということなのでした。本人も納得して退去するということに、その場ではなったということなのか、その辺を確認させてください。","respondent":"川原住宅課長","answer":"１点目の、分割納付の提案はしたのかといったところです。していらっしゃる方なので、金銭管理支援というところも第一にやっていきたいというところで、話をさせていただいているといったところです。","id":"exchange-047"},{"speaker":"中塚委員","kind":"質問・要望","question":"区営住宅ですから、理解しているか確認されているのかというか、どうされていくのか。次の住まいの確保に向けての対応が求められるのかなと思いますので、もう少し状況や、区の支援や対応を伺いたいと思います。","respondent":"川原住宅課長","answer":"就労した際には、ご自身の得た所得をどのように使うかといった優先順位というものが非常に難しいのかなと。早い段階で、こういった支援が必要な、方向けの自立支援の施設のほうに入所できれば一番よろしいのかなと考えているところですが。","id":"exchange-048"},{"speaker":"中塚委員","kind":"質問・要望","question":"支払ってほしいという当然の主張と、何らかの理由でそれが困難になっているわけですから、支払ってほしいだけでない。そうした専門的なスキルを福祉部との連携で進めていっていただきたいし、最後にそこだけもう一言、伺いたいと思います。","respondent":"川原住宅課長","answer":"福祉関係へのアプローチをどのように住宅課として行っていくかといったご質問であったかと思います。当然、こういった支援が必要と判断している方については、早期の解消というところにもつないでいきたいと考えています。","id":"exchange-049"},{"speaker":"ゆきた委員","kind":"質問","question":"６か月で最終催告と先ほどありましたが、何か月の待機をもって長期とするのか、明確な基準があるのであれば教えてください。先ほど７か月になった際に滞納事務に入るというお話がありましたが、お聞きできればと思います。","respondent":"川原住宅課長","answer":"滞納整理の開始に関する法的根拠といったご質問であったかと思います。そのほか、品川区の滞納整理事務処理要綱で、６か月以上の滞納があった場合には、こういった使用許可取消しについて進めるといった明記があります。","id":"exchange-050"},{"speaker":"ゆきた委員","kind":"確認","question":"では、長期滞納という定義というところは特にはないということですか。もし明確な基準がないのであれば、訴訟に至る前段階で制度として整備していくべきと考えますが、ここについてお聞きします。","respondent":"川原住宅課長","answer":"十分なヒアリングを行い、使用料が下がる見込みがある方であれば、まずお話をさせていただいています。一人一人、ケース・バイ・ケースで対応を行っているところです。","id":"exchange-051"},{"speaker":"ゆきた委員","kind":"意見","question":"もちろんケース・バイ・ケースで、あと個別のヒアリングによって対応が変わるところはあると思うのですけれども、最低限、ルールを明確に基準にしていっていいのかなとは感じましたので、ここについては進めていけるように考慮してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-052"}]},{"id":"topic-06","title":"目黒川航行マナー啓発活動の実施","agenda":"目黒川航行マナー啓発活動の実施","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"運用が１０回目ということで、浸透度というのですか、どんなふうに感じていらっしゃるのか伺いたいと思います。未申請の船舶が来たケースなどというのは結構あるものなのか、その辺についても併せて伺います。","respondent":"関根河川下水道課長","answer":"特に活動開始当初は、少なくともここ２年はそういった苦情もないという状況ですので、周知等も図られているのかなと認識しています。１割弱の船舶についてはまだ未申請というところがありますので、引き続き、こうした活動を継続していくことは重要かなと認識しています。","id":"exchange-053"},{"speaker":"中塚委員","kind":"質問・要望","question":"どんなマナー違反が多発しているのか、この取組をするに当たって、どういう問題が起きているのかということを伺いたいと思います。未申請の船舶というのは何の船なのか尋ねました。","respondent":"関根河川下水道課長","answer":"先ほど昨年度１０件強と申し上げましたが、小型のいわゆる旅客船といいますか小型船舶、または水上バイクのどちらかという形になっております。目黒川を航行される方もいらっしゃいますが、そういったカヌー等については、未申請は昨年度はございませんでした。","id":"exchange-054"}]},{"id":"topic-07","title":"水辺のライトアップ更新検討","agenda":"水辺のライトアップ更新検討","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"事業費は幾らなのかということをお伺いしたいと思います。ライトアップが、にぎわいの創出につながっているのかどうか、品川区としてはどういうふうに認識されているのかお伺いしたいと思います。","respondent":"関根河川下水道課長","answer":"ライトアップ事業を開始して５年程度が経過しておりますけれども、やはり水辺のにぎわい創出は非常に大事で必要な事業だと認識しています。今後、今回の試行実施等も踏まえて効果検証を行ってまいります。","id":"exchange-055"},{"speaker":"安藤委員","kind":"質問","question":"ちょっと分からなかったのですけれども、どこの部分が９８１万円なのかというのを、もう少し詳しく教えてもらいたいと思います。にぎわいの創出の件についての、現時点では、このライトアップがにぎわい創出につながっているといった実態は把握していないという感じか尋ねました。","respondent":"関根河川下水道課長","answer":"基本的には試行実施の第Ｉ期や、次年度以降予定しております構想に向けた準備といったものを実施するという委託の金額になってあります。こちらからも効果的にアピール、ＰＲをしていくためにはどういったものが効果的かということも含めて検討していきたいと考えています。","id":"exchange-056"},{"speaker":"中塚委員","kind":"質問","question":"よく分からないのですけれども、国や東京都からどんな補助金があるのか、一般財源を入れているのであればどれぐらいなのか、伺います。そこも最後に３点目で伺いたいです。","respondent":"関根河川下水道課長","answer":"この試行実施あるいは構想策定に当たっては、一定引き続き、事業費を使って検討を進めていくということを考えてあります。位置づけて進めてきたところですので、ライトアップにつきましても、より持続可能な形で継続していきたいと考えています。","id":"exchange-057"},{"speaker":"中塚委員","kind":"質問・要望","question":"区の計画で位置づけがあるからという説明ですけれども、何でライトアップする位置づけがあるのか、改めてご説明ほしいと求めました。本当にこれは必要なのかなと正直思っているところなのですけれども、ご説明をお願いします。","respondent":"関根河川下水道課長","answer":"「ヒカリの水辺プロジェクト」が開始される前の経緯となりますが、目黒川が全体的に暗いというところで、始まったものになります。そういった人観点で、「ヒカリの水辺プロジェクト」を実施してライトアップを進めるというふうになったと認識しています。","id":"exchange-058"},{"speaker":"中塚委員","kind":"質問","question":"つまり、河川下水道課がそこまで考えているかどうかはよく分かりませんけれども、区全体ではそういう位置づけがここにあるのではないですか。多様で魅力的な夜のライトアップを行うのか、最後まで私には理解できないのですけれども、改めて最後に伺いたいと思います。","respondent":"関根河川下水道課長","answer":"区の所有する橋のうち、目黒川あるいは運河を含め、１３の橋について実施しているものですので。推測になってしまうかもしれませんが、その中で、例えば地域のお店等に行っていただくという人も増える可能性もあるかなと認識しています。","id":"exchange-059"},{"speaker":"ゆきた委員","kind":"確認","question":"１３の橋梁でライトアップを実施していると理解しております。現在の状況と、今後もう３月から試行実施ということになっていますが、こちらについて確認でお聞きできればと思います。","respondent":"関根河川下水道課長","answer":"原因の特定には至らなかったということで、工事費用の見積り等を実施したところ、現在費用を抑えた形で調査できないかというのを検討しています。年度内というのは少し難しいところではありますが、令和８年度には調査…","id":"exchange-060"},{"speaker":"ゆきた委員","kind":"確認","question":"現状を確認できました。ということは、勝島橋は、３月に行われる試行実施には間に合うかどうか、まだ不明ということか尋ねました。","respondent":"関根河川下水道課長","answer":"３月の試行実施は品川橋のみで実施するという形で考えてあります。勝島橋につきましては、３月の試行実施を予定等はしてございません。","id":"exchange-061"},{"speaker":"ゆきた委員","kind":"確認","question":"確認できました。勝島橋を除いた１３橋梁で、現在、こういった場所というのはあるのかないのか、説明を求めました。","respondent":"関根河川下水道課長","answer":"やはり、足場をかけないといけなかったり、なかなか維持管理上、正直苦労しているところがあります。今回、将来的な維持管理のしやすいライトアップというのをしっかりと検討して、それを実施していきたいと考えています。","id":"exchange-062"}]},{"id":"topic-08","title":"その他","agenda":"その他","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"２３区長会等でどのような検討が行われているのかというのを伺いたいのと、品川区としては、この物価高ですから。そちらについての考え方はいかがかということをお伺いしたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-063"},{"speaker":"安藤委員","kind":"質問・要望","question":"去年もやったと思うのですが、何人ぐらいで、実際に、どういう方々がどういうふうに公道を歩いてくるのか。装備はどうするのかなど、区民の方の目にどう映るか、具体的にもう少し教えていただきたいです。","respondent":"星災害対策担当課長","answer":"ご質問にございました人数については、自転車で５名となります。首都直下地震のときにこちらに来て対応できるような装備で来ると、昨年はそのような状況でしたので、今年も同様の装備だと思います。","id":"exchange-064"},{"speaker":"安藤委員","kind":"質問","question":"ですから、どこが主催なのかというのと、この訓練の意味というか目的というのですか。ですから、やはり何でこの訓練が必要なのかということを明確にお示しいただかないと、私は承服できないわけです。","respondent":"星災害対策担当課長","answer":"昨年実施したときは、能登半島地震の際、道路が潰れてしまいまして、自衛隊の方が徒歩で山越えをして救助に向かったと。そちらを基に訓練を開始したと聞いておりますので、今回も同様の目的を持っての訓練と考えております。","id":"exchange-065"},{"speaker":"安藤委員","kind":"質問","question":"自治体に協力をお願いしてきたのか、通知してきたのか分からないのですけれども、全ての自治体がやっているわけではないわけです。どのようなやり取りがあって、受入れに至ったのかというのを、最後に説明を求めました。","respondent":"星災害対策担当課長","answer":"３月１１日、品川区役所をゴールとして訓練をしたいというところが１つ、連絡としてございました。トイレの使用をさせていただきたいと、電話での連絡が入ったところで、品川区役所としても了承して対応するというところになっております。","id":"exchange-066"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/680934?Template=document&Id=7315#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=8&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":52996,"voices":205}},{"id":"r08-20260224-9","meetingId":"r08-1t","date":"2026年2月24日","dateIso":"2026-02-24","committee":"文教委員会","time":"午前１０時００分～午後 １時５８分","status":"正式会議録","sourceType":"formal","overview":"文教委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を69件整理しています。","topics":[{"id":"topic-01","title":"関係条例の整備等（3議案）","agenda":"関係条例の整備等（3議案）","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"それと、運用上は主任教諭の名称で扱うということですけれども、主務教諭と主任教諭の関係がどうなるのか伺いたいと思います。今、主任教諭は何人いらっしゃるのか伺います。","respondent":"酒川指導課長","answer":"既に２０年ほど前から、地域連携の推進、引き続き主任教諭を主務教諭に代えるです。現在、品川区には、主任教諭は４００人ほど存在しております。","id":"exchange-001"},{"speaker":"のだて委員","kind":"確認","question":"給与は、４万円から５万円違うと結構違うという感じがしたのですけれども、これは月額ですか。同じ年齢、同じ経験年数の場合、これだけ違うのか伺います。","respondent":"酒川指導課長","answer":"それから、時間外勤務の時間数は国の目標を既に下回っておりますので、主任教諭についても大きな負担になっているとは認識しておりません。品川区もですけれども、主務教諭の職が学校の中にあるわけではないという、お見込みのとおりです。","id":"exchange-002"},{"speaker":"のだて委員","kind":"質問","question":"実際、分断が生まれると思うのですけれども、いかがでしょうか。こうした実態を区はつかんでいるのか伺います。","respondent":"酒川指導課長","answer":"上下関係ができるということは言えると考えていますけれども、分断が生まれているとか差別が生じているといった状況については把握しておりません。なお、論文によっての選考になります。","id":"exchange-003"},{"speaker":"のだて委員","kind":"質問","question":"そうすると、論文だけではないところで管理職の覚えがいい人が受かっていくことになっていくと思うのですが、改めて伺いたいと思います。そうしたことはやはりあってはいけないと思いますけれども、いかがか尋ねました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-004"},{"speaker":"のだて委員","kind":"質問・要望","question":"把握していないということなので、把握していただけたらと思うのですけれども、いかがでしょうか。実態を把握してほしいと求めましたが、いかがか尋ねました。","respondent":"酒川指導課長","answer":"もちろん不当な理由で合格できないという状況は避けていきたいと思います。当然ながら、そういった職員の業務態度に関する相談があった場合は、こちらも把握し、改善に努めていくものです。","id":"exchange-005"},{"speaker":"のだて委員","kind":"意見","question":"業務負担の増大も懸念されます。階層化を条例に位置づけるものですので、反対ですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-006"},{"speaker":"のだて委員","kind":"意見","question":"管理職の処遇改善は前進面ではありますけれども、主務教諭を新たに追加するのは、第１８号議案と同様の理由で、やるべきではないと考えますので、反対ですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-007"}]},{"id":"topic-02","title":"第１９号・第２１号議案（児童センター・保育所条例）","agenda":"第１９号・第２１号議案（児童センター・保育所条例）","exchanges":[{"speaker":"のだて委員","kind":"質問・要望","question":"今回の条例変更で、そうすると三ツ木保育園は公立ではなくなるということでいいのか、そこを確認させてほしいと求めました。今回こうした民営化を進めていくのは、保育の実施責任を後退させていくものと思うのですけれども、いかがか尋ねました。","respondent":"芝野保育入園調整課長","answer":"１点目の位置づけになりますが、こちらは民設民営の保育所に変更になります。運営についてもしっかりとモニタリングをさせていただきながら進めていきますので、品川区の実施責任は引き続き担保する形と考えております。","id":"exchange-008"},{"speaker":"のだて委員","kind":"質問","question":"実施責任との関係で、三ツ木保育園を廃止することをどのように認識されているのか伺いたいと思います。併せて、公私連携型保育所になると何が変わるのか伺います。","respondent":"芝野保育入園調整課長","answer":"実施責任ですが、そして最終的に運営委員会に品川区がしっかりと関与させていただきながら、モニタリングをさせていただきたいと考えています。公私連携型に変わった段階で、こちらはポイントが３つございまして、品川区の保育理念の継承は進められます。","id":"exchange-009"},{"speaker":"のだて委員","kind":"質問・要望","question":"これが実際にどういう規模で、どういう実績だから継続的かつ安定的だということなのか、具体的に分かっていれば伺います。公共性・公益性の高い事業の実施に向けた取組を期待したいと書かれているのですけれども、具体的には何を求めているのか、伺います。","respondent":"芝野保育入園調整課長","answer":"そして、公共性・公益性の考え方ですが、今いろいろ区で取り組んでいるところがあります。例えば小学校との連携ですとか防災関係、今後、事業者と一緒に詰めていきたいと考えております。","id":"exchange-010"},{"speaker":"のだて委員","kind":"質問","question":"区立だと勤続年数は１２.９年、株式会社では６.３年で、民間は約半分になっているということです。民営化は進めるべきではないと言っておきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-011"},{"speaker":"高橋（し）委員","kind":"質問","question":"先ほど特定財源が望まれるというお話だったのですが、三ツ木保育園は８０人ぐらいの規模だと伺っています。特定財源やそのほか補助金等でどのぐらい区の負担が減るのか分かる範囲で結構ですので、具体的な数字が分かれば知りたいのでお願いします。","respondent":"芝野保育入園調整課長","answer":"公私連携型保育所に移行した場合、特定財源が見込まれるので、区負担としては年間７,０００万円程度になるという試算をしております。そのため、年間で約９,０００万円の財政負担軽減が見込まれてあります。","id":"exchange-012"},{"speaker":"高橋（し）委員","kind":"質問","question":"財政のことだけお尋ねするのですが、９,０００万円の財政負担の軽減について、公私連携型を導入する１つの大きな理由だと思うのですけれども、９,０００万円削減になることについて、区としてどのようにお考えか尋ねました。","respondent":"芝野保育入園調整課長","answer":"９,０００万円削減は非常に大きな効果だということもありますが、公私連携型に移行することによって、保育の質が落ちてしまうとかそういうことがあっては制度の趣旨から外れてしまいますので、こちらはしっかりと担保していきたいと考えております。","id":"exchange-013"},{"speaker":"高橋（し）委員","kind":"意見","question":"公私連携型については、質を担保するのはもちろん前提条件で、進めていってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-014"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"要望ですけれども、先ほどのだて委員からありました公共性・公益性の部分で、私もやはり園内保育だけにとどまらず、例えば園内解放とか、子育て世代の相談支援といったものを、三ツ木保育園が地域福祉の拠点になるような、何かそういった取組はぜひ区から要望していただけたらと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-015"},{"speaker":"筒井副委員長","kind":"質問","question":"そもそも公私連携型保育所制度は、財政負担の軽減というメリットとかそういうものがありながらも、完全に民営化してしまうと不安だという声もあるので、その両方のバランスをとった制度だと思っているのですけれども、その他、公私連携型保育所制度の捉え方、意味合いを改めて説明を求めました。","respondent":"芝野保育入園調整課長","answer":"公私連携型保育所の意味合いは、今副委員長からご説明がありましたとおりの内容でございまして、行政が協定をもって関与していく。品川区の保育の質を承継していく、こちらのやり方の１つとして、通常の民設民営とは違う視点で進めていくのがこの制度の概要です。","id":"exchange-016"},{"speaker":"筒井副委員長","kind":"質問","question":"その点、建物もだんだん傷んでくると思うのですが、それは民間事業者が負担するのですか。土地・建物の維持管理とか将来的な修繕の負担はどちらなのかを説明を求めました。","respondent":"芝野保育入園調整課長","answer":"建物の維持管理ですが、こちらは事業者側に負担させる内容で協定を結ぶ予定です。","id":"exchange-017"},{"speaker":"若林委員","kind":"提案","question":"具体的な提案内容を確認したいというのが、既にこの時点で当然提案内容が示されて、その進捗状況を確認したいという意味なのかを確認させてください。ここが提案としては１つ特記されていると思うのですけれども、３番目のとこで、どんな提案内容なのかも教えてほしいと求めました。","respondent":"芝野保育入園調整課長","answer":"２つ目の、それに加え、公私連携型は区の理念も一緒に入れていただく。準備を進めているということと、研修等も品川区で実施しておりますので、どこまで協力できるかを一緒に考えていくことを評価されているものです。","id":"exchange-018"},{"speaker":"若林委員","kind":"確認","question":"最初の指定管理者制度の選考方法に準じてとは、どこが決めたのでしょうか。そこは確認したいと思います。","respondent":"芝野保育入園調整課長","answer":"５年間の効果検証を、指定管理者制度も原則５年ということで進めていますが、その後、指定管理を更新する際に、ガイドラインに基づいてやっている。それが今回の公私連携型の選定方法に一番合致しているという考え方を基に、今回採用させていただいているところです。","id":"exchange-019"},{"speaker":"若林委員","kind":"質問","question":"そうすると、子ども未来部で決定して、区の執行部も了解したというということで認識したいと思いますが、お聞きします。","respondent":"芝野保育入園調整課長","answer":"そうです、きっちりとトップまで決裁を取りまして、区の決定として今回の選定を行っております。","id":"exchange-020"},{"speaker":"横山委員","kind":"質問・要望","question":"５ページですけれども、子どもの事故の予防の観点で、どういった形で取り組んでいくということを確認できているのかを確認させてください。こちらの事業者の独自性を発揮した保育を提供すると３ページに書いてあるのですけれども、具体的にどういった独自性があるのかも確認させてください。","respondent":"芝野保育入園調整課長","answer":"インセンティブの考え方ですが、委員からご説明ありましたように、安定的な経営に資することを主目的としております。定期的な研修の実施、年度が変わって公私連携型になっても、しっかりとモニタリングをしていきたいと考えております。","id":"exchange-021"},{"speaker":"横山委員","kind":"質問・要望","question":"児童虐待はやっていただくと確認していたのですけれども、区としてこうした環境を整えてほしいということをしっかりと伝えていただきたいという趣旨だったのですけれども、その辺りはいかがか尋ねました。","respondent":"芝野保育入園調整課長","answer":"保育園の事故予防については、しっかりと連携をとりながら、事業者任せにしないというのが第一にありますので、しっかりと機会を捉えて、こちらでも働きかけを行っていきたいと考えております。","id":"exchange-022"},{"speaker":"若林委員","kind":"意見","question":"ケアすべきなのはどういうところと考えていらっしゃるのかというのが１つ。そういう環境に移るということで、新しい環境の中でどのように事業展開を考えておられるのか、お考えは聞いておきたいと思いますとの意見を述べました。","respondent":"上野子ども育成課長","answer":"１点目、子どもたちの顔ぶれが変わる見込みについて、職員がきっちりとフォローしていきたいと考えております。地域との連携を大切にしながら、相乗効果を望めるように、児童センターの運営を行ってまいりたいと思います。","id":"exchange-023"},{"speaker":"のだて委員","kind":"質問","question":"すみません、最後に。先ほど来、区の理念はそこで継承されるということでしたけれども、区の理念は何なのかを伺いたいと思います。","respondent":"芝野保育入園調整課長","answer":"区の保育理念というのは、就学前の乳幼児が等しく質の高い保育・教育を受け、０歳児からの保育・教育の充実に取り組むことを保育理念としております。こちらの保育理念をしっかりと公私連携型の法人にも伝え、継承していっていただきたいと考えております。","id":"exchange-024"}]},{"id":"topic-03","title":"第２０号議案、品川区子ども家庭支援センター条例の一部を改正する条例","agenda":"第２０号議案、品川区子ども家庭支援センター条例の一部を改正する条例","exchanges":[{"speaker":"のだて委員","kind":"質問・要望","question":"移ろうとしている場所は、広さ的にはどうなるのでしょうか。場所が変わることになると、利用者への周知もやっていただきたいと思うのですが、どのようにしようとしているのか伺います。","respondent":"吉野子ども家庭支援センター長","answer":"今度、第三庁舎に行きますと３３４平米になるのですが、現在区職員が使っておりますランチルームがあります。それから、利用の周知ですけれども、こちらはホームページ、それから４月１日号の広報にてお知らせする予定です。","id":"exchange-025"},{"speaker":"のだて委員","kind":"質問","question":"広さは狭くなるということで、今までの業務を今後、十分継続できるのか伺いたいのと、あと、利用者の周知は広報でやるということで、当然利用者の方には直接通知をしていくということでいいのか尋ねました。","respondent":"吉野子ども家庭支援センター長","answer":"今までの業務には、支障がないようにしっかりとやっていきたいと考えております。周知ですけれども、現在利用されている方にも周知をしっかりとやっていきたいと思います。","id":"exchange-026"}]},{"id":"topic-04","title":"第２２号・第２３号議案（乳児等通園支援事業）","agenda":"第２２号・第２３号議案（乳児等通園支援事業）","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"第２２号議案のところで伺いたいのですが、こうした理由を伺いたいのと、変更によって生じるメリット・デメリットを伺いたいと思います。それと、第２２号議案と第２３号議案の関係性を伺います。","respondent":"佐藤保育事業担当課長","answer":"利用定員の区分の変更について、利用者にとっての利便性が向上することを理由に、区分ごとの分けがなくなったと認識しています。第２３号議案は、子ども・子育て支援法に関連したものでございまして、提供拒否の禁止や会計についてなどが定められているものです。","id":"exchange-027"},{"speaker":"のだて委員","kind":"質問","question":"第２３号議案の資料、別紙２で、今回いろいろ区がやっていく中身が説明されましたけれども、国の制度と違うのはどこなのか伺います。今回、一般型のやり方を選択した事業者は、どういった理由から選択しているのか伺いたいと思います。","respondent":"佐藤保育事業担当課長","answer":"一般型は専任の職員の方がついて対応することになりますので、懸念されていたような危険性には対応できるものと考えております。続いて、一般型を選択された事業者の理由ですが、これは専用の部屋を用意できることが一番大きな理由と認識しております。","id":"exchange-028"},{"speaker":"のだて委員","kind":"質問・要望","question":"継続してしっかりとやっていけるのかが１つ問題だと思いますが、その点、いかがでしょうか。５時間だったら６回で、週１回になってしまうとまたゼロに戻ってしまう感じもするのですが、利用時間の拡大の可能性はあるのか伺います。","respondent":"佐藤保育事業担当課長","answer":"対応できるようになってきたというお声もいただいているのですけれども、そのような施設をつくる事業者に関しても、補助を実施する予定です。今後の拡大の見込みですが、こうしたものをしっかりと見ていきながら、継続して議論していきたいと考えております。","id":"exchange-029"},{"speaker":"のだて委員","kind":"質問・要望","question":"今回実施していく園の候補が６０園あるということで、第２２号議案と第２３号議案の基準で、違いとかはあるのか伺います。つまり、どちらかは、認可はされるけれども確認はされない、つまり公定価格が出ない、そうしたこともあるのか伺いたいと思います。","respondent":"佐藤保育事業担当課長","answer":"児童福祉法と子ども・子育て支援法の観点で求められている内閣府の定める基準ということでございまして、基本的には、どちらか一方だけお認めして。横の連携についてですが、先ほどお話しさせていただいたような事業実施に当たる懸念事項などについては…","id":"exchange-030"},{"speaker":"のだて委員","kind":"質問・要望","question":"園長だけでなく、職員同士も実際に現場でできるところがあれば、ぜひそうした交流もしていただけたらと思います。０～２歳ということで実施されると思うのですけれども、また、豊かな保育ができる体制をとっていくようにしてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-031"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"財政的な安定はあるのか１つ教えていただきたいのと、今お話がありましたけれども、８割ぐらいが余裕活用型です。さっきの話ではないですけれども、現場の保育士の過重労働につながらないのか心配があるのですが、まずそこを説明を求めました。","respondent":"佐藤保育事業担当課長","answer":"予算につきましては、今年度よりも約倍増した形で予算措置を予定していますので、一定程度の需給に関しては対応できると考えています。余裕活用型については、それぞれの園で決められている定員内の空きを活用したものですので…","id":"exchange-032"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"荏原が１７とすると、東大井・八潮は５で、地域差という部分です。未実施の園へインセンティブを付与していくとか、そういった検討などもぜひしていただきたいと思うのですが、いかがか尋ねました。","respondent":"佐藤保育事業担当課長","answer":"乳児等通園支援事業の利用率などを勘案して、計算上は一般型の空き定員と余裕活用型の定員で対応できると考えているのですけれども。これにつきましては、現時点で参加されていない私立認可保育所だけでも５０園近くありますので、供給数を増やしていきたいと考えております。","id":"exchange-033"},{"speaker":"筒井副委員長","kind":"質問","question":"利用者が定期利用で登録していた日以外に急に利用したい場合はどう対応されるのか、試行的事業のときにそういったことは出てこなかったのか、その点をお聞きしたいと思います。","respondent":"佐藤保育事業担当課長","answer":"まず、急な予定により保育施設等を利用したいというものとは目的が異なるものでございまして、そちらにおいて対応できるものであると認識しています。様々な状況によって行けなくなってしまうことがあると思いますが…","id":"exchange-034"},{"speaker":"筒井副委員長","kind":"質問","question":"ほかに、試行的事業のときに出た課題、これは直さなければいけないという点が何かありましたら、説明を求めました。","respondent":"佐藤保育事業担当課長","answer":"区としては潤沢な予算を措置し、充実した保育士の配置、人員配置等をしていただきたいと考えています。施設の方に丁寧な説明をさせていただきたい、また、利用者にとっても分かりやすく利用できるような支援をしていきたいと考えております。","id":"exchange-035"},{"speaker":"横山委員","kind":"確認","question":"どういった内容のアンケート結果ですとかお声があったのか、どういった形で検証されたのか、その流れですとかを確認させていただけたらと思います。","respondent":"佐藤保育事業担当課長","answer":"それと、ワンオペレーションで大変だったので非常に助かった、自分の時間を持てるようになったというようなお声をいただいているところです。実施していただいている事業者とお話をさせていただいて、何時間で設定するのが適切なのかを様々な議論をした中で…","id":"exchange-036"},{"speaker":"横山委員","kind":"確認","question":"保護者の方のリフレッシュであったり、ご自身の子育てがどういった形で、確認させていただきました。双方が利用しやすいような形で着地していけるように、ぜひ区としてもお声をそれぞれ聞いていただきながら進めていただければと思っています。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-037"},{"speaker":"若林委員","kind":"意見","question":"それは、試行実施の中も含めて、どういうご様子、また、考え方なのか。国ではこのように示されているとか、何かコメントをほしいと求めました。","respondent":"佐藤保育事業担当課長","answer":"提供拒否の禁止の条項についてのご質問だと認識していますけれども、あと定員が足りないとか、そういったことが想定されるものだと認識しております。試行的事業の中において、そこが争点となるようなご意見やクレームを受けたことはなかったと認識しております。","id":"exchange-038"},{"speaker":"若林委員","kind":"確認","question":"親御さんも確認しながらですが、継続性、そこら辺はどのように考えていますか。","respondent":"佐藤保育事業担当課長","answer":"こども誰でも通園制度に関する特別支援児への対応ですけれども、この制度につきましては、誰でも利用できるものです。区としては来年度、様々な取組の中で、そうしたニーズにも応えていける体制づくりも継続して実施しています。","id":"exchange-039"},{"speaker":"のだて委員","kind":"質問・要望","question":"しっかりと事故も起きないように、豊かな保育が実施できるような体制をとることを求めたいと思います。国は３歳になったら打ち切りという感じですけれども、こうした前進面も評価をして、賛成したいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-040"}]},{"id":"topic-05","title":"品川区立学校の学校医、学校歯科医および学校薬剤師の公務災害補償に関する条例の一部を改正する条例","agenda":"品川区立学校の学校医、学校歯科医および学校薬剤師の公務災害補償に関する条例の一部を改正する条例","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"今回増額になるということですけれども、その理由、背景を伺います。実際にこれまで区ではこうした事例はあるのか伺いたいと思います。","respondent":"石井学務課長","answer":"こちらの改正の経緯ですけれども、基本的な金額につきましては、国も様々な審議会等で議論しており、それによって改正がされたと承知しております。平成１３年度までは東京都の条例だったのですけれども、区に条例が移管された後は、本条例による補償は今まで発生してございませ…","id":"exchange-041"}]},{"id":"topic-06","title":"令和８年請願第１号、一人ひとりの子どもが大切にされる品川区を求める請願","agenda":"令和８年請願第１号、一人ひとりの子どもが大切にされる品川区を求める請願","exchanges":[{"speaker":"のだて委員","kind":"質問・要望","question":"一人ひとりの子どもが大切にされる品川区を求める請願ということで出されて、後日１１名と、多くの方から署名が集まっている。区としてはこの配置基準で十分だと考えているのか伺います。","respondent":"佐藤保育事業担当課長","answer":"区の認識ですが、まず国の配置基準につきましては、様々、国におきまして有識者等との話合い等が行われた上で、保育園を運営するために必要な基準を設けてありますので、区としても、園を運営していくために必要な最低基準としては、この基準が適切と考えています。","id":"exchange-042"},{"speaker":"のだて委員","kind":"質問","question":"最低基準としては適切だということで、実際に保育をやっていく上でどれだけ必要なのかという点では、十分だと考えているのか伺いたいと思います。","respondent":"佐藤保育事業担当課長","answer":"基準についてですが、それぞれの園の事情等、様々あると考えています。区としては、または支援していく必要性があると考えておりまして、冒頭でご説明させていただいたような補助メニューを整備しています。","id":"exchange-043"},{"speaker":"のだて委員","kind":"質問","question":"そうであるならば、配置基準もぜひ区独自に引き上げていくことをお願いしたいと思うのですけれども、いかがでしょうか。やはり充実した保育を行っていくという点では、この基準をさらに上げていくことが必要だと思いますけれども、いかがか尋ねました。","respondent":"佐藤保育事業担当課長","answer":"基準について様々なお考え、または状況があるかと認識していますけれども、令和５年度には状況等を考えた上での改善をされてあります。こちらも有識者の集まるこども未来戦略会議の中で十分に議論された上で実施されたものであるということと、追加の人員配置…","id":"exchange-044"},{"speaker":"のだて委員","kind":"質問・要望","question":"いかがでしょうか。子どもはいないけれども定員数の保育士を配置しなければならないわけですから、区は問題と思わないのか、認識を伺います。","respondent":"佐藤保育事業担当課長","answer":"巡回支援や指導検査なども十分に実施して、あと、第三者評価機関にも受審を各事業所において努力義務として実施していただいてあります。特別な支援が必要な方の配置または保育支援員の配置などをしていただいた事業所に対して補助を実施しているということと…","id":"exchange-045"},{"speaker":"のだて委員","kind":"質問・要望","question":"認証保育所にも補助金を出している区が複数あるのですから、ぜひ品川区としても定員未充足に対する補填、補助をやっていただきたい。それがやはり区の保育を豊かにしていく、守っていくことになると思うのですけれども、いかがか尋ねました。","respondent":"佐藤保育事業担当課長","answer":"冒頭でご説明させていただいたような補助を実施してございまして、様々な事業所において国基準以上の人員が配置されていると認識しております。で、認証保育所は東京都が独自に認証制度を用いて実施している認可外の保育施設ですので…","id":"exchange-046"},{"speaker":"のだて委員","kind":"質問・要望","question":"そこはぜひしっかりと運営していけるように支援をしていただきたいと思うのですが、いかがでしょうか。通っていた人たちは保育を受けられなくなってしまうことになるわけですから、そうした影響をどう考えていらっしゃるのか伺います。","respondent":"佐藤保育事業担当課長","answer":"先ほどお伝えさせていただいたように、根本的な運営につきましては東京都において検討され、広域的に実施されるのが適切と考えています。今年度におきましても、昨今の情勢等を考えまして、補助の単価も増額していますので…","id":"exchange-047"},{"speaker":"のだて委員","kind":"質問・要望","question":"ほかの子どもを空いているところで受け入れてやっていくことは保育士にも負担になって、やはり運営努力だけではどうにもならない状況になっているので、ぜひそこは補助をやっていただきたいと要望しておきます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-048"},{"speaker":"筒井副委員長","kind":"意見","question":"本日結論を出すで、不採択でお願いいたします。国の最低基準は２年ほど前の国のこども未来戦略会議等で話し合われたばかりですし、物理的な問題や、今回はそうした理由で不採択としますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-049"},{"speaker":"若林委員","kind":"質問・要望","question":"基準、それから補填の考え方も議論がありました。私立保育園、しっかりと行政が一定の関与をし続けながら、そのときのニーズに応じて質のよい保育行政に邁進してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-050"},{"speaker":"のだて委員","kind":"質問・要望","question":"本日結論を出すということで、採択を主張します。豊かな保育にしてほしいと求めましたし、園運営が大変なところをしっかり支援していくべきだと思いますので、採択です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-051"},{"speaker":"高橋（し）委員","kind":"質問","question":"今ご説明いただいたように、国基準を超える様々な形の補助をしている状況であります。ということから、請願でいただいたご希望には沿い難いということです。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-052"},{"speaker":"横山委員","kind":"質問","question":"区として様々取り組んでいただいている内容のご説明がありました。引き続き子どもたちを中心に据えて、現場の方々のお声を伺いながら、品川区の実情に合わせた運営への支援を。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-053"}]},{"id":"topic-07","title":"令和８年陳情第８号、生成ＡＩ時代におけるネットリテラシー教育の機会創出を求める陳情","agenda":"令和８年陳情第８号、生成ＡＩ時代におけるネットリテラシー教育の機会創出を求める陳情","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"区としては、こうした危険性、リスクをどう考えているのかを伺います。危険性を学んでいるのか、もし学んでいるとしたら、どんな形でやっているのか伺います。","respondent":"丸谷教育総合支援センター長","answer":"は、いわゆる災害時のフェイクニュースに惑わされないように、しっかり情報源に当たっていきましょうという学習を行っている段階です。今後、さらに急速に発展していくものではありますけれども、児童生徒向けの教材や、そうしたものは出てくるものと捉えているところです。","id":"exchange-054"},{"speaker":"のだて委員","kind":"提案","question":"この陳情で提案されているのが、危険性、あと有用性も学んでいこうということだと思います。こうした取組についての区の認識を伺いますとの意見を述べました。","respondent":"丸谷教育総合支援センター長","answer":"ワークショップが子どもたちにとって適切なものかを考えますと、学習指導要領に基づいたものは１つ、大きな指針になってくると思います。そういったものを各学校の担当者、管理職、また、教育委員会が判断しながら進めていくことが望ましいと考えております。","id":"exchange-055"},{"speaker":"のだて委員","kind":"意見","question":"区でも既に始めている部分もありながら、やっていく方向だということですので、ぜひ議会としてもこれを後押しするということで進めていきたいと私は思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-056"},{"speaker":"筒井副委員長","kind":"質問・要望","question":"１番目については、２つ目については、求めることについてはかなりかなっていると思います。したがって、結論としては不採択でお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-057"},{"speaker":"若林委員","kind":"意見","question":"本日結論を出すで、不採択でお願いします。そこも含めて慎重に、現在の水準をまた日々上げながら、しっかりと取り組んでほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-058"},{"speaker":"のだて委員","kind":"提案","question":"本日結論を出すということで、採択を主張します。そうした中にこの提案も盛り込みながらやっていけばいいと思いますし、これを学んでいくことは重要だと思いますので、採択ですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-059"},{"speaker":"高橋（し）委員","kind":"質問","question":"ただ、６年間の授業の中で働きかけをするチャンスはたくさんあるので、そちらもぜひ力を入れて進めていっていただくことが重要だと思います。こちらの陳情とは少し話があれですけれども、そういった通常の授業の中での指導はすごく重要になってくると思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-060"}]},{"id":"topic-08","title":"専決処分の報告","agenda":"専決処分の報告","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"今回、損害賠償額が１３０万円で、少し大きいと思ったのですけれども、これは門扉を全部新しいものに取り替えたのですか。一部破損だけれども、使えなくなってしまったということなのか伺います。","respondent":"舩木庶務課長","answer":"ただいま委員のご指摘のとおり、破損した門扉が廃盤品だったことから、類似品同等品を新たに新規に交換しなければならなかったこと、そして、門扉以外のブロックフェンスも基礎から交換するという工事が伴いまして、資料にあります損害賠償額になったものです。","id":"exchange-061"},{"speaker":"まつざわ委員","kind":"確認","question":"安全基準のマニュアルですか、消防車を運行するときは絶対に２人、バックするときは必ず後方確認をすることは決められているのです。それを守りましょうという安全基準があるのですけれども、全庁的に見て、公用車を運転するときの安全基準、事故防止マニュアルはあるのか。","respondent":"舩木庶務課長","answer":"運行の部分も含めて、それから注意義務であったりというところは、これはマニュアル以前にしっかりと遵守することが大前提になろうかと考えています。安全確認を含めて、繰り返しになりますけれども、徹底していくことが第一に基本になると考えております。","id":"exchange-062"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"よりしっかりするには、やはりルールづくり、体制づくりはある程度マニュアル化したほうがいいと思います。要望です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-063"}]},{"id":"topic-09","title":"令和８年度私立保育園の設置等","agenda":"令和８年度私立保育園の設置等","exchanges":[{"speaker":"のだて委員","kind":"質問・要望","question":"１歳から５歳、全部１２名で、こうした定員になっているのはどういった理由なのか伺います。確認させてほしいと求めました。","respondent":"佐藤保育事業担当課長、芝野保育入園調整課長","answer":"設置者の変更についてですが、例えば介護とか、幅広く実施されていた事業者でございました。今回、保育・子育ての環境等が目まぐるしく変化することもあって、迅速に保育事業に対応していきたいという思いから… 私からは、新規園２園の状況についてご説明申し上げます。定員の考え方ですが、１歳児から５歳児まで各１２名ですが、この定員にしています。","id":"exchange-064"},{"speaker":"のだて委員","kind":"質問・要望","question":"ぜひそこは把握していただいて、把握せずに保育の質を担保できるのかというのがあるのですけれども、そこを伺いたいと思います。区としても支援していただけたらと思いますし、ぜひ園庭を設置できるような、園庭を設置する補助もやってほしいと求めました。","respondent":"芝野保育入園調整課長","answer":"株式会社テノ．コーポレーションも区内２か所、今回、新規開設を認めることで動いてあります。","id":"exchange-065"},{"speaker":"のだて委員","kind":"質問・要望","question":"ぜひ保育の質を担保し、よくしていくというところで、保育士の待遇も含めて確認していただいて、区の保育がよくなるようにしてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-066"}]},{"id":"topic-10","title":"その他","agenda":"その他","exchanges":[{"speaker":"高橋（し）委員","kind":"質問","question":"それから３つ目は、（仮称）サポートセンターを令和８年度ですか、それが教員の様々な働き方をカバーしていくのか教えてください。３つ、お願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-067"},{"speaker":"横山委員","kind":"質問","question":"私も高橋しんじ委員とかぶってしまうのですけれども、一部、周知で、学校・保護者という話があったのですけれども、地域や議会に対してですとか、区内全体、どのように周知していくのかをお聞きしたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-068"},{"speaker":"高橋（し）委員","kind":"質問","question":"今委員長にご説明いただいたのですけれども、ガイドラインはまだ実際にこれで品川区の学校で何かをしたということは恐らくないと思うので、それが来年度、現実的に、これまで小中学校でこういうことがあったけれども、それはこのガイドラインによってこう解決していくだろうということをお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-069"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/631298?Template=document&Id=7313#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=9&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":47116,"voices":256}}]);
